-- Poems batch 209
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3db89ea5-b456-4182-89aa-062992377162','荷鷺  其二','釋智愚','宋','宋诗','song-poetry','','[]','蒲葉吹秋，水天漠漠。',20,'全唐诗/poet.song.196000.json','["蒲葉吹秋，水天漠漠。", "歛影肅心，意不在啄。"]'),
('534d71f0-fb2c-4b44-8492-2dbbac3965fd','偈頌十七首  其一','釋智愚','宋','宋诗','song-poetry','','[]','懷州牛喫禾，益州馬腹脹。',24,'全唐诗/poet.song.196000.json','["懷州牛喫禾，益州馬腹脹。", "天下覓醫人，灸豬左膊上。"]'),
('135afae5-d16a-4801-a22e-a9d840122da1','偈頌十七首  其二','釋智愚','宋','宋诗','song-poetry','','[]','吒吒呀呀如獅子兒，我者裏也須勘你。',49,'全唐诗/poet.song.196000.json','["吒吒呀呀如獅子兒，我者裏也須勘你。", "勃勃窣窣似探竿影草，我者裏也須疑你。", "雖然菽麥不分，爭奈鹽落醤裏。"]'),
('f978bfdc-fbea-49c2-a1d9-780d83f13089','偈頌十七首  其三','釋智愚','宋','宋诗','song-poetry','','[]','盡信書不如無書，識得箇字不如忘却箇字。',57,'全唐诗/poet.song.196000.json','["盡信書不如無書，識得箇字不如忘却箇字。", "九經諸子徒爾藻飾，一大藏教盡是藥方。", "分明對物收稅，何用商量，一葉扁舟載大唐。"]'),
('1aef122d-a264-4068-be8f-be96d38af675','偈頌十七首  其四','釋智愚','宋','宋诗','song-poetry','','[]','金錍刮膜，自病難醫。',58,'全唐诗/poet.song.196000.json','["金錍刮膜，自病難醫。", "利劍揮空，逃蹤莫及。", "何似橫拈麈尾，抑挫來機。", "殺活雖殊，對揚有準，什麽人得此三味。", "一二三，三二一。"]'),
('5e187004-745d-4c09-af81-791039a2958f','偈頌十七首  其五','釋智愚','宋','宋诗','song-poetry','','[]','七步周行猶彷彿，指天指地不分明。',32,'全唐诗/poet.song.196000.json','["七步周行猶彷彿，指天指地不分明。", "是非既落傍人耳，洗到馿年也不清。"]'),
('6f660a18-35cc-4a47-b723-7601e8386f67','偈頌十七首  其六','釋智愚','宋','宋诗','song-poetry','','[]','渡江風倚蘆梢碧，夜深金殿人相憶。',68,'全唐诗/poet.song.196000.json','["渡江風倚蘆梢碧，夜深金殿人相憶。", "此土西天賣不行，千古萬古成狼藉。", "當良月蓂敷五葉之辰，孰謂韜其光，晦其跡。", "熏爐茗椀想遺音，分明對面不相識。"]'),
('c3434799-cfa8-4d1d-84e2-7b823bab4c41','偈頌十七首  其七','釋智愚','宋','宋诗','song-poetry','','[]','朝朝相似，日日一般。',36,'全唐诗/poet.song.196000.json','["朝朝相似，日日一般。", "見成受用，千難萬難。", "因思臨濟掌黄檗，何似華亭把釣竿。"]'),
('80e1d3b4-42f8-47d2-8656-019e1f77f210','偈頌十七首  其八','釋智愚','宋','宋诗','song-poetry','','[]','有意待不來，無心忽會面。',52,'全唐诗/poet.song.196000.json','["有意待不來，無心忽會面。", "頂髮垂絲，眼光如電。", "說盡湖海風波，論量柴米貴賤。", "更有一處少人知，也是重安眼上眉。"]'),
('770c3eea-881f-4a2d-8b1e-c415bd57a18d','偈頌十七首  其九','釋智愚','宋','宋诗','song-poetry','','[]','羣陰剝盡一陽生，又見東山水上行。',32,'全唐诗/poet.song.196000.json','["羣陰剝盡一陽生，又見東山水上行。", "冷笑雲門多口老，却來日午打三更。"]'),
('e2ea55e0-85fc-45e8-9cfa-c89e9d776c7c','偈頌十七首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','道人猛利難親近，漾笠中流驗作家。',32,'全唐诗/poet.song.196000.json','["道人猛利難親近，漾笠中流驗作家。", "憶昔高人何處去，夜深和月過平沙。"]'),
('0102c723-2e6c-4bb7-ad00-3eb6fb3e32a5','偈頌十七首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','或隠或顯，有虧有盈。',42,'全唐诗/poet.song.196000.json','["或隠或顯，有虧有盈。", "爲天上無私之鑑，實人間照夜之燈。", "尋常多是論三五，惟有今宵分外明。"]'),
('cdb090b0-0930-43c7-99eb-8002125ac5e1','偈頌十七首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','船上無散工，駕御有方所。',40,'全唐诗/poet.song.196000.json','["船上無散工，駕御有方所。", "打篙底打篙，摇櫓底摇櫓。", "觸浪迎風天地寬，去來不礙東西浦。"]'),
('a95c6265-20c2-4b2a-9788-76417cec8706','偈頌十七首  其一三','釋智愚','宋','宋诗','song-poetry','','[]','丁寧損君德，無言真有功。',24,'全唐诗/poet.song.196000.json','["丁寧損君德，無言真有功。", "任從滄海變，終不爲君通。"]'),
('96da631d-7dc0-422a-9e76-51d3f27e2c4d','偈頌十七首  其一四','釋智愚','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',74,'全唐诗/poet.song.196000.json','["晷運推移，日南長至。", "東海鯉魚，鼓腮振鬣。", "南山鼈鼻，伸眉吐氣。", "唯有趙州老兒沒意智，拖箇破席日裏睡。", "浄慈路見不平，道箇蘇盧悉利。", "恐者老子背地裡討人便宜。"]'),
('2370ba8c-7581-434e-b124-7bbc704c01ab','偈頌十七首  其一五','釋智愚','宋','宋诗','song-poetry','','[]','城東聖母坐蓮臺，大地衆生正眼開。',32,'全唐诗/poet.song.196000.json','["城東聖母坐蓮臺，大地衆生正眼開。", "與佛同生嫌見佛，一身難作二如來。"]'),
('13577b4a-4e05-4f62-b6f7-415b95f9725b','偈頌十七首  其一六','釋智愚','宋','宋诗','song-poetry','','[]','二月十五入寂，四月八日復生。',26,'全唐诗/poet.song.196000.json','["二月十五入寂，四月八日復生。", "虛空開笑口，大地絕人行。"]'),
('bf42cb15-a8f8-4b35-aa24-ef4ad83743f9','偈頌十七首  其一七','釋智愚','宋','宋诗','song-poetry','','[]','秤鎚捻得汁出，石人喝得汗流。',32,'全唐诗/poet.song.196000.json','["秤鎚捻得汁出，石人喝得汗流。", "臨機應變，隨分知羞，乘時推上五峯頭。"]'),
('60f9afd4-4013-4652-b5cb-e7b6c4cf4a1c','偈頌二十一首  其一','釋智愚','宋','宋诗','song-poetry','','[]','開端令節，萬事從新。',55,'全唐诗/poet.song.196000.json','["開端令節，萬事從新。", "普賢磨墨，文殊把筆，書箇事事大吉。", "從茲常住寬餘，掃除逋積。", "斗南長見老人星，五峯峨峨倚空碧。"]'),
('f10369e7-7e80-4029-a569-67ed9e43f37f','偈頌二十一首  其二','釋智愚','宋','宋诗','song-poetry','','[]','君勿愛清涼，清涼如火如沸湯。',40,'全唐诗/poet.song.196000.json','["君勿愛清涼，清涼如火如沸湯。", "君勿惡炎熱，炎熱如冰如積雪。", "勿愛亦勿惡，未是逍遥處。"]'),
('04793433-527c-409b-8e6a-db0e1d8752f7','偈頌二十一首  其三','釋智愚','宋','宋诗','song-poetry','','[]','吽㗶吒喇竭節，地轉天回難辨別。',67,'全唐诗/poet.song.196000.json','["吽㗶吒喇竭節，地轉天回難辨別。", "不使松源省數錢，慣用衲僧鎖口訣。", "同死不同生，特地成途轍，秋風影裏重羅列。", "義斷情忘四十年，何時待得龜成鱉。"]'),
('8355af43-0d34-483c-b731-cc0ca0efd7e0','偈頌二十一首  其四','釋智愚','宋','宋诗','song-poetry','','[]','閙不如靜，忙不如閒。',48,'全唐诗/poet.song.196000.json','["閙不如靜，忙不如閒。", "靜閙俱泯，謂之得理。", "歸宗事理絕，日輪正當午。", "向道莫行山下路，果然猿叫斷腸聲。"]'),
('a7df08c5-0cf3-47be-bb45-67ba204a8f99','偈頌二十一首  其五','釋智愚','宋','宋诗','song-poetry','','[]','鳶飛戾天，魚躍于淵。',28,'全唐诗/poet.song.196000.json','["鳶飛戾天，魚躍于淵。", "四夷拜舞，八表宣傳，笑看紅日上闌干。"]'),
('84530a58-7f9b-4f6a-bcc7-c04a0aae3aff','偈頌二十一首  其六','釋智愚','宋','宋诗','song-poetry','','[]','天不文，地不理。',58,'全唐诗/poet.song.196000.json','["天不文，地不理。", "忽去忽來，如月印水。", "歲月已往兮波旬得時，槨示雙趺兮飲光增喜。", "悲兮喜兮，春風桃李。", "一以貫之，曾子曰唯。"]'),
('c31cc240-5f5c-4c41-a4d6-1524fb5e4ef2','偈頌二十一首  其七','釋智愚','宋','宋诗','song-poetry','','[]','諸人知處良遂知，良遂知處人不知。',32,'全唐诗/poet.song.196000.json','["諸人知處良遂知，良遂知處人不知。", "因思積雨花狼藉，空寫愁膓說向誰。"]'),
('0bd3847f-4a35-4303-bd24-c92c02ec2810','偈頌二十一首  其八','釋智愚','宋','宋诗','song-poetry','','[]','秋風吹曉露，秋雨送秋炎。',36,'全唐诗/poet.song.196000.json','["秋風吹曉露，秋雨送秋炎。", "祖師門下客，無處不咨參。", "前程忽撞著箇金口木舌漢。"]'),
('dd55e190-7f7f-4c97-971c-51c1ae9f06e4','偈頌二十一首  其九','釋智愚','宋','宋诗','song-poetry','','[]','觀東震旦，有大乘根器，逾海越漠而來，遠赴梁朝丹闕。',76,'全唐诗/poet.song.196000.json','["觀東震旦，有大乘根器，逾海越漠而來，遠赴梁朝丹闕。", "一言契合，如春卷衣。", "北面折葦問津，信知桂讖不誣人。", "追思嚴諱，炊黍鱠芹。", "流水希聲絃欲斷，不知將底續芳塵。"]'),
('3c0551d9-fd7f-4ead-8a81-ff7e02932491','偈頌二十一首  其一○','釋智愚','宋','宋诗','song-poetry','','[]','平生好攻禪病，不知病是道源。',90,'全唐诗/poet.song.196000.json','["平生好攻禪病，不知病是道源。", "要知道源端的，直須陸地行船。", "因思大唐裴相國作圓覺經一序，一字一義，聳動人天。", "又思本朝溫國公製解禪頌六篇，一褒一貶，口業昭然。", "匪伊自絕夙種，佛亦不度無緣。"]'),
('eca8cba1-23a3-46dd-922a-f69ed781b2aa','偈頌二十一首  其一一','釋智愚','宋','宋诗','song-poetry','','[]','一氣潜回，百昌萌動。',56,'全唐诗/poet.song.196000.json','["一氣潜回，百昌萌動。", "君子道長兮露柱咨參，小人道消兮燈籠作舞。", "義出豐年，道復太古。", "國師歡喜問如何，冬至寒食一百五。"]'),
('b1ffbc70-b518-46ee-8abb-02c43dedd708','偈頌二十一首  其一二','釋智愚','宋','宋诗','song-poetry','','[]','乾坤之內，宇宙之間，中有一寶，秘在形山。',20,'全唐诗/poet.song.196000.json','["乾坤之內，宇宙之間，中有一寶，秘在形山。"]'),
('2491e660-0085-470e-a31f-c832cb853c4f','偈頌二十一首  其一三','釋智愚','宋','宋诗','song-poetry','','[]','夫蠱者最靈通，不期而會，不約而同。',55,'全唐诗/poet.song.196000.json','["夫蠱者最靈通，不期而會，不約而同。", "拶著崖崩石裂，拋出金圈栗蓬。", "驚倒露柱，嚇煞燈籠。", "不知何處毒種，元來門裏有蟲。"]'),
('3444d0d4-6ecf-4a21-bd28-3364cce34af3','偈頌二十一首  其一四','釋智愚','宋','宋诗','song-poetry','','[]','一人高高峯頂立，一人深深海底行。',32,'全唐诗/poet.song.196000.json','["一人高高峯頂立，一人深深海底行。", "不是與人難共住，大都緇素要分明。"]'),
('fc5dc4d8-2d64-4c62-bd48-900b9df5911b','偈頌二十一首  其一五','釋智愚','宋','宋诗','song-poetry','','[]','西天末葉，東土初枝。',93,'全唐诗/poet.song.196000.json','["西天末葉，東土初枝。", "趑趄梁魏兮形影相吊，冷坐嵩少兮路徑委蛇。", "將謂單傳直指，誰知一握亂絲。", "駡底恨底患在爲人之師。", "今則枝枯葉隕，敷茂何期。", "有屈明明無雪處，臨風只可自噓戲。", "聊陳菲供，來兮鑒諸。"]'),
('49d4feaf-9dbb-4544-8b70-6c17349b8ca8','偈頌二十一首  其一六','釋智愚','宋','宋诗','song-poetry','','[]','憂民恤物歛天威，坐斷乾坤肅四夷。',32,'全唐诗/poet.song.196000.json','["憂民恤物歛天威，坐斷乾坤肅四夷。", "先放臘梅凝瑞雪，次教春色到瑶池。"]'),
('c1d0ab6a-eb58-43b7-8bef-02f567796803','偈頌二十一首  其一七','釋智愚','宋','宋诗','song-poetry','','[]','年垂九十礙叢林，歷盡風霜歲月深。',32,'全唐诗/poet.song.196000.json','["年垂九十礙叢林，歷盡風霜歲月深。", "妙藴豈能超佛祖，寸衷端可格天心。"]'),
('5e790600-3199-4ad8-baf7-3745d3afe1fe','偈頌二十一首  其一八','釋智愚','宋','宋诗','song-poetry','','[]','老不禁寒，山邊水邊曝日。',77,'全唐诗/poet.song.196000.json','["老不禁寒，山邊水邊曝日。", "春歸閬苑，長底短底從新。", "笙歌叢裏賀年朝，錦綉筵中開壽域。", "衲僧門下別有條章，每日蒙頭打坐。", "不知歲月易遷，直饒拶著不來，誰展鉢盂喫飯。"]'),
('b8679d81-1bd2-4d1a-91c9-971f1fd204c2','偈頌二十一首  其一九','釋智愚','宋','宋诗','song-poetry','','[]','四達皇皇，無邊無表，因甚有新有舊。',36,'全唐诗/poet.song.196000.json','["四達皇皇，無邊無表，因甚有新有舊。", "會得此去漢陽不遠，不然黄鶴樓前鸚鵡洲。"]'),
('b66b61e3-2e9a-41bf-b04d-b081a8b135ba','偈頌二十一首  其二○','釋智愚','宋','宋诗','song-poetry','','[]','上元新節，處處燒燈，都城巷陌，市廛邸店。',37,'全唐诗/poet.song.196000.json','["上元新節，處處燒燈，都城巷陌，市廛邸店。", "觀者如堵，惟復燈來眼底，眼到燈邊。"]'),
('aba6622d-6983-4278-862f-7d903f226871','偈頌二十一首  其二一','釋智愚','宋','宋诗','song-poetry','','[]','百丈清規，千古洪範。',26,'全唐诗/poet.song.196000.json','["百丈清規，千古洪範。", "藏之則虛空絕跡，用之則綱令森嚴。"]'),
('6d39b385-073f-4521-84b2-552be78b2aa2','頌古','釋智愚','宋','宋诗','song-poetry','','[]','趙州八十方行脚，虛堂八十再住山。',32,'全唐诗/poet.song.196000.json','["趙州八十方行脚，虛堂八十再住山。", "別有一機恢佛租，九重城裏動龍顔。"]'),
('1d2efb71-1233-421d-854a-9b2775fc78c9','寄集慶開山','釋智愚','宋','宋诗','song-poetry','','[]','如意來尸釋梵宮，雨花狼藉濕春風。',32,'全唐诗/poet.song.196000.json','["如意來尸釋梵宮，雨花狼藉濕春風。", "自慚老矣無靈骨，日在深雲聽講鐘。"]'),
('8b29dc26-1e47-4820-801e-d8c4df0090cd','賡靜學林府判游天澤菴韻','釋智愚','宋','宋诗','song-poetry','','[]','古道兼禪到，躬行得幾年。',48,'全唐诗/poet.song.196000.json','["古道兼禪到，躬行得幾年。", "乾坤資定力，心月鑑前緣。", "一靜人難學，三生話未圓。", "老來重有約，不在北山邊。"]'),
('c4c7440f-3eb8-4bf0-a987-ca0b149a8fed','答洞陽居士糜監丞','釋智愚','宋','宋诗','song-poetry','','[]','冷冰冰地洞陽春，橐籥乾坤萬物新。',32,'全唐诗/poet.song.196000.json','["冷冰冰地洞陽春，橐籥乾坤萬物新。", "拋下葛藤提不起，不知纏縛幾多人。"]'),
('94f8621a-7655-4701-bbfb-ffcab377e6d9','送了侍者游台山','釋智愚','宋','宋诗','song-poetry','','[]','慕膻高舉興何窮，秋在黄蘆葉裏風。',32,'全唐诗/poet.song.196000.json','["慕膻高舉興何窮，秋在黄蘆葉裏風。", "已事未明如蹈火，白雲深處見巖翁。"]'),
('cf6e5ed6-cdaf-4363-b49a-ed1b0ada1078','來知客慈峰之乳竇瞻禮明覺塔','釋智愚','宋','宋诗','song-poetry','','[]','湖邊問路入深雲，十載心香一炷焚。',32,'全唐诗/poet.song.196000.json','["湖邊問路入深雲，十載心香一炷焚。", "不見隠之真隠處，曉風凌露葉初聞。"]'),
('a4ec1265-3ceb-4ee1-8b4b-0919c6ac0436','賢侍者號木翁','釋智愚','宋','宋诗','song-poetry','','[]','录曲輪囷兒似癡，春風花鳥自忘機。',32,'全唐诗/poet.song.196000.json','["录曲輪囷兒似癡，春風花鳥自忘機。", "年來老大渾無用，一任叢林鼓是非。"]'),
('16d79710-0e81-4ce7-b4ac-fb47c0e4f3ea','寄道彬侍者','釋智愚','宋','宋诗','song-poetry','','[]','勃窣家風一任真，述朱終是不成文。',32,'全唐诗/poet.song.196000.json','["勃窣家風一任真，述朱終是不成文。", "何如竹榻吟清夜，月到花梢有幾分。"]'),
('6fd2ceef-4ec1-4e4d-9134-09ef15e002bf','準侍者歸省','釋智愚','宋','宋诗','song-poetry','','[]','山空木落岸雲輕，吹面霜風有幾程。',32,'全唐诗/poet.song.196000.json','["山空木落岸雲輕，吹面霜風有幾程。", "明月脩江歸夢急，入門先祝老人星。"]'),
('a21c9ab4-ef64-4915-aad3-fb89c2839b15','清禪者游方','釋智愚','宋','宋诗','song-poetry','','[]','金風露浥菊花秋，杞棘當途何處游。',32,'全唐诗/poet.song.196000.json','["金風露浥菊花秋，杞棘當途何處游。", "衡岳康廬相撞著，恐伊未是汝同流。"]'),
('272909d0-0a4e-43a3-b2bb-8e2f49dc0c30','珪禪者號石翁','釋智愚','宋','宋诗','song-poetry','','[]','逃空劫外已蒼然，翫水觀山得幾年。',32,'全唐诗/poet.song.196000.json','["逃空劫外已蒼然，翫水觀山得幾年。", "聞說聽經曾肯首，老來無力補青天。"]'),
('ac717ec1-b9b5-4bc9-b7dc-2eb6d6ff748e','瞿居士號無知','釋智愚','宋','宋诗','song-poetry','','[]','過緣觸境總茫然，地闊天寬著那邊。',32,'全唐诗/poet.song.196000.json','["過緣觸境總茫然，地闊天寬著那邊。", "一點既明超物表，不知將底鑑偏圓。"]'),
('006f862b-44b2-4c52-b5f6-fe16d7f89672','贈妙潔道人','釋智愚','宋','宋诗','song-poetry','','[]','妙心明潔契如如，操履分明女丈夫。',32,'全唐诗/poet.song.196000.json','["妙心明潔契如如，操履分明女丈夫。", "龐老家風殊不二，摝籬高價許誰沽。"]'),
('330992c7-ad03-43e0-a7ea-18c164e3f1b9','廢寺','釋智愚','宋','宋诗','song-poetry','','[]','入眼荒蓁古殿秋，歲華遷謝沒人修。',32,'全唐诗/poet.song.196000.json','["入眼荒蓁古殿秋，歲華遷謝沒人修。", "夜深靜聽風甌語，似罵檀那不點頭。"]'),
('97e58dfc-f578-49f6-935c-e61271a9dba4','越山','釋智愚','宋','宋诗','song-poetry','','[]','翠螺簇簇繞湖濱，寒影清磨古鑑塵。',32,'全唐诗/poet.song.196000.json','["翠螺簇簇繞湖濱，寒影清磨古鑑塵。", "休問岡頭望夫石，人間恐有斷腸人。"]'),
('b3f75a80-abf2-4bb1-bc73-acc5737e5cea','墨戲屠生善老融牛','釋智愚','宋','宋诗','song-poetry','','[]','草木傳真筆力高，戴嵩牛在一秋毫。',32,'全唐诗/poet.song.196000.json','["草木傳真筆力高，戴嵩牛在一秋毫。", "此行莫擬天台去，忍作孤僧過石橋。"]'),
('45b85be5-7bf0-48ff-8106-7035a327cdbc','題凈業圖','釋智愚','宋','宋诗','song-poetry','','[]','鍊行修身結佛冤，未曾說著齒先寒。',32,'全唐诗/poet.song.196000.json','["鍊行修身結佛冤，未曾說著齒先寒。", "老來不願西方去，樂得閻浮眼界寬。"]'),
('ed39932c-dc40-4995-90ee-5637305148e3','示惠靈爲僧','釋智愚','宋','宋诗','song-poetry','','[]','惠性何如見性通，要教靈驗顯吾宗。',32,'全唐诗/poet.song.196000.json','["惠性何如見性通，要教靈驗顯吾宗。", "乘時颺下墜腰石，笑捧衣盂繼祖風。"]'),
('bb6f10ff-52ee-4521-968b-c575e210b73b','慶遠俊長老請贊','釋智愚','宋','宋诗','song-poetry','','[]','老不死，心未灰。',42,'全唐诗/poet.song.196000.json','["老不死，心未灰。", "觸著惡發，青天怒雷。", "引得虎頭燕頷，競起叢林禍胎。", "點著便領，何其俊哉。"]'),
('e53021b9-626b-4c93-b7fd-dda459a6f3d2','凈覃藏主請贊','釋智愚','宋','宋诗','song-poetry','','[]','容易肯人，難與共語。',42,'全唐诗/poet.song.196000.json','["容易肯人，難與共語。", "竹篦頭惜之如金，禪牀角委之如土。", "浄覃知藏善知機，電光影裏分賓主。"]'),
('172de87a-b117-4384-a55b-cf3625be9d8d','以文長老請贊','釋智愚','宋','宋诗','song-poetry','','[]','天地不仁，出此妖怪。',60,'全唐诗/poet.song.196000.json','["天地不仁，出此妖怪。", "有偷營劫寨之機，無喜捨慈悲之戒。", "正脈將沉，法門凋瘵，如何嗣續松源派。", "大奸難後越精神，駡人嘴毒如蜂蠆。"]'),
('141fc574-a75b-4ba6-ad73-692352ec9a1b','新建浄慈天錫莊請贊','釋智愚','宋','宋诗','song-poetry','','[]','不期而會，不約而同。',50,'全唐诗/poet.song.196000.json','["不期而會，不約而同。", "晴光爍爍，和氣融融。", "際遇兩朝聖主，中興徽廟禪叢。", "良田天錫平如砥，坐對靈苗歲歲豐。"]'),
('07005f23-0592-4853-8b3f-6c1b3eb19d44','徒弟宗璞建施水菴請贊','釋智愚','宋','宋诗','song-poetry','','[]','等是垂慈，初無門戶。',42,'全唐诗/poet.song.196000.json','["等是垂慈，初無門戶。", "璞玉既分兮可觀，梵儀頓舉兮難覩。", "凌霄峯頂看雲人，普化堂中第一祖。"]'),
('a59a1de8-6f4f-4d18-a918-20c5997559e5','日本紹明知客請贊','釋智愚','宋','宋诗','song-poetry','','[]','紹既明白，語不失宗。',36,'全唐诗/poet.song.196000.json','["紹既明白，語不失宗。", "手頭簸弄，金圈栗蓬。", "大唐國裡無人會，又却乘流過海東。"]'),
('bcfc9bc7-7eb6-46d5-8d51-b17677523fcc','磻溪禪子請贊','釋智愚','宋','宋诗','song-poetry','','[]','怒氣噀人，殊不可犯。',40,'全唐诗/poet.song.196000.json','["怒氣噀人，殊不可犯。", "雖有蓋膽毛，且無驗人眼。", "是亦剗，非亦剗。", "咬定牙關，一生擔板。"]'),
('7a0a764f-b126-4637-b4ca-998bb0942e20','光禪者請贊','釋智愚','宋','宋诗','song-poetry','','[]','初而欣，久而厭。',28,'全唐诗/poet.song.196000.json','["初而欣，久而厭。", "明月夜光，多逢按劍。", "但信得及，自有靈驗。"]'),
('f5a8d3fb-c0a3-4e6f-b6a6-127d9ec51c9a','無則都寺玉几寫予夢影自散席後言音不相接者十二年今上徑山請贊筆老墨澀勉而書之','釋智愚','宋','宋诗','song-poetry','','[]','敬而遠，親而疎。',44,'全唐诗/poet.song.196000.json','["敬而遠，親而疎。", "明鑑靈腑，善定鎖銖。", "凌霄高而衆峰拱，海嶠聳而蟾影孤。", "子歸就父，吾不識渠。"]'),
('bc1514a9-9487-4501-b5f8-c96db4f8e69e','徑山西寮衆老郎請贊','釋智愚','宋','宋诗','song-poetry','','[]','霜嚴氣烈，山空月明。',52,'全唐诗/poet.song.196000.json','["霜嚴氣烈，山空月明。", "涵養有得，剗削不平。", "拈起則佛祖不識，放下也草木爭榮。", "捱到凌霄八十四，誰知名重九重城。"]'),
('fb1e404c-9fc5-4c4d-a25f-cc2ed7c8b39f','黄檗禮佛掌宣宗圖贊','釋智愚','宋','宋诗','song-poetry','','[]','七赤之軀，額有圓珠。',42,'全唐诗/poet.song.196000.json','["七赤之軀，額有圓珠。", "問著便掌，膽大心粗。", "不是大中天子，幾乎喚馬作馿。", "大家水底按葫蘆。"]'),
('d45beec7-9026-43aa-be86-8fd87ab652f9','趙王訪趙州州不下禪牀圖贊','釋智愚','宋','宋诗','song-poetry','','[]','堅不剛，柔不弱。',38,'全唐诗/poet.song.196000.json','["堅不剛，柔不弱。", "七百甲子老翁，偏要用此一著。", "列土王來不下牀，高風千古爲標格。"]'),
('245388cd-18fb-4c3d-9fc5-a703c4440365','肅宗問忠國師十身調御圖贊','釋智愚','宋','宋诗','song-poetry','','[]','萬乘垂衣立問端，國師答處太顢頇。',32,'全唐诗/poet.song.196000.json','["萬乘垂衣立問端，國師答處太顢頇。", "誰知十月清霜重，一陣風來一陣寒。"]'),
('0fa2e536-6d23-4f8d-bc09-19f3ea5b6f26','李翱參藥山圖贊','釋智愚','宋','宋诗','song-poetry','','[]','黑豆數無窮，青松蓋不盡。',40,'全唐诗/poet.song.196000.json','["黑豆數無窮，青松蓋不盡。", "癯然老比丘，即此吾無隠。", "更提雲水曲周遮，添得傍人眼裏花。"]'),
('abc66d98-045c-43e9-98ef-ca0a0fda19f3','韓愈見大顛圖贊','釋智愚','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','氈拍板，無孔笛。',46,'全唐诗/poet.song.196000.json','["氈拍板，無孔笛。", "省要乞一言，虛空轟霹靂。", "臨機不解，轉身又却。", "隨他聲色非聲色，洞庭湖外千峯碧。"]'),
('798bc215-62a8-4be6-a251-83d9ea52a70d','莊宗宣興化問答圖贊','釋智愚','宋','宋诗','song-poetry','','[]','君臣慶會豁全機，百億山河盡貢歸。',32,'全唐诗/poet.song.196000.json','["君臣慶會豁全機，百億山河盡貢歸。", "拈起太平無價寶，乾坤何處不光輝。"]'),
('2df19292-ad38-4a68-a6e7-5c0e4838c9f7','順宗問鵝湖大義禪師圖贊','釋智愚','宋','宋诗','song-poetry','','[]','當機一句闢天關，海闊山遥豈等閑。',32,'全唐诗/poet.song.196000.json','["當機一句闢天關，海闊山遥豈等閑。", "堪笑冬瓜長儱侗，翻成瓠子曲彎彎。"]'),
('593484b1-baef-42bb-a4ba-dbe29398ce6f','文宗問終南山蛤蜊瑞相圖贊','釋智愚','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','攧不開，撲不破。',48,'全唐诗/poet.song.196000.json','["攧不開，撲不破。", "人言大士應身，我也疑他真箇。", "終南山，相應和。", "喜動龍顔，百僚俱賀，誰知別有彌天過。"]'),
('b757a3b5-0d7a-4488-b841-be3ae497c754','龐居士問馬大師圖贊','釋智愚','宋','宋诗','song-poetry','','[]','藏頭露影問來由，却把西江盡力酬。',32,'全唐诗/poet.song.196000.json','["藏頭露影問來由，却把西江盡力酬。", "回首眼空天地窄，不知身在御街游。"]'),
('a021fe4b-7043-422b-8e3b-59847c966d7a','丹霞見靈照女圖贊','釋智愚','宋','宋诗','song-poetry','','[]','冤有頭，債有主。',48,'全唐诗/poet.song.196000.json','["冤有頭，債有主。", "天然欲訪龐翁，恰好撞著此女。", "揣盡家私，瓜甜蒂苦。", "因茲上下不和同，牛奶郎忙塗赤土。"]'),
('0fde3182-236f-416d-8d41-bd057be4348a','龐居士大家團欒共說無生話圖贊','釋智愚','宋','宋诗','song-poetry','','[]','窮廝煎，餓廝吵。',36,'全唐诗/poet.song.196000.json','["窮廝煎，餓廝吵。", "父子不同途，大家相脫卯。", "萬頃湘江洗不清，無生曲調何時了。"]'),
('b25138fa-61e6-42ae-bb78-f2229a4b0629','龐居士闔家都去圖贊','釋智愚','宋','宋诗','song-poetry','','[]','神出鬼沒，接響承虛。',36,'全唐诗/poet.song.196000.json','["神出鬼沒，接響承虛。", "這一火絡，邪法難扶。", "互將魚目作明珠，笑倒西天碧眼胡。"]'),
('b64b729d-b70d-4e16-a563-80d32b1cd3e5','棘林和尚遺書至','釋智愚','宋','宋诗','song-poetry','','[]','因記七峯來玉几，去年花月下雲坳。',32,'全唐诗/poet.song.196000.json','["因記七峯來玉几，去年花月下雲坳。", "未周一歲背盟我，剔盡春燈眼不交。"]'),
('20a20174-8a4a-4ced-8546-ae55b652d218','鍼生大阬','釋智愚','宋','宋诗','song-poetry','','[]','假道鍼鋒上，行藏雲水中。',48,'全唐诗/poet.song.196000.json','["假道鍼鋒上，行藏雲水中。", "且非心法妙，自是手頭通。", "前輩多遺偈，靈襟出衆工。", "明朝何處去，黄葉度谿風。"]'),
('ebcb4d96-9a5c-4443-a7f7-13420882957b','琳禪人歸豫章','釋智愚','宋','宋诗','song-poetry','','[]','慎將窺管鑑靈知，用在亡羊愧在斯。',32,'全唐诗/poet.song.196000.json','["慎將窺管鑑靈知，用在亡羊愧在斯。", "莫謂西山好消息，須知江海有名緇。"]'),
('9c25531b-a73b-4b09-972d-4a1e808f6e3c','雲山小景','釋智愚','宋','宋诗','song-poetry','','[]','渺渺晴烟薄，蒼蒼古樹昏。',24,'全唐诗/poet.song.196000.json','["渺渺晴烟薄，蒼蒼古樹昏。", "天涯殊未足，對此暗消魂。"]'),
('e27f1c50-952a-4d28-8735-b91232da75f6','孤山','釋智愚','宋','宋诗','song-poetry','','[]','黯黯青青一望中，迥然不與衆峯同。',32,'全唐诗/poet.song.196000.json','["黯黯青青一望中，迥然不與衆峯同。", "白雲散盡江天曉，想見人間無路通。"]'),
('a92b4ac2-14d4-41ff-a977-ece13ca5c621','和秉彜李君五偈  其一','釋智愚','宋','宋诗','song-poetry','','[]','深夜何人立少林，見成公案不須尋。',32,'全唐诗/poet.song.196000.json','["深夜何人立少林，見成公案不須尋。", "堆山積嶽難消遣，相對頑然鐵作心。"]'),
('48be3977-6ef7-4cb1-bb3e-abf9a4e9459a','和秉彜李君五偈  其二','釋智愚','宋','宋诗','song-poetry','','[]','呈瑞喧傳是有年，眼前分曉被人謾。',32,'全唐诗/poet.song.196000.json','["呈瑞喧傳是有年，眼前分曉被人謾。", "自家冷暖知來處，老骨從前不怕寒。"]'),
('44a8d9d0-b969-44f6-b81b-6cec9bd1c4f4','和秉彜李君五偈  其三','釋智愚','宋','宋诗','song-poetry','','[]','千鈞之重一毫輕，好向聊將尉客情。',32,'全唐诗/poet.song.196000.json','["千鈞之重一毫輕，好向聊將尉客情。", "縱擬怪松爲玉樹，月高依舊可憐生。"]'),
('f567872b-f5fd-42ca-84a8-3791fd6bdff4','和秉彜李君五偈  其四','釋智愚','宋','宋诗','song-poetry','','[]','曉聽君臣慶賀時，六街如晝不曾迷。',32,'全唐诗/poet.song.196000.json','["曉聽君臣慶賀時，六街如晝不曾迷。", "普賢境界應垂問，手詔來時見紫泥。"]'),
('8d043f97-6396-4ffc-8800-53a9b42c53b5','和秉彜李君五偈  其五','釋智愚','宋','宋诗','song-poetry','','[]','爐邊呵凍得能多，端石無辜日夜磨。',32,'全唐诗/poet.song.196000.json','["爐邊呵凍得能多，端石無辜日夜磨。", "却把悼詞爲雪咏，詩魔難敵勝修羅。"]'),
('b3bd752c-4f7d-43be-985b-dd88c65f95c5','贈禪客智仁','釋智愚','宋','宋诗','song-poetry','','[]','法戰場中樹勝旗，話頭何似問頭危。',32,'全唐诗/poet.song.196000.json','["法戰場中樹勝旗，話頭何似問頭危。", "古人減竈添兵處，切忌交鋒蹉過伊。"]'),
('92f22a94-1f85-4e15-b737-d9743d728f5f','問話行者智仁炷香請語以此贈之景定癸亥至節虛堂老僧書于雪竇西菴送日本南浦知客','釋智愚','宋','宋诗','song-poetry','','[]','敲磕門庭細揣磨，路頭盡處再經過。',32,'全唐诗/poet.song.196000.json','["敲磕門庭細揣磨，路頭盡處再經過。", "明明說與虛堂叟，東海兒孫日轉多。"]'),
('d63155f0-8cf6-4092-8313-8a8b299c3669','辭世頌','釋智愚','宋','宋诗','song-poetry','','[]','八十五年，佛祖不識。',20,'全唐诗/poet.song.196000.json','["八十五年，佛祖不識。", "掉臂便行，太虛絕跡。"]'),
('4c3452a6-94cd-49af-b723-1416d33472ba','頌古三首  其一','釋智愚','宋','宋诗','song-poetry','','[]','金鍾夜擊九重城，六載歸來改瘦形。',32,'全唐诗/poet.song.196000.json','["金鍾夜擊九重城，六載歸來改瘦形。", "待得衆生心眼活，雪山依舊碧崚層。"]'),
('900b7d8a-53f7-47a8-ad97-325e8e40fb22','頌古三首  其二','釋智愚','宋','宋诗','song-poetry','','[]','力在如今作用時，情存毫忽便成欺。',32,'全唐诗/poet.song.196000.json','["力在如今作用時，情存毫忽便成欺。", "誰知脩水千峰碧，盡入秋風一瘦藜。"]'),
('e85b17ff-6d8a-42b8-8063-6231e58ed316','頌古三首  其三','釋智愚','宋','宋诗','song-poetry','','[]','一拳拳倒黄鶴樓，一趯趯反鸚鵡洲。',32,'全唐诗/poet.song.196000.json','["一拳拳倒黄鶴樓，一趯趯反鸚鵡洲。", "有意氣時添意氣，不風流處也風流。"]'),
('815a0961-0fc0-4c70-ac94-21ebd682b6d2','劍池','釋智愚','宋','宋诗','song-poetry','','[]','石壁千尋勢嶮巇，下臨寒玉浸蟾輝。',32,'全唐诗/poet.song.196000.json','["石壁千尋勢嶮巇，下臨寒玉浸蟾輝。", "古今多少凭闌者，親見干將到底稀。"]'),
('d9c6c29f-fc66-450c-8c50-e2b423412946','憨憨泉','釋智愚','宋','宋诗','song-poetry','','[]','憨泉一掬清無底，暗與曹源正脤通。',32,'全唐诗/poet.song.196000.json','["憨泉一掬清無底，暗與曹源正脤通。", "陸羽若教知此味，定應天下水無功。"]'),
('d77532d6-0a1c-4eae-9ff3-913cbabfba1e','千人座','釋智愚','宋','宋诗','song-poetry','','[]','蒼厓險處坦然平，萬指曾來此聽經。',32,'全唐诗/poet.song.196000.json','["蒼厓險處坦然平，萬指曾來此聽經。", "若謂生公消息遠，一聲啼鳥共誰聽。"]'),
('c423e23a-29d3-4097-a8f0-ba0a393483df','點頭石','釋智愚','宋','宋诗','song-poetry','','[]','大包才剖礙人間，日炙風吹轉放頑。',32,'全唐诗/poet.song.196000.json','["大包才剖礙人間，日炙風吹轉放頑。", "見說聽經曾肯首，更須來透鐵門關。"]'),
('33ef3934-79d7-42f6-be10-503a373584dd','試劍石','釋智愚','宋','宋诗','song-poetry','','[]','雲骨深埋草莽中，竟傳秦王試靈鋒。',32,'全唐诗/poet.song.196000.json','["雲骨深埋草莽中，竟傳秦王試靈鋒。", "舊痕尚带春苔綠，一罅能生偃草風。"]'),
('e374f1da-68ad-4f54-b864-b5403471e9de','生公講臺','釋智愚','宋','宋诗','song-poetry','','[]','鱗皴瘦石籠寒蘚，千石遺蹤意轉新。',32,'全唐诗/poet.song.196000.json','["鱗皴瘦石籠寒蘚，千石遺蹤意轉新。", "縱使天花來墮席，何如緘口過殘春。"]'),
('09d9491b-82e5-4cbf-b4fb-27f21d55374f','花雨亭','釋智愚','宋','宋诗','song-poetry','','[]','昔人曾此談空有，花雨紛紛繞座寒。',32,'全唐诗/poet.song.196000.json','["昔人曾此談空有，花雨紛紛繞座寒。", "堪笑空生無伎倆，不曾開口被人瞞。"]'),
('1c6c3472-2d7a-458d-8dab-94ed9b93eb33','小吳軒','釋智愚','宋','宋诗','song-poetry','','[]','結茅初不爲孤峯，祇愛登臨眼底空。',32,'全唐诗/poet.song.196000.json','["結茅初不爲孤峯，祇愛登臨眼底空。", "風淡雲收見天末，始知吳在一毫中。"]'),
('ebc234f5-5e78-4d07-84d8-c1baf344a689','吳王闔廬墓','釋智愚','宋','宋诗','song-poetry','','[]','海湧通幽一徑深，怪來時作老龍吟。',32,'全唐诗/poet.song.196000.json','["海湧通幽一徑深，怪來時作老龍吟。", "闔閭覿面無回迹，休向空山斷處尋。"]'),
('38561f31-2a01-4115-a06b-7a87d099b097','日本照禪者欲得數字徑以述懷贈之','釋智愚','宋','宋诗','song-poetry','','[]','世路多巇嶮，無思不研窮。',48,'全唐诗/poet.song.196000.json','["世路多巇嶮，無思不研窮。", "平生見諸老，今日自成翁。", "認字眼猶綻，過譚耳尚聾。", "任天行直道，休問馬牛風。"]'),
('b4998cae-4099-479e-950a-23ba2ecd556e','榕陰圖','胡夢昱','宋','宋诗','song-poetry','','[]','古人遺直今人是，肯效鄉原事踽涼。',64,'全唐诗/poet.song.196000.json','["古人遺直今人是，肯效鄉原事踽涼。", "不把危言陳北闕，因何著脚到南荒。", "排奸斥佞風霜手，耐冷禁寒鐵石腸。", "贏得榕陰濃密處，忘言默坐對爐香。"]'),
('79e4e5ca-934e-4938-9e22-9eb3876f183e','步王盧溪韻  其一','胡夢昱','宋','宋诗','song-poetry','','[]','新來時事不相關，贏得蠻荒日月閒。',64,'全唐诗/poet.song.196000.json','["新來時事不相關，贏得蠻荒日月閒。", "存取丹心照碧漢，任他黄口閙清班。", "非求美譽傳千古，不欲浮生愧兩間。", "天亦而今無奈說，秀才且荷肯相還。"]'),
('d4f92e3c-351a-43ee-8808-919dabba4344','步王盧溪韻  其二','胡夢昱','宋','宋诗','song-poetry','','[]','瘴地人憂我莫支，人雖危我我何危。',64,'全唐诗/poet.song.196000.json','["瘴地人憂我莫支，人雖危我我何危。", "元來憂國不怕死，非爲捐身要出奇。", "肯怨江山千里遠，幸逢天地一時知。", "孔光張禹人無笑，祿位輸他善保持。"]'),
('2b78a27b-09bf-4e96-95eb-1fcdd1bc6eb2','再寄','胡夢昱','宋','宋诗','song-poetry','','[]','沉沉漢殿曉烟迷，燕雀輸他取次飛。',64,'全唐诗/poet.song.196000.json','["沉沉漢殿曉烟迷，燕雀輸他取次飛。", "爰把丹衷吐骨鯁，且甘白飯與魚肥。", "意循天理可無忤，豈料人心各有機。", "日薄西山予未死，當留此語待公歸。"]'),
('5cbbfdb8-a67e-4df0-8b0c-b1d6065fe052','挽胡季昭','楊賓言','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','湛湛長江月，高標太華清。',48,'全唐诗/poet.song.196000.json','["湛湛長江月，高標太華清。", "孤忠千古重，去國一身輕。", "箇事從來有，近來多怕行。", "凜然公屹立，一死足平生。"]'),
('5d98a4bf-caf2-4a33-a0b5-39a2b6b62572','挽胡季昭用王盧溪韻  其一','羅䦔','宋','宋诗','song-poetry','','[]','虎豹摩牙闖九關，人心節義不踰閑。',64,'全唐诗/poet.song.196000.json','["虎豹摩牙闖九關，人心節義不踰閑。", "監門鄭俠能無懼，折檻朱雲若是班。", "頼有名留千古重，不容身在衆邪間。", "忠臣義士骨不朽，白日青天敕許還。"]'),
('453cc259-cc06-4b8f-9a7c-0dff96734ed9','挽胡季昭用王盧溪韻  其二','羅䦔','宋','宋诗','song-poetry','','[]','百世期令固本支，一身寧復許安危。',64,'全唐诗/poet.song.196000.json','["百世期令固本支，一身寧復許安危。", "前瞻象郡賢方去，後有鶴山人效奇。", "地接宜陽山谷笑，舟回湘水屈原知。", "櫝中龜玉而輕毀，祿位何妨善保持。"]'),
('1a4bb314-f48a-4b74-8050-98ee3c7a1097','送胡季昭謫象州','李伯圭','宋','宋诗','song-poetry','','[]','伏馬總爲芻豆謀，孤忠嫠緯不勝憂。',64,'全唐诗/poet.song.196000.json','["伏馬總爲芻豆謀，孤忠嫠緯不勝憂。", "事當言路官無小，理未安時心肯休。", "千古綱常增砥柱，一身去就等虛舟。", "惡鴟儘任陵鸞鳳，贏得清名雪外州。"]'),
('03c04345-40cc-4b21-8985-41f728ac7773','挽胡季昭二首  其一','李伯圭','宋','宋诗','song-poetry','','[]','危言不畏觸干戈，瘴雨蠻烟換玉珂。',64,'全唐诗/poet.song.196000.json','["危言不畏觸干戈，瘴雨蠻烟換玉珂。", "今古廬陵兩胡老，是非儋耳一東坡。", "拳拳抗志甘三已，惻惻招魂聽九歌。", "信得平生稽古力，初心不爲履朝靴。"]'),
('fb4e79ba-3ae0-40ca-8e14-5e255585155f','挽胡季昭二首  其二','李伯圭','宋','宋诗','song-poetry','','[]','聖朝寬詔下龍墀，盡放纍臣脫串覊。',64,'全唐诗/poet.song.196000.json','["聖朝寬詔下龍墀，盡放纍臣脫串覊。", "痛失長沙賈誼舍，空存潮海退之祠。", "孤忠元自輕生死，白骨寧知問去歸。", "萬里江山丹旐返，悲風一掬淚沾衣。"]'),
('98aed066-c07b-4559-8d08-49594942f88b','送胡季昭謫象郡','杜豐','宋','宋诗','song-poetry','','[]','廬陵一小郡，百歲兩胡公。',48,'全唐诗/poet.song.196000.json','["廬陵一小郡，百歲兩胡公。", "論事雖小異，處心應略同。", "有書莫焚稿，無恨豈傷弓。", "病愧不遠別，寫詩霜月中。"]'),
('223f7ac9-b837-49d8-96ac-2dfdb5b45f87','送胡季昭謫象州','曾夢選','宋','宋诗','song-poetry','','[]','象州銷黯又欽州，道路何辭作遠游。',64,'全唐诗/poet.song.196000.json','["象州銷黯又欽州，道路何辭作遠游。", "投北誰憐新逐客，落南不減舊編修。", "江山在處猶加護，廊廟諸公底著羞。", "天定從來人可勝，著書消日海西頭。"]'),
('292cca61-fb2c-4a1f-ab47-b4745e3cc044','送胡季昭謫象州次王盧溪送澹庵貶新州韻  其一','李元實','宋','宋诗','song-poetry','','[]','知公不怕鬼門關，直氣橫干清禁閑。',64,'全唐诗/poet.song.196000.json','["知公不怕鬼門關，直氣橫干清禁閑。", "鵰嘴明知林甫毒，鯁言要與澹庵班。", "一身渠任黄茆裏，千古名標青史間。", "非晚清朝邪正辨，紫薇紅藥待君還。"]'),
('7093ab56-5007-4e1f-8605-8cee170f8db4','送胡季昭謫象州次王盧溪送澹庵貶新州韻  其二','李元實','宋','宋诗','song-poetry','','[]','清名傳播到黄支，直節寧憂趙氏危。',64,'全唐诗/poet.song.196000.json','["清名傳播到黄支，直節寧憂趙氏危。", "虎尾蹈時都不畏，象臺到日大爲奇。", "是行廊廟人皆怍，所過山川鬼亦知。", "官職本爲錫底鴆，傷今正論有誰持。"]'),
('9a1ea981-76b6-4bfd-a2f5-64bbf1297a41','再作十絕寄胡伯負兵侍仲方尚書  其一','李元實','宋','宋诗','song-poetry','','[]','文昌武庫九霄中，翁是新州老澹翁。',32,'全唐诗/poet.song.196000.json','["文昌武庫九霄中，翁是新州老澹翁。", "應念象臺今日客，清風端與我翁同。"]'),
('800a722a-62b3-4d9c-b529-e580d6855300','再作十絕寄胡伯負兵侍仲方尚書  其二','李元實','宋','宋诗','song-poetry','','[]','公家富貴足掀天，都出新州十九年。',32,'全唐诗/poet.song.196000.json','["公家富貴足掀天，都出新州十九年。", "若念象臺今日客，方知澹老子孫賢。"]'),
('859eff48-d727-418d-ad6d-17210c012de9','再作十絕寄胡伯負兵侍仲方尚書  其三','李元實','宋','宋诗','song-poetry','','[]','官職廬陵不是無，文章更亦擬歐蘇。',32,'全唐诗/poet.song.196000.json','["官職廬陵不是無，文章更亦擬歐蘇。", "若言直氣橫牛斗，但見人間說姓胡。"]'),
('ee4d6a9b-07fc-4b53-b2a7-030266b23d9e','再作十絕寄胡伯負兵侍仲方尚書  其四','李元實','宋','宋诗','song-poetry','','[]','赤手批鱗事最難，況渠班底一微官。',32,'全唐诗/poet.song.196000.json','["赤手批鱗事最難，況渠班底一微官。", "澹翁去後能如此，當作三生石上看。"]'),
('1861e591-ae0f-4c00-ab0a-eb1c0dc86e7c','再作十絕寄胡伯負兵侍仲方尚書  其五','李元實','宋','宋诗','song-poetry','','[]','澹翁直氣貫三才，入座雲仍漸上臺。',32,'全唐诗/poet.song.196000.json','["澹翁直氣貫三才，入座雲仍漸上臺。", "料想而今聞底事，中心應亦念渠回。"]'),
('c51969e5-d086-4307-989d-ff0ebeaeb5bf','再作十絕寄胡伯負兵侍仲方尚書  其六','李元實','宋','宋诗','song-poetry','','[]','朝行多少氣英英，不怕霜朝曲嘴鷹。',32,'全唐诗/poet.song.196000.json','["朝行多少氣英英，不怕霜朝曲嘴鷹。", "一網而今都打盡，廬陵人且說廬陵。"]'),
('6eef7a32-baf9-4218-a2dd-2e6cafa2f998','再作十絕寄胡伯負兵侍仲方尚書  其七','李元實','宋','宋诗','song-poetry','','[]','紹興秦檜秉洪鈞，澹老昌言斬檜秦。',32,'全唐诗/poet.song.196000.json','["紹興秦檜秉洪鈞，澹老昌言斬檜秦。", "猶恨日來三四子，抗章不說斬奸臣。"]'),
('7a1c294e-e69b-44c5-94fb-374cdb3e7a27','再作十絕寄胡伯負兵侍仲方尚書  其八','李元實','宋','宋诗','song-poetry','','[]','一從藝祖握乾符，元氣都憑直氣扶。',32,'全唐诗/poet.song.196000.json','["一從藝祖握乾符，元氣都憑直氣扶。", "若欲皇家宗社永，胡家直氣豈容無。"]'),
('c5752350-a003-4c45-99ef-e6eff873d7cc','再作十絕寄胡伯負兵侍仲方尚書  其九','李元實','宋','宋诗','song-poetry','','[]','東西兩浙及閩川，皆見鴛行有直言。',32,'全唐诗/poet.song.196000.json','["東西兩浙及閩川，皆見鴛行有直言。", "若我江西獨鉗口，澹翁九地也埋寃。"]'),
('a055279d-b90a-415b-aae4-f106ea373c0d','再作十絕寄胡伯負兵侍仲方尚書  其一○','李元實','宋','宋诗','song-poetry','','[]','寄語朝家廊廟人，新州奇事又重新。',32,'全唐诗/poet.song.196000.json','["寄語朝家廊廟人，新州奇事又重新。", "肯甘富貴忘他底，應爲斯人作好春。"]'),
('f4ee75a6-1f66-40f5-b00f-d25f8e05e5b5','遊洞霄','釋法照','宋','宋诗','song-poetry','','[]','天柱華心結蕊宮，翠蛟飛玉滾溪風。',32,'全唐诗/poet.song.196000.json','["天柱華心結蕊宮，翠蛟飛玉滾溪風。", "巖生洞穴非人世，不到那知造化功。"]'),
('ce1edf0d-cad5-44d1-9a8d-6c24c68ab1b9','垂虹晚望','釋法照','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','老眼青青望洞庭，虹垂斷岸月初生。',32,'全唐诗/poet.song.196000.json','["老眼青青望洞庭，虹垂斷岸月初生。", "滔滔橋下無情水，不爲吳王洗甲兵。"]'),
('1358ba91-75e7-4d1b-855d-6b109ab43346','表忠觀','釋法照','宋','宋诗','song-poetry','','[]','錢王古廟鎖莓苔，華表秋深鶴不來。',32,'全唐诗/poet.song.196000.json','["錢王古廟鎖莓苔，華表秋深鶴不來。", "昨夜石壇風露重，凌霄花落鳳仙開。"]'),
('7b836d3b-a968-4fee-82bd-18b2ed785db9','辭世偈','釋法照','宋','宋诗','song-poetry','','[]','佛壽八十，我多九年。',20,'全唐诗/poet.song.196000.json','["佛壽八十，我多九年。", "虛空掇轉，大用現前。"]'),
('ce8641db-785c-4670-b8f3-3706b78026b4','送南浦明公歸日本','釋惟俊','宋','宋诗','song-poetry','','[]','空手東來已十霜，依然空首□回檣。',32,'全唐诗/poet.song.196000.json','["空手東來已十霜，依然空首□回檣。", "明明一片祖師意，莫作唐朝事舉揚。"]'),
('a17aa03e-87c3-4e4c-8d0c-9b9c40df90f8','月巖','趙師恕','宋','宋诗','song-poetry','','[]','睠此巖壑勝，領客共登臨。',132,'全唐诗/poet.song.196000.json','["睠此巖壑勝，領客共登臨。", "危棧臨不測，巇塗歷𡼭嶔。", "俯仰極高低，上下窮幽深。", "來登空明山，千崖正沉沉。", "下瞰清羅江，古木鬰蕭森。", "清風萬里來，層雲盪孤襟。", "有客可共賦，有酒可自斟。", "此景豈易得，此樂豈易尋。", "吾生今老矣，遁迹歸窮岑。", "一棹下瀟湘，此別意難任。", "別後無相忘，詩成寄郵音。"]'),
('0c387c47-60f2-4c3e-9902-f9144ca84ba2','上喻史君重建霞起堂六首  其一','陳夢建','宋','宋诗','song-poetry','','[]','丈人昔日經行處，草暗苔荒四十春。',32,'全唐诗/poet.song.196000.json','["丈人昔日經行處，草暗苔荒四十春。", "誰倚高寒訪陳迹，璇題寶墨一時新。"]'),
('e2bb213f-6887-48dd-ab30-03b011f28648','上喻史君重建霞起堂六首  其二','陳夢建','宋','宋诗','song-poetry','','[]','酒酣步出玉霄峯，此去天關隔幾重。',32,'全唐诗/poet.song.196000.json','["酒酣步出玉霄峯，此去天關隔幾重。", "霞佩頡頏風雨上，清都只在嘿存中。"]'),
('86ad7ecc-2870-47d4-b1bb-2414b3db0463','上喻史君重建霞起堂六首  其三','陳夢建','宋','宋诗','song-poetry','','[]','詩社神交識迺翁，耳孫凜凜有仙風。',32,'全唐诗/poet.song.196000.json','["詩社神交識迺翁，耳孫凜凜有仙風。", "青雲垂上斜飛去，時要題詩徧浙東。"]'),
('80994fb4-d104-490e-8d0d-1d71cea06c80','上喻史君重建霞起堂六首  其四','陳夢建','宋','宋诗','song-poetry','','[]','玉泉天上古仙伯，曾吏五雲書閣來。',32,'全唐诗/poet.song.196000.json','["玉泉天上古仙伯，曾吏五雲書閣來。", "寄語家人須候我，有時騎鶴過丹臺。"]'),
('b27470f1-0a29-4db5-9e17-3f6767cad008','上喻史君重建霞起堂六首  其五','陳夢建','宋','宋诗','song-poetry','','[]','樓觀微茫似積蘇，一麾得傍化人居。',32,'全唐诗/poet.song.196000.json','["樓觀微茫似積蘇，一麾得傍化人居。", "可能永日銷棋局，且要蒙頭讀道書。"]'),
('d4d11392-1a46-4e86-96c9-191801cdff67','示兒魯','饒炎','宋','宋诗','song-poetry','','[]','匡居終日只欽欽，一寸靈臺萬古心。',32,'全唐诗/poet.song.196000.json','["匡居終日只欽欽，一寸靈臺萬古心。", "鹿洞象山前路在，頻思寡過到而今。"]'),
('7489a9c9-2bc3-45bf-bbab-7c3f71a0c18e','宮詞','陳昉','宋','宋诗','song-poetry','','[]','桂影婆娑玉殿涼，風傳花漏夜聲長。',32,'全唐诗/poet.song.196000.json','["桂影婆娑玉殿涼，風傳花漏夜聲長。", "內人亦有思仙者，月下吹簫引鳳皇。"]'),
('aa0ca6f2-bcb6-472d-95cc-47c96a918fe7','寒食湖上','陳昉','宋','宋诗','song-poetry','','[]','花瘦水肥三月天，畫橈雙動木蘭船。',32,'全唐诗/poet.song.196000.json','["花瘦水肥三月天，畫橈雙動木蘭船。", "人家盡換新榆火，唯有垂楊带舊烟。"]'),
('41f5ccfd-6793-48ac-aaa7-6e565c2da751','落花','陳昉','宋','宋诗','song-poetry','','[]','蘭麝香消委廢宮，紛紛漠漠夕陽中。',64,'全唐诗/poet.song.196000.json','["蘭麝香消委廢宮，紛紛漠漠夕陽中。", "長門夢斷金閨月，南國歌殘玉樹風。", "流水池塘春色去，綠陰庭院綵雲空。", "西園半醉休回首，烟草淒淒雨正紅。"]'),
('6a2172ee-6487-4011-b1d1-c985ef7ae85b','全州','陳昉','宋','宋诗','song-poetry','','[]','湘中惟此郡，地接五溪蠻。',48,'全唐诗/poet.song.196000.json','["湘中惟此郡，地接五溪蠻。", "楚水波長碧，堯時竹尚斑。", "昔曾行樂處，今在夢魂間。", "橋是先公建，休言我涕潸。"]'),
('3113ece3-bc51-40c7-b133-6fe5f39e99d1','頌古','釋如玨','宋','宋诗','song-poetry','','[]','諸佛出身處，千般謾度量。',24,'全唐诗/poet.song.196000.json','["諸佛出身處，千般謾度量。", "東山行水上，眨眼過扶桑。"]'),
('f09d7689-ce6f-4556-b239-2c615c5b39e0','答僧問','釋如玨','宋','宋诗','song-poetry','','[]','如何是佛爛冬瓜，咬著冰霜透齒牙。',32,'全唐诗/poet.song.196000.json','["如何是佛爛冬瓜，咬著冰霜透齒牙。", "根蒂雖然無窖子，一年一度一開花。"]'),
('ff7ac733-7d46-4c12-a5ce-3146f5bcc8ae','繼天童穎禪師席後上堂說偈','釋如玨','宋','宋诗','song-poetry','','[]','新歲新擊鼓，普施新法雨。',49,'全唐诗/poet.song.196000.json','["新歲新擊鼓，普施新法雨。", "萬物盡從新，一一就規矩。", "普賢大士忻歡，乘時打門戶。", "放出白象王，遍地無尋處。"]'),
('81966ed3-d35f-4ac3-986f-a4084d1f2a6c','越溪吟','釋永頤','宋','宋诗','song-poetry','','[]','石磊磊，猿啾啾，越王霸業秋山頭。',64,'全唐诗/poet.song.196000.json','["石磊磊，猿啾啾，越王霸業秋山頭。", "英雄喪盡知何數，可怪猶存浣紗處。", "當時月照清溪頭，美人如水逐東流。", "至今片石終難改，千載猶含澤國羞。"]'),
('09fd9998-58f4-4092-887d-ee6d8385fdf6','咏懷','釋永頤','宋','宋诗','song-poetry','','[]','晨風蕩原野，高林摩蒼條。',72,'全唐诗/poet.song.196000.json','["晨風蕩原野，高林摩蒼條。", "屋上野花落，階前春草摇。", "少壯不可恃，金骨亦易銷。", "夙志歎沈泯，晚心日幽寥。", "紫烟凌石峯，綠雲生桂標。", "林懷頗清暢，況復靈景饒。"]'),
('f5f27381-add8-4eb7-9b47-2ee7c5d2536f','食新茶','釋永頤','宋','宋诗','song-poetry','','[]','自囘山中來，泉石足幽弄。',84,'全唐诗/poet.song.196000.json','["自囘山中來，泉石足幽弄。", "茶經猶挂壁，庭草積已衆。", "拜先俄食新，香凝雲乳動。", "心開神宇泰，境豁謝幽夢。", "至味延冥遐，靈爽脫塵控。", "靜語生雲雷，逸想超鸞鳳。", "飽此巖壑真，清風願遐送。"]'),
('b183ca02-b3fd-4e69-855e-d330286863af','雨後對月','釋永頤','宋','宋诗','song-poetry','','[]','清夜不復寐，蕭然據胡牀。',72,'全唐诗/poet.song.196000.json','["清夜不復寐，蕭然據胡牀。", "對此九天上，陰魄含虛光。", "光飛激洞戶，彩瑩棲雲塘。", "芙蓉雜羽蓋，暗水流瑶芳。", "景異沈昔夢，心定聞空香。", "不知孤寂身，尚此山水鄉。"]'),
('bba46700-ffec-4dc7-82a7-a549f701fe69','秋日汎西湖','釋永頤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水涼宜照影，與客上湖船。',48,'全唐诗/poet.song.196000.json','["水涼宜照影，與客上湖船。", "白浪翻紅楫，青山映碧蓮。", "鳥飛荷葉下，人散柳條邊。", "烟蓋歸來晚，燈前鶴未眠。"]'),
('58bd4ff8-09c1-4fe9-9bb6-a2587f85691a','久雨','釋永頤','宋','宋诗','song-poetry','','[]','山房十日雨，仰棟看行蝸。',48,'全唐诗/poet.song.196000.json','["山房十日雨，仰棟看行蝸。", "筍暗風庭竹，萱凝晚砌花。", "罌紅留夕火，焙綠薦春芽。", "滴滴西窗下，清泉滿石漥。"]'),
('ff5de45c-a971-4310-b03b-207ede1a8310','初秋憶湖上諸山','釋永頤','宋','宋诗','song-poetry','','[]','山中夏日足幽娛，葛帔藤牀誦寶書。',64,'全唐诗/poet.song.196000.json','["山中夏日足幽娛，葛帔藤牀誦寶書。", "白拂惹雲黏几案，清香緣竹上空虛。", "草堂夜月秋花近，水閣晨霞夕霓疎。", "遥憶錢唐舊朝寺，繞湖鐘梵早涼初。"]'),
('2715f6ff-815f-4760-a9fc-4d9d2e25c161','雪中夜吟','釋永頤','宋','宋诗','song-poetry','','[]','亂書塵席散清輝，竹院香凝宿火微。',64,'全唐诗/poet.song.196000.json','["亂書塵席散清輝，竹院香凝宿火微。", "客去蘚階黏凍屐，鳥迷庭樹入寒扉。", "重陰覆野春耕闊，列炬明山夜獵歸。", "燈下老翁吟復聽，斷崖冰折碎聲稀。"]'),
('c28db131-3b78-43a7-8812-ae25cedce65e','山村日暮','釋永頤','宋','宋诗','song-poetry','','[]','犢背斜陽暖，茅茨石樹穿。',48,'全唐诗/poet.song.196000.json','["犢背斜陽暖，茅茨石樹穿。", "行人識岡路，饑鵲噪沙田。", "遠浦生微月，荒臯起暝烟。", "羣烏飛散盡，寒水漾漁船。"]'),
('17558515-ebb1-42b1-907b-62588ebc90ff','山中晚興','釋永頤','宋','宋诗','song-poetry','','[]','松間石上聽流泉，看盡雲歸宿鳥還。',64,'全唐诗/poet.song.196000.json','["松間石上聽流泉，看盡雲歸宿鳥還。", "夕殿焚香春院閉，暮鐘沈響月階閒。", "非干獨往輕遺世，自合離羣靜掩關。", "林境翠深烟樹合，正堪高卧縱疎頑。"]'),
('efe9e57c-fab3-458a-899f-dc119d3ed62f','唐栖寺前','釋永頤','宋','宋诗','song-poetry','','[]','唐栖寺前溪水流，客帆來往舊杭州。',32,'全唐诗/poet.song.196000.json','["唐栖寺前溪水流，客帆來往舊杭州。", "津亭樹老無人記，得見幾囘僧白頭。"]'),
('23f6fd2e-69e4-42b4-8e42-aa0f87610637','觀烏鳶山下藤樹','釋永頤','宋','宋诗','song-poetry','','[]','一株老樹蔽荒林，下有藤懸巨蟒身。',32,'全唐诗/poet.song.196000.json','["一株老樹蔽荒林，下有藤懸巨蟒身。", "幾度日斜烏鳥散，山昏鬼哭斷行人。"]'),
('c101fdaf-ffff-48cb-81f5-31cc661807fc','金鵝晚眺','釋永頤','宋','宋诗','song-poetry','','[]','天低野曠樹濛濛，盡入金鵝望眼中。',64,'全唐诗/poet.song.196000.json','["天低野曠樹濛濛，盡入金鵝望眼中。", "青嶂月生雙雁去，碧溪雲繞亂帆通。", "平篙落照沈烟墅，結陣寒鴉噪暝叢。", "歲月飛騰吾懶矣，昏鐘迢遞起秋宮。"]'),
('e1410399-0eb7-4582-975b-5b4fd863d64a','送僧歸茜徑','釋永頤','宋','宋诗','song-poetry','','[]','吳渚僧歸落日曛，故王宮井已無聞。',32,'全唐诗/poet.song.196000.json','["吳渚僧歸落日曛，故王宮井已無聞。", "水邊尚有紅藍草，不染香衣染塹雲。"]'),
('78a26747-3906-41cc-9521-2b8a934210e8','牽牛花','釋永頤','宋','宋诗','song-poetry','','[]','老梅枝上挂牽牛，引得青花上樹頭。',32,'全唐诗/poet.song.196000.json','["老梅枝上挂牽牛，引得青花上樹頭。", "秋圃日斜風露冷，倒垂長蔓拂鳴鳩。"]'),
('6d00bf1c-9da9-47a8-b036-15c836645990','和韓澗泉韻題周晉仙山楹','釋永頤','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','不翦亦不斲，山楹在塵表。',84,'全唐诗/poet.song.196000.json','["不翦亦不斲，山楹在塵表。", "石泉聲淙淙，秀谷自圍繞。", "是中玄覽人，未見今日了。", "君固自無心，世亦不易曉。", "夢奠何可攀，頹然泰山小。", "當時巖壑人，百世何矯矯。", "清吟振霞纓，日翳羣陰悄。"]'),
('d5acaa84-7568-45c1-8e49-b05a906b7e95','過吳門  其一','釋永頤','宋','宋诗','song-poetry','','[]','故苑烟花百草香，五湖人去事茫茫。',32,'全唐诗/poet.song.196000.json','["故苑烟花百草香，五湖人去事茫茫。", "浮雲幾度春陰合，猶見西山白鷺行。"]'),
('47d10aee-9d23-4770-9646-00abb6c3be04','過吳門  其二','釋永頤','宋','宋诗','song-poetry','','[]','花落春江一夜風，滿江烟碧撼垂虹。',32,'全唐诗/poet.song.196000.json','["花落春江一夜風，滿江烟碧撼垂虹。", "輕舟浮載如天上，況是殘雲細雨中。"]'),
('e1bbf65a-cb8e-4bb1-99ce-5b7b1db7047a','汀漲','釋永頤','宋','宋诗','song-poetry','','[]','澤國迷春漲，芳洲生綠波。',48,'全唐诗/poet.song.196000.json','["澤國迷春漲，芳洲生綠波。", "浄涵汀樹小，閒占浦雲多。", "風晚低輕燕，川明媚浴鵝。", "望人烟思遠，奈此暮山何。"]'),
('1027c098-32bd-41d0-9898-937828d286a4','雪中送僧還竹閣  其一','釋永頤','宋','宋诗','song-poetry','','[]','白公竹閣雲生晚，城市人歸夜雪平。',32,'全唐诗/poet.song.196000.json','["白公竹閣雲生晚，城市人歸夜雪平。", "燈在北高峯頂上，塔如千尺玉長檠。"]'),
('9cc74538-cad7-4049-9c87-d7433bd32771','雪中送僧還竹閣  其二','釋永頤','宋','宋诗','song-poetry','','[]','湖練平鋪肅夜濤，柳翻王母白旌旄。',32,'全唐诗/poet.song.196000.json','["湖練平鋪肅夜濤，柳翻王母白旌旄。", "舞殘鷺翿歸何處，天上飛花散碧桃。"]'),
('b9540b64-7a15-44c5-bbd3-3e8ed957312a','山樂官寄野齋','釋永頤','宋','宋诗','song-poetry','','[]','山樂官，山樂官。',80,'全唐诗/poet.song.196000.json','["山樂官，山樂官。", "爾爲靈鳳典音樂，想爾廢職來考槃。", "莫厭山中多寂寞，山中無事忘憂樂。", "曉窗睡起春晝靜，聽爾幽情如有託。", "山樂官，山樂官。", "縱令致汝百鳥前，此聲此曲終難傳。"]'),
('05cdadab-ac89-4cfb-9433-b50c96cb2f87','往龍岫舟中','釋永頤','宋','宋诗','song-poetry','','[]','龍山溪上路，短棹臘中行。',48,'全唐诗/poet.song.196000.json','["龍山溪上路，短棹臘中行。", "雪霽寒郊闊，春囘宿霧生。", "柳摇冰綫斷，鷺起玉衣明。", "未見晴梅發，先思杖屨輕。"]'),
('9405f899-5ffd-4fdf-b079-4d108159a2ec','歸練潭','釋永頤','宋','宋诗','song-poetry','','[]','孤舟東下涉蘋溪，兩岸幽花送客西。',32,'全唐诗/poet.song.196000.json','["孤舟東下涉蘋溪，兩岸幽花送客西。", "到得山房綠陰滿，午窗猶有子規啼。"]'),
('5041a6d3-9587-4f0a-a9cb-b318a0ea3687','次韻答周伯弜信後見寄','釋永頤','宋','宋诗','song-poetry','','[]','清茶相對飲山巵，憶在西峯寺裏時。',32,'全唐诗/poet.song.196000.json','["清茶相對飲山巵，憶在西峯寺裏時。", "今日雲深無好伴，澗松獨看挂猿枝。"]'),
('e05f4615-db63-4497-ac00-b84cea663448','寄周宗聖','釋永頤','宋','宋诗','song-poetry','','[]','我心如有失，曾未識南園。',48,'全唐诗/poet.song.196000.json','["我心如有失，曾未識南園。", "幾見閒花落，頻將好夢原。", "時賢多厚祿，君子尚衡門。", "詩卷逢僧寄，長吟落照村。"]'),
('b41e26d9-e09f-4391-84de-1630d7231204','遊何山登道場','釋永頤','宋','宋诗','song-poetry','','[]','中流望極山頭寺，溪午聞鐘泊柳津。',64,'全唐诗/poet.song.196000.json','["中流望極山頭寺，溪午聞鐘泊柳津。", "春草細霑微雨潤，老松高與碧虛鄰。", "鶴歸烟麓書堂廢，虎去寒巖蘚石皴。", "無奈薄游歸路晚，水邊風旆濕征塵。"]'),
('aa437867-3c23-4536-88be-7fadaf8bd591','友人銅雀臺硯','釋永頤','宋','宋诗','song-poetry','','[]','異物留傳因好古，南來篋笥伴瑶琴。',64,'全唐诗/poet.song.196000.json','["異物留傳因好古，南來篋笥伴瑶琴。", "漳河流水去無已，魏主荒臺久廢沈。", "往日姦文須九錫，今朝片瓦尚千金。", "所嗟人事多浮僞，誰識河濱古舜心。"]'),
('558e70d1-3617-40b2-93d3-0b733f82e411','過聚景園','釋永頤','宋','宋诗','song-poetry','','[]','路繞長堤萬柳斜，年年春草待香車。',32,'全唐诗/poet.song.196000.json','["路繞長堤萬柳斜，年年春草待香車。", "君王不宴芳春酒，空鎖名園日暮花。"]'),
('80ba99a9-9af8-487f-ad9d-6a439f950720','宿村莊','釋永頤','宋','宋诗','song-poetry','','[]','螻蛄偷火照田溝，山鬼移燈上樹頭。',32,'全唐诗/poet.song.196000.json','["螻蛄偷火照田溝，山鬼移燈上樹頭。", "楓岸夜深茅屋閉，月明沙鳥自相謳。"]'),
('c05eb03f-9805-484e-8a29-e67314dbfb87','伯弜出示新題樂府四十章雄深雅健有長吉之風喜而有咏','釋永頤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','偉哉吳人周伯弜，國風雅頌今再昌。',160,'全唐诗/poet.song.196000.json','["偉哉吳人周伯弜，國風雅頌今再昌。", "鈞天洞庭不敢張，楚羋暗泣嗟窮湘。", "慶祚三百多禎祥，嗚呼四十樂府章。", "春宵翦燭飛蘭香，浩歌激烈聲洋洋。", "貞魂義血流精光，姦鬼妬魄誅幽荒。", "土木閃怪踏雪僵，茫茫萬竅塞鼓簧。", "再洗律呂調宮商，金玉振耀齊鏗鏘。", "一清一濁均陰陽，風霆變化始有常。", "咏歌唐虞及商湯，矇瞽獻納皆贊襄。", "煌煌天子朝明堂，永被金石無哀傷。"]'),
('5ae014e6-4884-4cd4-9f25-b8b5378fe5be','西峰日暮','釋永頤','宋','宋诗','song-poetry','','[]','手携一束書，秋風獨來此。',48,'全唐诗/poet.song.196000.json','["手携一束書，秋風獨來此。", "松深夜月清，水冷芙蓉死。", "嬾於簷下讀，兩眼懸秋水。", "時看澗鼠來，食我山茶子。"]'),
('e8ae9c88-6c39-48cb-904e-9ad4b2c275e3','老梅','釋永頤','宋','宋诗','song-poetry','','[]','一度開花一度新，莫嫌終老舊花身。',32,'全唐诗/poet.song.196000.json','["一度開花一度新，莫嫌終老舊花身。", "文君頭白空銜怨，不及枝間碧蘚春。"]'),
('bd7e13c9-c277-4bd1-ad93-a4fd65083217','聞子規','釋永頤','宋','宋诗','song-poetry','','[]','客情誰是不思歸，芳草春深未有期。',32,'全唐诗/poet.song.196000.json','["客情誰是不思歸，芳草春深未有期。", "昨夜月明啼更苦，山花滿樹落臙脂。"]'),
('613f2473-c497-4c15-9c4b-ec856dd0d8ac','送王以通之官金陵  其一','釋永頤','宋','宋诗','song-poetry','','[]','芳辰早失意兼衰，不擬君來重舉杯。',64,'全唐诗/poet.song.196000.json','["芳辰早失意兼衰，不擬君來重舉杯。", "雲暗月牆花氣重，蠟殘風幕鳥聲催。", "醉鄉人有江東役，乘興船從闕下囘。", "明日沙頭相送罷，荼䕷小院獨徘徊。"]'),
('dc7eeeb7-0ada-495e-9cbf-1cc18fe16b02','送王以通之官金陵  其二','釋永頤','宋','宋诗','song-poetry','','[]','伯符兄弟最英雄，千載青山繞故宮。',64,'全唐诗/poet.song.196000.json','["伯符兄弟最英雄，千載青山繞故宮。", "宋祖只知曹馬事，齊高還與獍梟同。", "暮簫尚带蘭陵怨，春水多愁舊壘空。", "登覽未應迷宿昔，夜猿啼在晉時楓。"]'),
('ca4c12d0-bc73-4433-abd4-acb4813dc836','湖上春晚','釋永頤','宋','宋诗','song-poetry','','[]','水邊三月芳菲晚，楊柳樓船擁萬家。',32,'全唐诗/poet.song.197000.json','["水邊三月芳菲晚，楊柳樓船擁萬家。", "浩浩歌鐘迷白日，不知烟寺落桐花。"]'),
('dc0d719f-5b20-41c8-ae5a-84f0037bdf80','龍山野望','釋永頤','宋','宋诗','song-poetry','','[]','聞說西潘桑柘少，舊來多種紫櫻桃。',32,'全唐诗/poet.song.197000.json','["聞說西潘桑柘少，舊來多種紫櫻桃。", "龍山春晚聊舒望，雪白梨花一丈高。"]'),
('a087421c-b781-4fe5-a997-d122abee6b2f','雲巖寺','釋永頤','宋','宋诗','song-poetry','','[]','老來好古尚關心，寺裏荒題幾度尋。',64,'全唐诗/poet.song.197000.json','["老來好古尚關心，寺裏荒題幾度尋。", "山鵲報晴窺畫閣，水雞嫌雨上高林。", "麥殘餘冷收春候，楝落輕風滯晚陰。", "無限幽懷難具寫，一憑闌罷一閒吟。"]'),
('98cc5bb3-b68d-4e49-b93d-0fb5c0d41670','秋日與知言學士','釋永頤','宋','宋诗','song-poetry','','[]','水落小山浮，山人上下游。',48,'全唐诗/poet.song.197000.json','["水落小山浮，山人上下游。", "月崖烟桂晚，風浦石蘭秋。", "食芰漁溪宿，烹葵野館留。", "肩吾相對坐，清話不知休。"]'),
('b1401512-60fd-4af8-b836-bf0e10203794','後谷春晚','釋永頤','宋','宋诗','song-poetry','','[]','烟冷雲深燕不歸，徑多松葉少花枝。',32,'全唐诗/poet.song.197000.json','["烟冷雲深燕不歸，徑多松葉少花枝。", "春風過盡無行客，白晝山獐飲石池。"]'),
('0f81d02b-336b-4a06-957d-4c083ed6feae','姚震父自剡來喜晴郊行','釋永頤','宋','宋诗','song-poetry','','[]','梅發春江棹綠波，越鄉纔離認吳歌。',64,'全唐诗/poet.song.197000.json','["梅發春江棹綠波，越鄉纔離認吳歌。", "尋花戴帽誰家去，載酒移船與客過。", "廢館夕陽寒柳動，古宮芳草白雲多。", "山行每是清晨出，歸路牛羊下遠坡。"]'),
('b912736d-ee24-439f-b608-ba185aaac636','遊霅城寄輝明遠','釋永頤','宋','宋诗','song-poetry','','[]','老來霅上經過少，不復虛堂拜皎然。',64,'全唐诗/poet.song.197000.json','["老來霅上經過少，不復虛堂拜皎然。", "窺廟野童驚古像，拊碑山客慕先賢。", "雨多亂水穿城過，日上蒼山繞郡連。", "隔港木蘭摇客棹，浦荷香散碧雲天。"]'),
('c743bbea-c699-460a-9b40-c07ff3298c37','題壁','釋永頤','宋','宋诗','song-poetry','','[]','春來日日風兼雨，開戶晴軒長翠蘿。',32,'全唐诗/poet.song.197000.json','["春來日日風兼雨，開戶晴軒長翠蘿。", "山鵲弄花飛不遠，隔檐衝散落梅多。"]'),
('a30a60b8-c8ca-4711-9bd2-a38dc8f9ece9','杉下聾僧','釋永頤','宋','宋诗','song-poetry','','[]','殿陰古杉高百尺，蒼弁虬髯森淀漆。',160,'全唐诗/poet.song.197000.json','["殿陰古杉高百尺，蒼弁虬髯森淀漆。", "林深化蝶粉光冷，威鳳飄颻感仙實。", "旁有聾僧喚不聞，囁囁枯吟如有失。", "或時兀坐何堆豗，或時手把古書帙。", "帙中明星不復記，案上吟篇已亡律。", "居山六月不知暑，地凉豔草生幽苾。", "茶竈泥崩古蘚黏，石盆仰地蓮花出。", "山童晝睡靠其旁，袴如盤絡不掩膝。", "僧今老矣無別懷，時夢響潭清汩汩。", "終當卜室居其偏，坐看蜿蜒舞清溢。"]'),
('93c0d619-d597-46ac-adc7-5d50b49e2e01','贈術者王髯','釋永頤','宋','宋诗','song-poetry','','[]','王君僧服而胡鬚，贈我手寫千隸書。',96,'全唐诗/poet.song.197000.json','["王君僧服而胡鬚，贈我手寫千隸書。", "秦漢古法淪俗筆，鍾王秘刻藏綺疏。", "君游市俗誰問此，我好奇古貧無餘。", "閒來古寺看畫壁，醉去野店烹寒魚。", "擊竹有時談九命，無錢踏雪走千墟。", "問君歲晚君何如，家有老婢歸田廬。"]'),
('09b86f06-6f3a-4109-b324-99817bbe0970','寄行宮監門王以通  其一','釋永頤','宋','宋诗','song-poetry','','[]','中興天子議攻車，歎息諸公屈壯圖。',32,'全唐诗/poet.song.197000.json','["中興天子議攻車，歎息諸公屈壯圖。", "行殿不開塵鎖合，至今風雨暗金鋪。"]'),
('0d8b541c-6b89-4f86-99d1-1c6eb460c2e9','寄行宮監門王以通  其二','釋永頤','宋','宋诗','song-poetry','','[]','玉鉤簾外前朝柳，鬭鴨闌邊小豔葩。',32,'全唐诗/poet.song.197000.json','["玉鉤簾外前朝柳，鬭鴨闌邊小豔葩。", "莫道君王不曾問，好收銀鑰護宮花。"]'),
('38f0667c-1874-4f41-a7de-688d244e7252','山行與伯弜同賦野廟','釋永頤','宋','宋诗','song-poetry','','[]','芳草沒荒基，終年掩畫扉。',48,'全唐诗/poet.song.197000.json','["芳草沒荒基，終年掩畫扉。", "酒臺乾舊滴，香殿入斜暉。", "神樹枝枝曲，山魈箇箇歸。", "春來歌鼓動，野老薦春薇。"]'),
('6c2a8dcd-a981-4379-bef2-2364633c3110','悼周晉仙  其一','釋永頤','宋','宋诗','song-poetry','','[]','蕭散嵇康輩，難教縛宦情。',48,'全唐诗/poet.song.197000.json','["蕭散嵇康輩，難教縛宦情。", "識高渾脫略，意廣惜沈嬰。", "老面烟霞古，醉衣苔蘚生。", "西峯難獨往，茶竈對誰烹。"]'),
('044be681-d4bc-45f4-bc67-48e4b511e265','悼周晉仙  其二','釋永頤','宋','宋诗','song-poetry','','[]','詩救元和失，先生學最精。',48,'全唐诗/poet.song.197000.json','["詩救元和失，先生學最精。", "律嚴方苦硬，才大始縱橫。", "貞曜何須謚，魏閑相繼生。", "他年詩集著，風雅被家聲。"]'),
('1363721c-52e0-498a-ba27-ee51dc504063','秋蟬','釋永頤','宋','宋诗','song-poetry','','[]','日落秋蟬噪柳津，爲傷風露咽聲頻。',32,'全唐诗/poet.song.197000.json','["日落秋蟬噪柳津，爲傷風露咽聲頻。", "送晴送雨江亭外，偏感舟行晚泊人。"]'),
('da7eb143-ed02-4d40-8367-0354c627c54d','乾元山洪水','釋永頤','宋','宋诗','song-poetry','','[]','乾元山頭洪水發，溪有長蛟潛伺察。',96,'全唐诗/poet.song.197000.json','["乾元山頭洪水發，溪有長蛟潛伺察。", "兩岸居人莫等閒，年深物怪終騰拔。", "往歲鄰封遭水變，只道溪流凈如練。", "倏忽人烟數里間，夜半平沈皆不見。", "東南地坼乾坤浮，幾番赤子葬洪流。", "神龜去後不復返，休看浪打石人頭。"]'),
('bd22af14-1a1b-4590-8928-cc28fec86aa6','防風王廟','釋永頤','宋','宋诗','song-poetry','','[]','萬國方尊禹，防風殞殿趨。',48,'全唐诗/poet.song.197000.json','["萬國方尊禹，防風殞殿趨。", "應憐舞干戚，獨不礙唐虞。", "祭豆侵田鼠，靈幡觸井烏。", "椒漿春奠罷，簫鼓舞村巫。"]'),
('6a3b9edf-c9fc-47ee-aadd-7f4c6a01bdf2','郜溪別周伯弜','釋永頤','宋','宋诗','song-poetry','','[]','夜館寒相對，篝燈語不眠。',48,'全唐诗/poet.song.197000.json','["夜館寒相對，篝燈語不眠。", "夕烟生水郭，風柳泊沙船。", "暖棄山中宅，春耕葑上田。", "西峯晴靄碧，歸去挹飛泉。"]'),
('d1f3cd34-0b01-454c-b445-b3ea86d1d449','山池早秋','釋永頤','宋','宋诗','song-poetry','','[]','荷葉傾香露，山池見早秋。',48,'全唐诗/poet.song.197000.json','["荷葉傾香露，山池見早秋。", "石涼幽蟹過，枝脆雨蟬休。", "廢堰憑虛漲，荒泉入亂流。", "水花紅漠漠，相對渚雲浮。"]'),
('0bbca8b8-858c-425c-8c63-60998904e07b','曉離山隠','釋永頤','宋','宋诗','song-poetry','','[]','出山便與山花別，清露叢邊不得留。',32,'全唐诗/poet.song.197000.json','["出山便與山花別，清露叢邊不得留。", "去伴水禽船上宿，石溪斜月下滄洲。"]'),
('2bddd1ac-7b8a-48a5-8c8b-1fd3005bf4b8','天竺秋日  其一','釋永頤','宋','宋诗','song-poetry','','[]','翠滴千竿溼砌苔，曲廊花木小叢開。',32,'全唐诗/poet.song.197000.json','["翠滴千竿溼砌苔，曲廊花木小叢開。", "吳僧愛覓閒吟處，偷向花邊竹裏來。"]'),
('49e4f0c6-f3b9-46ab-8f76-6d6b731fa107','天竺秋日  其二','釋永頤','宋','宋诗','song-poetry','','[]','行繞方池日又斜，青雲小注溼秋霞。',32,'全唐诗/poet.song.197000.json','["行繞方池日又斜，青雲小注溼秋霞。", "闌干幾度渾敲遍，爲引遊鱼出浪花。"]'),
('4134430a-190c-4f77-bf56-7a3334da607d','震父與僧偕至','釋永頤','宋','宋诗','song-poetry','','[]','王謝清遊带越僧，共携山老坐吳亭。',32,'全唐诗/poet.song.197000.json','["王謝清遊带越僧，共携山老坐吳亭。", "身閒不記爲官日，落落吟詩讀道經。"]'),
('1459719a-6f6e-499a-b7e0-3ba392a45c3a','茶爐','釋永頤','宋','宋诗','song-poetry','','[]','煉泥合瓦本無功，火煖常留宿炭紅。',32,'全唐诗/poet.song.197000.json','["煉泥合瓦本無功，火煖常留宿炭紅。", "有客適從雲外至，小瓶添水作松風。"]'),
('2cbb643e-44cd-48b1-b005-90585ac4c26b','惜梅贈別','釋永頤','宋','宋诗','song-poetry','','[]','蘆管含愁苦怨春，況兼風雨送行頻。',32,'全唐诗/poet.song.197000.json','["蘆管含愁苦怨春，況兼風雨送行頻。", "數株零落寒雲畔，難揀香枝寄遠人。"]'),
('48cc0d96-4550-4614-af11-22a4748f2778','雨窗','釋永頤','宋','宋诗','song-poetry','','[]','江湖春水欲生時，開盡梅花雁北飛。',32,'全唐诗/poet.song.197000.json','["江湖春水欲生時，開盡梅花雁北飛。", "風雨滿庭人不寐，小窗燈火夜深微。"]'),
('89c442a9-8be8-447e-af95-991dc01badab','虎丘','釋永頤','宋','宋诗','song-poetry','','[]','山色吳門少，行人愛此游。',48,'全唐诗/poet.song.197000.json','["山色吳門少，行人愛此游。", "天高雲閣晚，石裂劍池秋。", "虎去空陵變，僧栖古塔幽。", "上方曾眺遠，落日駐扁舟。"]'),
('c2a79dd7-4a25-4467-bebf-66e2a83eb47c','送通上人歸仙潭寺','釋永頤','宋','宋诗','song-poetry','','[]','寺憶清溪遶，舟移曲岸分。',48,'全唐诗/poet.song.197000.json','["寺憶清溪遶，舟移曲岸分。", "塔昏飛雨怪，殿黑隠雷文。", "錫挂秋房冷，香浮夕帳熏。", "蘚庭閒望過，碧鶴下晴雲。"]'),
('019f66ad-9fb9-4f54-8741-41cff8a4af35','雪中  其一','釋永頤','宋','宋诗','song-poetry','','[]','風定片初微，移時鵲噪稀。',48,'全唐诗/poet.song.197000.json','["風定片初微，移時鵲噪稀。", "曲塘添柳重，彤閣映花飛。", "鶴怪雲黏石，僧疑月照扉。", "閉門高卧者，終歲復何依。"]'),
('2714b4fc-85e0-4b31-aab1-9fb099c4a244','雪中  其二','釋永頤','宋','宋诗','song-poetry','','[]','谷寺掩高扉，松亭雪側垂。',48,'全唐诗/poet.song.197000.json','["谷寺掩高扉，松亭雪側垂。", "石幢圍隠獸，野殿沒寒鴟。", "路轉空林積，風驚老樹危。", "草堂香火靜，山鹿到荒墀。"]'),
('1e535f78-f15b-4402-af4e-14a116cef4f6','感雁來紅','釋永頤','宋','宋诗','song-poetry','','[]','落落雲中雁，亭亭階下草。',72,'全唐诗/poet.song.197000.json','["落落雲中雁，亭亭階下草。", "草心將變紅，雁聲來已早。", "霜風日夜催，對此忘吾老。", "玲瓏葉數層，次第顔色好。", "燕脂染盡時，倚欄如醉倒。", "年年秋雁來，每被吟情惱。"]'),
('041dc0c2-5205-4d94-a54e-e81be473f200','寄姚贛州','釋永頤','宋','宋诗','song-poetry','','[]','雪蓬生剡溪，家近放鶴岑。',96,'全唐诗/poet.song.197000.json','["雪蓬生剡溪，家近放鶴岑。", "晉士有遺風，愛尋支遁林。", "得善忘形服，率然披素襟。", "功名亦偶爾，王戴非無心。", "今人異古昔，賤義而懷琛。", "蕭條石門咏，浩蕩東山吟。", "如何昌黎翁，醉鄉譏湎沈。", "玉带與金魚，劉畢非所欽。"]'),
('866155f9-b671-4118-9cba-fc5c91035ffa','秋館','釋永頤','宋','宋诗','song-poetry','','[]','林暑漸消歇，爽氣浮高松。',48,'全唐诗/poet.song.197000.json','["林暑漸消歇，爽氣浮高松。", "風蟬有遺響，露花結秋紅。", "微月出東嶺，碧雲散遐穹。", "暮館正虛寂，泉聲雜鳴蛩。"]'),
('a2dd6785-8ea6-420f-bdb7-9e7bb115d079','送別','釋永頤','宋','宋诗','song-poetry','','[]','送別春湖動客心，荇花無浪颭寒金。',32,'全唐诗/poet.song.197000.json','["送別春湖動客心，荇花無浪颭寒金。", "晴山望極連江郡，沙鳥風檣度遠林。"]'),
('40b15361-6a49-4ca1-b7e9-b276ee7e1792','宿永安潭上','釋永頤','宋','宋诗','song-poetry','','[]','子規啼在亂山中，廢寺春深暮閣重。',32,'全唐诗/poet.song.197000.json','["子規啼在亂山中，廢寺春深暮閣重。", "門外永安潭上水，朝昏惟送一樓鐘。"]'),
('ede0213e-06ee-4090-8448-c822801ffc5e','水仙花','釋永頤','宋','宋诗','song-poetry','','[]','洛浦香銷珮解時，荆臺歸去峽雲遲。',32,'全唐诗/poet.song.197000.json','["洛浦香銷珮解時，荆臺歸去峽雲遲。", "綠羅湘带無心疊，玉墜頭花一半垂。"]'),
('199bb65c-f58b-4d81-a9e1-594841bd7758','送天竺僧還鄉','釋永頤','宋','宋诗','song-poetry','','[]','月冷雲深天上寺，桂花千樹遶樓臺。',32,'全唐诗/poet.song.197000.json','["月冷雲深天上寺，桂花千樹遶樓臺。", "歸時若對閒人說，莫道身從月裏來。"]'),
('19d1c24b-0faf-4301-9205-804f61cf2873','廢宮','釋永頤','宋','宋诗','song-poetry','','[]','渺渺笙歌散石筵，霓旌吹斷網蛛懸。',32,'全唐诗/poet.song.197000.json','["渺渺笙歌散石筵，霓旌吹斷網蛛懸。", "經年不鎖青鸞殿，野鶴飛來玉几前。"]'),
('6747e350-29c2-4c7c-b783-ede38d01a6a8','溪上','釋永頤','宋','宋诗','song-poetry','','[]','休文壠上陰雲起，雨漲定安橋下水。',32,'全唐诗/poet.song.197000.json','["休文壠上陰雲起，雨漲定安橋下水。", "漁人莫倚滿溪流，見說長蛟劍爲齒。"]'),
('2ad06a23-43ec-424a-8b12-ca6f55957feb','看梅雜興  其一','釋永頤','宋','宋诗','song-poetry','','[]','春動晴山照野扉，早梅開後失歸期。',32,'全唐诗/poet.song.197000.json','["春動晴山照野扉，早梅開後失歸期。", "夕陽無柰山郵路，過盡行人雪滿枝。"]'),
('048eda60-a87a-4253-8312-29afb5b24355','看梅雜興  其二','釋永頤','宋','宋诗','song-poetry','','[]','挂頭方帽與烏紗，兄自看梅弟煮茶。',32,'全唐诗/poet.song.197000.json','["挂頭方帽與烏紗，兄自看梅弟煮茶。", "閒問水邊行樂去，向陽渾有幾株花。"]'),
('43382d65-be58-4c96-9c68-33337c9cdd6e','看梅雜興  其三','釋永頤','宋','宋诗','song-poetry','','[]','青松古院一株梅，寒殿無人花自開。',32,'全唐诗/poet.song.197000.json','["青松古院一株梅，寒殿無人花自開。", "日暮老僧清梵罷，夜深偷照月華來。"]'),
('e38be309-3065-4842-9445-b8f02543fd61','野棠花','釋永頤','宋','宋诗','song-poetry','','[]','野火回飈掩舊株，新叢滿眼臨征途。',128,'全唐诗/poet.song.197000.json','["野火回飈掩舊株，新叢滿眼臨征途。", "綠攢深棘欲自蔽，千朵萬朵爭敷腴。", "新晴遠客過林坂，烟漲吳船春泊晚。", "冶豔空摇蕩子情，繁香暗逐吳姬遠。", "吳姬漂泊行人愁，年年此花開不休。", "半壓壞牆荒館外，亂生春蕻野池頭。", "人間買花貴紈綺，一世爭知異朝市。", "曲檻朱欄轉首空，野棠無主自成叢。"]'),
('1d7050fc-5bfc-41e4-a1e6-b315edb69b6a','春暮懷伯弜','釋永頤','宋','宋诗','song-poetry','','[]','篔簹深谷近青霄，春盡思君夢自勞。',64,'全唐诗/poet.song.197000.json','["篔簹深谷近青霄，春盡思君夢自勞。", "歌鳥不來香室掩，綬花空結紫藤高。", "荒池瓦礫迷芳草，曉案烟雲擁墨袍。", "山近響潭多勝好，論詩無處覓劉曹。"]'),
('b75b2a9a-3910-4293-b3d1-e21cea7e7b15','苧瀆夜泊','釋永頤','宋','宋诗','song-poetry','','[]','吳城水冷秋風高，迎霜楓葉飄城壕。',160,'全唐诗/poet.song.197000.json','["吳城水冷秋風高，迎霜楓葉飄城壕。", "吳儂射利如射虜，高帆大艑橫江濤。", "黄昏不顧風水惡，篙兒怒擊何輕豪。", "苧瀆人家慣迎接，憧憧來往無停艘。", "水上懸燈招夜泊，沙頭認客相呼號。", "人生富貴多不足，亦有稗販當勤勞。", "萬斛高裝謀重利，斗升未給浮輕舠。", "吾生最愛魯仲連，封侯不受海上逃。", "輕世肆志甘貧賤，誰能富貴詘辱遭。", "夜歌新詩喜達旦，起看征雁飛雲臯。"]'),
('d4a152ee-d878-4a5d-a33b-34973aa31374','悼趙宰紫芝甫','釋永頤','宋','宋诗','song-poetry','','[]','紫芝昔賦天台日，桐柏宮詩老更成。',64,'全唐诗/poet.song.197000.json','["紫芝昔賦天台日，桐柏宮詩老更成。", "夢斷玉樓春帳曉，蝶迷花院夕魂輕。", "錢郎舊體終難並，姚賈新裁近有聲。", "有子無家須弔問，故交誰不爲傷情。"]'),
('4a009145-a0db-4457-9edd-765f571b2a1c','果熟','釋永頤','宋','宋诗','song-poetry','','[]','方池曲沼動林花，竹院僧閒日又斜。',32,'全唐诗/poet.song.197000.json','["方池曲沼動林花，竹院僧閒日又斜。", "西崦果園方晚熟，一雙烏臼打烏鴉。"]'),
('dbc71d77-b908-48fb-ab30-5c52b6b6c994','觀小魚','釋永頤','宋','宋诗','song-poetry','','[]','藻間相失復相尋，水面爭浮力未禁。',32,'全唐诗/poet.song.197000.json','["藻間相失復相尋，水面爭浮力未禁。", "隔岸木蘭船欲去，浪花摇動一時沈。"]'),
('3c591e86-f932-4663-8a0c-41cfe70bfa44','潭上','釋永頤','宋','宋诗','song-poetry','','[]','落葉寒潭上，秋風釣艇閒。',48,'全唐诗/poet.song.197000.json','["落葉寒潭上，秋風釣艇閒。", "片雲移晚渡，孤浪兀晴山。", "敗柵寒蕪擁，高楓夕照還。", "一鷗飛起處，烟靄暮溪灣。"]'),
('a6f0b33c-a7ee-45f9-ad06-0f8e603a1eb8','龍岫南窗書懷','釋永頤','宋','宋诗','song-poetry','','[]','茅堂猶未卜，幽興日遲回。',48,'全唐诗/poet.song.197000.json','["茅堂猶未卜，幽興日遲回。", "带雨聽昏笛，和燈看落梅。", "春風三月近，客鬢二毛催。", "憶得初來日，山寒暝葉堆。"]'),
('09aaf539-67e5-4537-befe-3eeb45099124','葺唐栖舊廬','釋永頤','宋','宋诗','song-poetry','','[]','矯時無峻節，立行虧衆美。',108,'全唐诗/poet.song.197000.json','["矯時無峻節，立行虧衆美。", "遠岳憚孤征，徘徊就鄉里。", "人情好愉悅，我老齊賢鄙。", "娓娓聽鄉言，時時容側耳。", "前脩不可見，法社漸凋毀。", "名山半征徭，祖塔亂獐麂。", "林築無清資，澤居循舊址。", "鑿牖納晴曦，蒔竹臨幽泚。", "時將了歲寒，閉戶春風裏。"]'),
('0c3d7eea-d09b-4baa-ae6c-1a3393681d5f','裴六書堂','釋永頤','宋','宋诗','song-poetry','','[]','數峯相對夕陰遮，新占書堂舊竹斜。',32,'全唐诗/poet.song.197000.json','["數峯相對夕陰遮，新占書堂舊竹斜。", "地冷石階秋菊小，一叢開得兩三花。"]'),
('1432c487-658b-43e7-80b3-4be396682fcf','西湖日暮','釋永頤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','渺渺春湖夕靄浮，落花飛燕打蘭舟。',32,'全唐诗/poet.song.197000.json','["渺渺春湖夕靄浮，落花飛燕打蘭舟。", "游人半入烟城去，月照笙歌上水樓。"]'),
('335ed71e-4b87-4153-9d47-2ead63f6d3b0','夜歸','釋永頤','宋','宋诗','song-poetry','','[]','昨夜溪上歸，雲下扣松扉。',48,'全唐诗/poet.song.197000.json','["昨夜溪上歸，雲下扣松扉。", "老褐啟重鑰，瘦厖循我衣。", "院靜雨聲大，氣寒燈暈微。", "叨叨聽林鳥，春歇訴無依。"]'),
('e6079b9e-2a65-4ad2-a2a8-5777de639f56','秋晚','釋永頤','宋','宋诗','song-poetry','','[]','拒霜花落碧潭秋，懶向山巔水際遊。',32,'全唐诗/poet.song.197000.json','["拒霜花落碧潭秋，懶向山巔水際遊。", "自看夕陽烏臼樹，白雲紅葉亂溪流。"]'),
('379d3069-82b5-4be1-b9a2-350ad1ae67ce','送僧之金陵','釋永頤','宋','宋诗','song-poetry','','[]','秋鍼感線溪，雲衲幾回披。',48,'全唐诗/poet.song.197000.json','["秋鍼感線溪，雲衲幾回披。", "隴月當窗夜，鍾山入句時。", "夢依紅樹宿，寒渡碧江遲。", "吳楚繁幽勝，相逢苦未期。"]'),
('ec1ae5c4-3862-472e-a408-3c982c6f3183','將別舊山寄伯弜','釋永頤','宋','宋诗','song-poetry','','[]','吾道貴日損，紀綱付有力。',96,'全唐诗/poet.song.197000.json','["吾道貴日損，紀綱付有力。", "誓捨耕鑿資，生以給信食。", "歲晏民物耗，霜枯鷹隼擊。", "寂士無豐姿，空田罄塵積。", "小臧別我去，晚瓢先挂壁。", "饑寒併一身，舍下無遺跡。", "窮達不異趣，死生共短息。", "碩友諒難捨，他山終易適。"]'),
('06521190-06ec-45e2-bc7b-2d49c7f49b1e','鷲峰  其一','釋永頤','宋','宋诗','song-poetry','','[]','山後山前行遍了，倚闌不是動秋吟。',32,'全唐诗/poet.song.197000.json','["山後山前行遍了，倚闌不是動秋吟。", "從頭自較山中石，烟雨苔痕幾片深。"]'),
('8ae81fbf-83c5-4366-bd0c-0e805dd03fcd','鷲峰  其二','釋永頤','宋','宋诗','song-poetry','','[]','苔峯只就階基列，卧榻雲窗烟翠涼。',32,'全唐诗/poet.song.197000.json','["苔峯只就階基列，卧榻雲窗烟翠涼。", "老去山中貪勝賞，只應迢遞負三湘。"]'),
('bfa31fd9-3d9b-4330-af0d-ca1c7e97a9d9','次韻伯弜值雨見留','釋永頤','宋','宋诗','song-poetry','','[]','澗谷饒春雨，烹茶近石池。',48,'全唐诗/poet.song.197000.json','["澗谷饒春雨，烹茶近石池。", "竹雞鳴野壍，山雉出荒籬。", "草長藏初筍，花空只舊枝。", "旅懷吟不盡，刻竹記幽期。"]'),
('1f742a03-5659-40d9-a5be-b003911d4b7e','送僧歸霅寺坐夏','釋永頤','宋','宋诗','song-poetry','','[]','道會三旬滿，鄉山九夏初。',48,'全唐诗/poet.song.197000.json','["道會三旬滿，鄉山九夏初。", "蝶移金鼓夢，龍護寶蓮書。", "日落沙洲迥，蘋香水殿虛。", "閉門溪上寺，好好自安居。"]'),
('984add8e-d5af-402b-9e6d-1bfea7d4b89d','月夜遊冷泉亭','釋永頤','宋','宋诗','song-poetry','','[]','地靈泉上寺，松壑定深清。',48,'全唐诗/poet.song.197000.json','["地靈泉上寺，松壑定深清。", "獨聽子規叫，況逢山月明。", "樹藏春洞黑，石擁夜泉鳴。", "日出喧車馬，終非隠者情。"]'),
('37e00671-0617-4ae8-909c-642a8f9d4897','寄友','釋永頤','宋','宋诗','song-poetry','','[]','聞君蕭散在田廬，想見琴書足自娛。',32,'全唐诗/poet.song.197000.json','["聞君蕭散在田廬，想見琴書足自娛。", "欲挈瓶盂就茅屋，桃源圖上有僧無。"]'),
('79aa5375-3222-4e2f-914a-ed3134506eb4','聽琴','釋永頤','宋','宋诗','song-poetry','','[]','蘼蕪香散楚江頭，湘竹叢邊淚不收。',32,'全唐诗/poet.song.197000.json','["蘼蕪香散楚江頭，湘竹叢邊淚不收。", "莫把朱絲寫離恨，夜深簾外鬼神愁。"]'),
('1c0e1ec3-da7b-4bfa-92e7-eb9a59180027','咏懷','釋永頤','宋','宋诗','song-poetry','','[]','落日重雲下，哀哀聞子規。',72,'全唐诗/poet.song.197000.json','["落日重雲下，哀哀聞子規。", "荆玉化爲土，湘淚摧空枝。", "彼禽復何怨，歲歲號春時。", "春風自無情，衆芳日夜衰。", "冉冉無終極，哀樂徒爾爲。", "睇彼川上流，浩蕩無前期。"]'),
('2d431f11-06e7-4ffc-9e68-4ecee9c922e2','春日泛舟','釋永頤','宋','宋诗','song-poetry','','[]','野外苔磯好，孤舟未可拋。',48,'全唐诗/poet.song.197000.json','["野外苔磯好，孤舟未可拋。", "碧溪沿谷口，晴柳護塘坳。", "波靜魚吹沫，林深鵲隠巢。", "輕雲障暖日，閒思渺春郊。"]'),
('1cbc0eb0-3fde-4013-873d-892a5020f720','庭心草','釋永頤','宋','宋诗','song-poetry','','[]','兀坐轉流光，見爾庭心草。',48,'全唐诗/poet.song.197000.json','["兀坐轉流光，見爾庭心草。", "亭亭花未開，靡靡葉先老。", "潛荄幾化螢，芳蕤暫妍好。", "悁慮果徒勞，吾言非計早。"]'),
('d7ed1fd2-9819-436d-8f09-a0a2c40d6b75','山樂官','釋永頤','宋','宋诗','song-poetry','','[]','古來歌舞者，樂極總幽沈。',48,'全唐诗/poet.song.197000.json','["古來歌舞者，樂極總幽沈。", "山鬼晝無影，春禽歌好音。", "梨園虛寶閟，玉樹慢荒淫。", "一曲烟蘿外，傷哉悲樂心。"]'),
('17a02562-ff24-4eaf-83a0-9f0c45c3c89d','過青芝村觀晚梅','釋永頤','宋','宋诗','song-poetry','','[]','梅花樹下春風靜，苔荒薺老圍春井。',32,'全唐诗/poet.song.197000.json','["梅花樹下春風靜，苔荒薺老圍春井。", "山翁汲泉來點茶，觸殘花下玲瓏影。"]'),
('02473ee5-8512-4941-adb1-77cd7ccbd47d','送別韶溪權上人','釋永頤','宋','宋诗','song-poetry','','[]','溪行逢雪後，明月照孤身。',48,'全唐诗/poet.song.197000.json','["溪行逢雪後，明月照孤身。", "夜榜聞烟艇，春耕見穡人。", "早梅容易落，征路往來頻。", "應感隨陽雁，年年度柳津。"]'),
('ccd4d237-0ef0-4b8f-8dbd-7ce1859d24bb','松陵答友人','釋永頤','宋','宋诗','song-poetry','','["\u592a\u6e56"]','鬰羅天上挹星躔，拾羽編衣汎碧蓮。',32,'全唐诗/poet.song.197000.json','["鬰羅天上挹星躔，拾羽編衣汎碧蓮。", "長笛亂吹明月夜，秋風濯足太湖邊。"]'),
('2b96e178-838c-4032-b8c3-4f3c2c8a5530','憶舊隠付柔上人','釋永頤','宋','宋诗','song-poetry','','[]','遥憶荒階碧蘚生，木蘭露重滴歸情。',64,'全唐诗/poet.song.197000.json','["遥憶荒階碧蘚生，木蘭露重滴歸情。", "秋山松桂皆森爽，夜館星河幾晦明。", "溪色乍涼雙鷺下，雨聲纔絕一蟬鳴。", "經房舊掩青楓老，此夜無人月影清。"]'),
('e72539b0-fc98-480d-ade2-48f7db65c0d1','寄鳳山滿上人','釋永頤','宋','宋诗','song-poetry','','[]','空生久不來，端居常掩室。',48,'全唐诗/poet.song.197000.json','["空生久不來，端居常掩室。", "緬懷舊林社，泉壑翳清密。", "古鳳閟靈音，野竹無花實。", "動植皆營營，忘言消永日。"]'),
('671f50f1-2d12-4368-8f55-6f151d70becf','周令自江夏歸郜溪','釋永頤','宋','宋诗','song-poetry','','[]','芳草萋迷征騎歸，且依張負入書帷。',64,'全唐诗/poet.song.197000.json','["芳草萋迷征騎歸，且依張負入書帷。", "家園懶記閒花草，蔬豆重甘舊藿葵。", "崔顥能吟有陳迹，禰衡作賦想當時。", "才能往往爲身累，好讀淵明飲酒詩。"]'),
('31aed18f-51e1-42bf-9055-6015b1cb32e4','春至  其一','釋永頤','宋','宋诗','song-poetry','','[]','松鳴山欲浮，昨夜春風過。',24,'全唐诗/poet.song.197000.json','["松鳴山欲浮，昨夜春風過。", "曉戶啟晴光，早鶑啼一箇。"]'),
('8de5ec8a-5afd-42a3-9999-f3fc869eabcf','春至  其二','釋永頤','宋','宋诗','song-poetry','','[]','朝吟還自酬，暮吟還自酢。',24,'全唐诗/poet.song.197000.json','["朝吟還自酬，暮吟還自酢。", "年光整整來，山房人亦樂。"]'),
('7b7e4450-3e8b-44fe-9e57-f209adc6308b','呂晉叔著作遺新茶','釋永頤','宋','宋诗','song-poetry','','[]','四葉及王游，共家原坂嶺。',108,'全唐诗/poet.song.197000.json','["四葉及王游，共家原坂嶺。", "歲摘建溪春，爭先取晴景。", "大窠有壯液，所發必奇穎。", "一朝團焙成，價與黄金逞。", "呂侯得鄉人，分贈我已幸。", "其贈幾何多，六色十五餠。", "每餠包青蒻，紅籤纏素檾。", "屑之雲雪輕，啜已神魄惺。", "會待佳客來，侑談當晝永。"]'),
('1baa99dc-b5cf-4c1c-b1d6-45b08dd2c0a8','游張園觀海棠戲作','釋永頤','宋','宋诗','song-poetry','','[]','春色都將付海棠，羣仙會處錦屏張。',32,'全唐诗/poet.song.197000.json','["春色都將付海棠，羣仙會處錦屏張。", "約齋妙出春風手，子美無情爲發揚。"]'),
('0c5d49fe-c9ba-45b9-bee5-3354c092830f','雪中海棠','釋永頤','宋','宋诗','song-poetry','','[]','蜀妃夜謁紫虛皇，玉鳳差參促曉妝。',32,'全唐诗/poet.song.197000.json','["蜀妃夜謁紫虛皇，玉鳳差參促曉妝。", "讌罷瑶臺魂未醒，臙脂臉上白雲香。"]'),
('ef0518a7-14df-4c3a-b0c3-96b337f99768','夏夜懷洞霄  其一','釋永頤','宋','宋诗','song-poetry','','[]','跣足曾穿古洞，衲衣挂在長松。',28,'全唐诗/poet.song.197000.json','["跣足曾穿古洞，衲衣挂在長松。", "一別烟霄十載，夜來夢入西峯。"]'),
('41f46e94-3338-49ac-83eb-81675ec8745b','夏夜懷洞霄  其二','釋永頤','宋','宋诗','song-poetry','','[]','凉夜宛游清境，歸時尚愛攀松。',28,'全唐诗/poet.song.197000.json','["凉夜宛游清境，歸時尚愛攀松。", "回首雲烟滿目，盡遮九鎖寒峯。"]'),
('e549439c-0ba4-4d3c-86c5-635769609e5b','荒城','趙葵','宋','宋诗','song-poetry','','[]','城荒葉落風颼颼，淮水茫茫古渡頭。',32,'全唐诗/poet.song.197000.json','["城荒葉落風颼颼，淮水茫茫古渡頭。", "回首不堪行樂地，黄花點點是離愁。"]'),
('fd951f75-63d9-442c-a5eb-d4fc50b05abd','春  其一','趙葵','宋','宋诗','song-poetry','','[]','檀板且教停，花嬌不耐驚。',48,'全唐诗/poet.song.197000.json','["檀板且教停，花嬌不耐驚。", "日融鶑語滑，風軟蝶身輕。", "縷篆銷春晝，遊絲弄晚晴。", "誰家楊柳院，笑語雜棋聲。"]'),
('dbc96c7a-82ae-49cc-811d-1e44b8cbc54e','春  其二','趙葵','宋','宋诗','song-poetry','','[]','綠竹移陰抹畫牆，倚欄紅藥殿春光。',32,'全唐诗/poet.song.197000.json','["綠竹移陰抹畫牆，倚欄紅藥殿春光。", "風開簾幙催香篆，坐聽鶑聲春晝長。"]'),
('274593c5-91b7-4da5-97ed-96972c74293d','春  其三','趙葵','宋','宋诗','song-poetry','','[]','點點殘紅纈燕泥，畫堂春暖日初遲。',32,'全唐诗/poet.song.197000.json','["點點殘紅纈燕泥，畫堂春暖日初遲。", "綠楊影裏鶑聲碎，正是南窗夢覺時。"]'),
('7253da2d-858f-4661-95fe-eb0782375679','春遊','趙葵','宋','宋诗','song-poetry','','[]','載酒尋春二月天，子規啼破綠楊烟。',32,'全唐诗/poet.song.197000.json','["載酒尋春二月天，子規啼破綠楊烟。", "日斜醉倚鞦韆柱，石上桃花紅欲然。"]'),
('791206ad-3111-46b2-9d7f-83e3a34d6426','初夏  其一','趙葵','宋','宋诗','song-poetry','','[]','院宇沈沈雨四垂，博山香斷未多時。',32,'全唐诗/poet.song.197000.json','["院宇沈沈雨四垂，博山香斷未多時。", "驅除春事風姨怨，貼水新荷又滿池。"]'),
('7c0a9f40-5e09-4118-8d79-358c8ba728fb','初夏  其二','趙葵','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u590f\u5929"]','梅子留酸濺齒牙，芭蕉分綠映窗紗。',32,'全唐诗/poet.song.197000.json','["梅子留酸濺齒牙，芭蕉分綠映窗紗。", "日高睡起無情思，閑看兒童捉柳花。"]'),
('f18b31fc-25e9-4124-a3cf-c9e1e6fba36e','初夏  其三','趙葵','宋','宋诗','song-poetry','','[]','櫻笋方夭麥報秋，梅黄雨過水平疇。',32,'全唐诗/poet.song.197000.json','["櫻笋方夭麥報秋，梅黄雨過水平疇。", "春歸欲带春風韻，枝上一聲黄栗留。"]'),
('8912fbe4-8988-42ac-bf34-9d73ea0ad9a4','上元','趙葵','宋','宋诗','song-poetry','','[]','翡翠簾開舞袖輕，寒星萬點下蓬瀛。',32,'全唐诗/poet.song.197000.json','["翡翠簾開舞袖輕，寒星萬點下蓬瀛。", "清尊對月酌不已，也向蓬窗坐到明。"]'),
('9a42a900-8d87-4a8c-bb78-b97ebc631be2','春寒','趙葵','宋','宋诗','song-poetry','','[]','春草平蕪烟雨迷，鞦韆寂寞舊園池。',32,'全唐诗/poet.song.197000.json','["春草平蕪烟雨迷，鞦韆寂寞舊園池。", "江南也是東風惡，花骨經寒瘦不支。"]'),
('fce7fe0a-bbce-414c-981d-2c6fcf5a290a','雪夜','趙葵','宋','宋诗','song-poetry','','[]','酒力欺寒淺，心清睡較遲。',24,'全唐诗/poet.song.197000.json','["酒力欺寒淺，心清睡較遲。", "梅花擎雪影，和月度疏籬。"]'),
('e9f4659c-e77d-4da4-a42b-fa755cb09115','賞花  其一','趙葵','宋','宋诗','song-poetry','','[]','人樂清明三月天，也隨人賞萬花園。',32,'全唐诗/poet.song.197000.json','["人樂清明三月天，也隨人賞萬花園。", "偷閑把酒簪花去，不似兒童笑語喧。"]'),
('73ffe6ee-b2ee-4133-801e-67dae3d19ba1','賞花  其二','趙葵','宋','宋诗','song-poetry','','[]','昨日新園去看花，路邊郎女阿誰家。',32,'全唐诗/poet.song.197000.json','["昨日新園去看花，路邊郎女阿誰家。", "香車寶馬相追逐，笑語歸來日未斜。"]'),
('ac70e53c-d81c-4a87-ab98-2e03a5c6ab01','落花','趙葵','宋','宋诗','song-poetry','','[]','他鄉桃李爲誰栽，逗曉輕紅带露開。',32,'全唐诗/poet.song.197000.json','["他鄉桃李爲誰栽，逗曉輕紅带露開。", "一夜風姨妬顔色，落花無數點蒼苔。"]'),
('2b7de5ba-444a-4f0b-ae21-92bc63ea2f06','十月見桃','趙葵','宋','宋诗','song-poetry','','[]','匼匝新園一徑通，荷經霜盡野塘空。',32,'全唐诗/poet.song.197000.json','["匼匝新園一徑通，荷經霜盡野塘空。", "桃花錯認東風暖，却與芙蓉鬭小紅。"]'),
('721598ef-ec20-47be-b33b-b6c9e594ea01','十月見菊','趙葵','宋','宋诗','song-poetry','','[]','落拓山園載酒來，江梅含雪倚春臺。',32,'全唐诗/poet.song.197000.json','["落拓山園載酒來，江梅含雪倚春臺。", "黄花無藉秋光老，猶自離披带雨開。"]'),
('fbea147c-d25b-4589-b147-57cd633d79cc','雪','趙葵','宋','宋诗','song-poetry','','[]','玉龍昨夜起天涯，曉看團花一尺圍。',32,'全唐诗/poet.song.197000.json','["玉龍昨夜起天涯，曉看團花一尺圍。", "莫放妝臺簾捲上，怕驚釵畔寶鸞飛。"]'),
('d01448a5-52fc-467d-9590-82a8faae8890','郊野','趙葵','宋','宋诗','song-poetry','','[]','白鳥衝烟去，山僧渡水來。',24,'全唐诗/poet.song.197000.json','["白鳥衝烟去，山僧渡水來。", "竹籬茅舍外，忽見野梅開。"]'),
('ce82b965-e580-4fbb-bbff-87258c43d79e','江行','趙葵','宋','宋诗','song-poetry','','[]','霜清月冷雁聲秋，今古江流不盡愁。',32,'全唐诗/poet.song.197000.json','["霜清月冷雁聲秋，今古江流不盡愁。", "風捲蘆花漫雪裏，夜深鼓櫂落汀洲。"]'),
('bd8256a3-a647-4f5d-b089-b493388f19bb','舟  其一','趙葵','宋','宋诗','song-poetry','','[]','雨過平蕪带落暉，蘆花飄泊點征衣。',32,'全唐诗/poet.song.197000.json','["雨過平蕪带落暉，蘆花飄泊點征衣。", "舟人忽報東風急，萬斛龍驤噴雪飛。"]'),
('f4b1ab1c-f723-4b77-91d8-56b85393d9fd','舟  其二','趙葵','宋','宋诗','song-poetry','','[]','櫓聲伊軋下灘來，驚起沙鷗去又回。',32,'全唐诗/poet.song.197000.json','["櫓聲伊軋下灘來，驚起沙鷗去又回。", "小艇暫停曲江滸，推篷和雪看寒梅。"]'),
('769f8de9-b87c-46c3-b886-add197b607fd','舟  其三','趙葵','宋','宋诗','song-poetry','','[]','鼓櫂過前灣，推篷破旅顔。',24,'全唐诗/poet.song.197000.json','["鼓櫂過前灣，推篷破旅顔。", "山回流水轉，烟逐曉雲閑。"]'),
('cc79fe32-3694-4903-b3de-7a28e24d32f1','樓','趙葵','宋','宋诗','song-poetry','','[]','等閑携酒上南樓，樓占東州古渡頭。',64,'全唐诗/poet.song.197000.json','["等閑携酒上南樓，樓占東州古渡頭。", "翼瓦拂天翔碧鳳，危欄隠霧鎖蒼虬。", "湖山環據三吳會，江漢雄吞四蜀流。", "醉裏浩歌天地闊，櫓聲摇月上汀洲。"]'),
('c0d58cbd-6832-42be-a27b-9d7b04a6b97e','寺  其一','趙葵','宋','宋诗','song-poetry','','[]','古木蕭森映綠苔，嵯峨樓閣倚天開。',32,'全唐诗/poet.song.197000.json','["古木蕭森映綠苔，嵯峨樓閣倚天開。", "山僧不問朝天客，自注冰泉浸野梅。"]'),
('0098c23b-9db4-46c8-9882-ec283b1331f7','寺  其二','趙葵','宋','宋诗','song-poetry','','[]','溪繞青山山繞溪，溪山勝處只僧知。',32,'全唐诗/poet.song.197000.json','["溪繞青山山繞溪，溪山勝處只僧知。", "雲閑古木禪關靜，不到禪關又幾時。"]'),
('d1311534-fcb6-411d-9538-e976d868798e','墨梅','趙葵','宋','宋诗','song-poetry','','[]','須知造物元無物，剛被花光强造端。',32,'全唐诗/poet.song.197000.json','["須知造物元無物，剛被花光强造端。", "認得色空都是幻，南枝非暖北枝寒。"]'),
('ca793585-2d26-4ba8-9f1b-54edb8b2c385','豐年','趙葵','宋','宋诗','song-poetry','','[]','一犁春雨足生涯，黍稷桑麻已滿畧。',32,'全唐诗/poet.song.197000.json','["一犁春雨足生涯，黍稷桑麻已滿畧。", "只願今年風景好，村村社酒樂農家。"]'),
('64a1fcdb-49ea-4a2e-bfdc-63117d1a1585','梅花','趙葵','宋','宋诗','song-poetry','','[]','夜深梅印橫窗月，紙帳魂清夢亦香。',32,'全唐诗/poet.song.197000.json','["夜深梅印橫窗月，紙帳魂清夢亦香。", "莫謂道人無一事，也隨疏影伴寒光。"]'),
('a2a64a72-4bdb-45ef-9990-fff643d526e4','芍藥','趙葵','宋','宋诗','song-poetry','','[]','芍藥殿春春幾許，簾幙風輕飛絮舞。',32,'全唐诗/poet.song.197000.json','["芍藥殿春春幾許，簾幙風輕飛絮舞。", "昨宵酒醉玉樓春，一聲畫角吹殘雨。"]'),
('d3b67194-5f34-456e-b7df-3bcf6dd469e2','海棠','趙葵','宋','宋诗','song-poetry','','[]','依依楊柳已藏鴉，風度鶑聲到碧紗。',32,'全唐诗/poet.song.197000.json','["依依楊柳已藏鴉，風度鶑聲到碧紗。", "洗盡春光連夜雨，海棠贏得兩三花。"]'),
('41829d9b-8ce0-4181-9a85-4a0b1935d88d','桃木','趙葵','宋','宋诗','song-poetry','','[]','誰家有女腰如束，雙眸剪水肌凝玉。',64,'全唐诗/poet.song.197000.json','["誰家有女腰如束，雙眸剪水肌凝玉。", "褪紅香汗濕鮫綃，低壓嬌花鬢雲綠。", "春光瀲灧春晝長，春風撲面春花香。", "一聲環珮鳴丁當，自臨鸞鏡勻新粧。"]'),
('c59ac8aa-ffc5-4384-b9ae-dc8d1e8004e0','菊花','趙葵','宋','宋诗','song-poetry','','[]','黄花照眼又經秋，山自青青江自流。',32,'全唐诗/poet.song.197000.json','["黄花照眼又經秋，山自青青江自流。", "多謝龍頭鰲禁客，年年把酒到江樓。"]'),
('af70dac0-acaf-4081-91e9-53df29fcb41d','柳花','趙葵','宋','宋诗','song-poetry','','[]','三月名園草色青，夢回猶聽賣花聲。',32,'全唐诗/poet.song.197000.json','["三月名園草色青，夢回猶聽賣花聲。", "春光不管人憔悴，飛絮紛紛弄晚晴。"]'),
('4b18e11c-8d18-4a63-948a-0fb3340982cc','竹  其一','趙葵','宋','宋诗','song-poetry','','[]','一抹輕烟隔小橋，新篁摇翠兩三梢。',32,'全唐诗/poet.song.197000.json','["一抹輕烟隔小橋，新篁摇翠兩三梢。", "惜春不覺歸來晚，花壓重門带月敲。"]'),
('40ab7626-c946-4868-b0f0-d9e0cf206d3f','竹  其二','趙葵','宋','宋诗','song-poetry','','[]','風竹蕭蕭梧葉黄，相思寸寸斷人腸。',32,'全唐诗/poet.song.197000.json','["風竹蕭蕭梧葉黄，相思寸寸斷人腸。", "一聲塞管來何處，鴈带秋聲入故鄉。"]'),
('8947f65f-720c-4d75-8b8f-71c73f707556','秋浦樓','趙葵','宋','宋诗','song-poetry','','[]','麗譙岧嶢壯城關，萬里關河歸目睫。',176,'全唐诗/poet.song.197000.json','["麗譙岧嶢壯城關，萬里關河歸目睫。", "雨餘漁釣玉奩開，烟生芙蓉翠屏列。", "吳頭楚尾二十秋，滿耳絃歌聲未絕。", "不才濫綴鴛鷺行，夜夢時還許歸謁。", "蕭晨振策來翠微，母憐吾兒倍怡悅。", "昔偕汝父居是邦，舊事辛苦爲兒話。", "星星鶴髮簪霞冠，笑者朱衣擁金節。", "一門和氣皆君恩，恩與天同酬未得。", "生平區區忠孝心，歲晚願爲松與柏。", "可憐清賞屬登臨，風景不殊人事別。", "徘徊徙倚十二闌，嘯聲吹上梅梢月。"]'),
('265c6061-2081-4e38-86f4-2481ca22ec47','惠山寺','趙葵','宋','宋诗','song-poetry','','[]','古木森森映碧苔，嵯峨樓閣倚天開。',32,'全唐诗/poet.song.197000.json','["古木森森映碧苔，嵯峨樓閣倚天開。", "山僧不問朝天客，自注冰泉浸野梅。"]'),
('0aba1da0-b753-419e-ab2b-7f89830f629a','貞義女咏','趙葵','宋','宋诗','song-poetry','','[]','白首辭廊廟，投閒瀨水隈。',72,'全唐诗/poet.song.197000.json','["白首辭廊廟，投閒瀨水隈。", "因觀貞女傳，深仰謫仙才。", "擊漂名猶在，沉淵事可哀。", "清魂招不得，偷俗挽教回。", "直筆遺青史，□磯鎖綠苔。", "憑將一杯酒，澆向浪花堆。"]'),
('64a647c9-743e-4251-a2af-1bb389eef160','祝融峰','趙葵','宋','宋诗','song-poetry','','[]','祝融萬仞拔地起，欲見不見青霄裏。',64,'全唐诗/poet.song.197000.json','["祝融萬仞拔地起，欲見不見青霄裏。", "山翁愛山不肯去，爲山醉卧松根底。", "家童尋著不敢驚，沉吟恐怕山翁嗔。", "夢回抖擻下山去，一徑蘿月松風清。"]'),
('07d5004e-8dcf-4b50-94b2-03f73e644b6c','荒城  其一','趙葵','宋','宋诗','song-poetry','','[]','萬里黄雲凍不飛，磧烟烽火夜深微。',32,'全唐诗/poet.song.197000.json','["萬里黄雲凍不飛，磧烟烽火夜深微。", "胡兒移帳寒笳絕，雲路時聞探馬歸。"]'),
('38221f8a-3778-4d2f-ae2c-a347002bf6c5','荒城  其二','趙葵','宋','宋诗','song-poetry','','[]','烏桓城下雨初晴，紫菊金蓮漫地生。',32,'全唐诗/poet.song.197000.json','["烏桓城下雨初晴，紫菊金蓮漫地生。", "最愛多情白翎雀，一雙飛近馬邊鳴。"]'),
('37afb89d-2202-4f0e-a3c6-9e4d21be929d','塞曲','趙葵','宋','宋诗','song-poetry','','[]','鴻傳霜信入邊州，目障烟塵昏戍樓。',32,'全唐诗/poet.song.197000.json','["鴻傳霜信入邊州，目障烟塵昏戍樓。", "多少征夫南北恨，玉關人老玉關秋。"]'),
('132ab072-3a83-49a6-a228-85344fe44a90','過小漿市','趙葵','宋','宋诗','song-poetry','','[]','人生南北與東西，幾度雲山幾度溪。',32,'全唐诗/poet.song.197000.json','["人生南北與東西，幾度雲山幾度溪。", "我亦欲歸歸未得，子規從此不須啼。"]'),
('0dd4bae9-6fba-461e-85a9-f1ab7eb64659','題金山','趙葵','宋','宋诗','song-poetry','','[]','紫金千仞鬰崔嵬，四面驚濤捲雪堆。',64,'全唐诗/poet.song.197000.json','["紫金千仞鬰崔嵬，四面驚濤捲雪堆。", "屹立中流天柱壯，高標雙闕海門開。", "江流今古幾分合，日月東西自往來。", "一覽象山皆㟝嶁，不知身世是蓬萊。"]'),
('7b527433-f5a7-4b88-96ef-cf582eeda801','避暑水亭作','趙葵','宋','宋诗','song-poetry','','[]','水亭四面朱闌繞，簇簇游魚戲萍藻。',64,'全唐诗/poet.song.197000.json','["水亭四面朱闌繞，簇簇游魚戲萍藻。", "六龍畏熱不敢行，海波煎徹蓬萊島。", "身眠七尺白蝦鬚，頭枕一枚紅瑪瑙。", "公子猶嫌扇力微，行人多在紅塵道。"]'),
('a1112559-7f38-49f1-a83a-8de85debaa38','贈石牛上人','趙葵','宋','宋诗','song-poetry','','[]','萬里江山萬里天，疏鐘半夜落漁船。',32,'全唐诗/poet.song.197000.json','["萬里江山萬里天，疏鐘半夜落漁船。", "老來羨殺禪關客，一枕江聲抱月眠。"]'),
('b2c3902d-4418-44a3-845e-ab42d6c2029f','句  其一','趙葵','宋','宋诗','song-poetry','','[]','不問春歸自放花。',8,'全唐诗/poet.song.197000.json','["不問春歸自放花。"]'),
('e190c126-94f6-4db0-b354-683da5a063da','句  其二','趙葵','宋','宋诗','song-poetry','','[]','多謝君恩好歸去，夜來小泊小孤山。',16,'全唐诗/poet.song.197000.json','["多謝君恩好歸去，夜來小泊小孤山。"]'),
('180816f4-9c52-4033-aabe-b604e7be03e0','別玉笥何鍊師  其一','陳元晉','宋','宋诗','song-poetry','','[]','軒軒黄冠師，胄出水曹後。',72,'全唐诗/poet.song.197000.json','["軒軒黄冠師，胄出水曹後。", "流風尚詩癖，聖處坐參透。", "褰裳紅塵外，心賞山水秀。", "渾融入芒端，字字遺氛垢。", "雲霧巧裁縫，冰雪工刻鏤。", "編成着山巖，光怪射牛斗。"]'),
('18804fc3-4670-47ad-b929-65d08b351dfe','別玉笥何鍊師  其二','陳元晉','宋','宋诗','song-poetry','','[]','誠齋已古人，文字上無古。',144,'全唐诗/poet.song.197000.json','["誠齋已古人，文字上無古。", "雲龍渺相從，傳家有文武。", "異聞蘄一面，渴予心獨苦。", "龍門快先登，羨子賞音遇。", "廖師抱長材，彌明吐奇語。", "牽聯千載名，政以韓子序。", "君從蕭灘來，我向贛水去。", "饑驅我漫出，可耐塵土汙。", "雲山固招君，底事闖城府。", "秋凄君且歸，我行方出戶。", "稻粱亦何味，茯苓自堪煮。", "何時扣白雲，借我一坐具。"]'),
('7cf2fa91-07bb-4da9-81b7-559fff9e3bb6','梅','陳元晉','宋','宋诗','song-poetry','','[]','吾敬林隠君，終老梅花鄉。',48,'全唐诗/poet.song.197000.json','["吾敬林隠君，終老梅花鄉。", "孤山足佳處，不願白玉堂。", "古來貧賤交，富貴渠相忘。", "歲寒誰古心，摇摇桃李場。"]'),
('275ebbcd-9a2a-4b5f-8358-cb8534de4348','竹','陳元晉','宋','宋诗','song-poetry','','[]','吾敬王子猷，傲俗獨愛竹。',48,'全唐诗/poet.song.197000.json','["吾敬王子猷，傲俗獨愛竹。", "行止必與俱，情義均骨肉。", "雲龍求友心，上下亦相逐。", "彼哉絕彜倫，乃戒桑下宿。"]'),
('424b7cb3-c456-4087-ba09-b1c69f6116e8','遊羅浮寶積寺  其一','陳元晉','宋','宋诗','song-poetry','','[]','晴峰膏秋容，遠騎駐春脚。',48,'全唐诗/poet.song.197000.json','["晴峰膏秋容，遠騎駐春脚。", "長風載之游，清月此旅酌。", "眼高天圍小，語暖雲氣薄。", "神仙邂逅親，導客以笙鶴。"]'),
('b906fa4d-9a0e-4875-a49e-c76c0780ce98','遊羅浮寶積寺  其二','陳元晉','宋','宋诗','song-poetry','','[]','半生夢羅浮，世事縛兩脚。',48,'全唐诗/poet.song.197000.json','["半生夢羅浮，世事縛兩脚。", "仙泉有誰何，生客那得酌。", "君詩挹其腴，水味從此薄。", "清遊天所裁，望極南飛鶴。"]'),
('72414e94-e934-4f9d-a2f8-5722753de631','有感','陳元晉','宋','宋诗','song-poetry','','[]','寒聲戰梧楸，風色歲行暮。',48,'全唐诗/poet.song.197000.json','["寒聲戰梧楸，風色歲行暮。", "誰念天涯人，貂裘敝塵土。", "一飽亦易營，局促良自苦。", "安得八駿蹄，駕言觀玄圃。"]'),
('631585ea-cafd-43a1-a32b-6181cb58306c','和留粹中將游南華之什','陳元晉','宋','宋诗','song-poetry','','[]','南來佳山水，清淑如三吾。',132,'全唐诗/poet.song.197000.json','["南來佳山水，清淑如三吾。", "何必二水間，獨有八境圖。", "秀水饑可餐，清淪渴可𣂏。", "頡頏飛霞佩，簸弄明月珠。", "心閑鷗許知，日遠鴻與徂。", "蓬窗苦局促，畧取山川娛。", "是間有意趣，逢人輒周諏。", "一舍兩叢林，半點塵埃無。", "頓漸非二門，凡聖同一區。", "見佛心即了，迷者直非夫。", "冥心休外觀，來此同僧趺。"]'),
('bc8084d0-0f33-4935-bd06-9b0a30461069','壽嬾庵趙先生十首  其一','陳元晉','宋','宋诗','song-poetry','','[]','更生青藜杖，長吉古錦囊。',48,'全唐诗/poet.song.197000.json','["更生青藜杖，長吉古錦囊。", "豈無芝蘭馨，終少蒹葭霜。", "精深師友漸，磨琢金玉相。", "凜此宗姓傑，高掩漢與唐。"]'),
('fa57f781-b7b6-4579-9c4a-4bb14cd7aa46','壽嬾庵趙先生十首  其二','陳元晉','宋','宋诗','song-poetry','','[]','曩時吳畏齋，槃槃極宏毅。',48,'全唐诗/poet.song.197000.json','["曩時吳畏齋，槃槃極宏毅。", "今時葉水心，表表負經濟。", "公游二老間，聖處心獨契。", "人物方眇然，甚矣夫子似。"]'),
('efe87b72-933a-4234-824e-ae05f1b88334','壽嬾庵趙先生十首  其三','陳元晉','宋','宋诗','song-poetry','','[]','皎皎疇昔心，睠焉本根計。',48,'全唐诗/poet.song.197000.json','["皎皎疇昔心，睠焉本根計。", "一鳴驚萬喑，獨醒閲衆醉。", "勇指非種鋤，有膽竟成事。", "彼哉稱國師，千載有餘媿。"]'),
('8d4c99b1-081c-4f57-bcb2-8eaa9c766746','壽嬾庵趙先生十首  其四','陳元晉','宋','宋诗','song-poetry','','[]','醫國藥萬金，補衮線五色。',48,'全唐诗/poet.song.197000.json','["醫國藥萬金，補衮線五色。", "誰令落江湖，刺史六百石。", "衆萬溝壑瀕，援手公一力。", "平生富青州，關心豈官職。"]'),
('4238dfbe-9dcd-489f-9c4b-548d1ead1f6a','壽嬾庵趙先生十首  其五','陳元晉','宋','宋诗','song-poetry','','[]','嘉師固秉彝，祥刑盡生德。',48,'全唐诗/poet.song.197000.json','["嘉師固秉彝，祥刑盡生德。", "惠文恣彈治，此意誰復識。", "雨露既天覆，刀劍亦俗革。", "活人不言功，所願長我國。"]'),
('81e0d76f-4ef3-4cfc-aa09-efd4fb805cb4','壽嬾庵趙先生十首  其六','陳元晉','宋','宋诗','song-poetry','','[]','王氣鬰東南，兵塵莽關洛。',48,'全唐诗/poet.song.197000.json','["王氣鬰東南，兵塵莽關洛。", "事會豈有極，祇恐元氣弱。", "折衝樽俎餘，欠着一諤諤。", "如公胡不歸，儒用魯何削。"]'),
('054cdb91-5bbd-4e9e-aaae-6c04313040a3','壽嬾庵趙先生十首  其七','陳元晉','宋','宋诗','song-poetry','','[]','垂弧正大夏，明炳肖火德。',48,'全唐诗/poet.song.197000.json','["垂弧正大夏，明炳肖火德。", "仙源毓英靈，帝賫扶社稷。", "恩波溢西江，釀作壽觴碧。", "一飲千斯年，福與宋無極。"]'),
('53fa4a68-22af-4bef-8a08-94a098f5f151','壽嬾庵趙先生十首  其八','陳元晉','宋','宋诗','song-poetry','','[]','書生棲大厦，燕賀媿無從。',48,'全唐诗/poet.song.197000.json','["書生棲大厦，燕賀媿無從。", "嵩高乏嘉頌，何以祝我公。", "一節貫歲寒，願似南山松。", "下有千歲苓，嘗許氣味同。"]'),
('f1b7a252-3ccc-439b-a6b1-d8e3dc3dc973','壽嬾庵趙先生十首  其九','陳元晉','宋','宋诗','song-poetry','','[]','開濟平生學，忠精一寸心。',48,'全唐诗/poet.song.197000.json','["開濟平生學，忠精一寸心。", "時危添白髮，意遠寄清吟。", "河洛風埃滿，江湖歲月深。", "眼明天柱壯，𤃩淥對渠斟。"]'),
('1176ae7b-1105-411b-ba97-aeacb50edfdf','壽嬾庵趙先生十首  其一○','陳元晉','宋','宋诗','song-poetry','','[]','楚望環宗嶽，湘源遠派浯。',48,'全唐诗/poet.song.197000.json','["楚望環宗嶽，湘源遠派浯。", "山川鍾氣異，宇宙要賢扶。", "晚遍朱軒轍，春饒綠野腴。", "遥知初度日，歌舞沸重湖。"]'),
('ae369cd9-a02c-4c47-84ac-aa3e1431e513','朱明洞天','陳元晉','宋','宋诗','song-poetry','','[]','南來大艑凌空浮，卸帆試畧羅浮秋。',160,'全唐诗/poet.song.197000.json','["南來大艑凌空浮，卸帆試畧羅浮秋。", "胸中無機神仙喜，筆底光怪山靈愁。", "山泉夜作糟床滴，風松閃冉青旗色。", "招我三啜玻璃觥，峯頭飛上八千尺。", "星微月壯海茫茫，蓬萊仙袂遥相望。", "銅龍夜吼風霧香，石橋跨空河漢長。", "千巖笙籟奏清曲，萬樹醴露如天漿。", "金鴉海底初刷翮，雲擁扶桑一枝出。", "羣仙拍手嘆絕奇，坐中相顧屬誰筆。", "阿翁曾是夾日飛，公孫請賦五色日。"]'),
('ef82253c-0e18-44c9-a811-9b200d53fac1','田家謠','陳元晉','宋','宋诗','song-poetry','','[]','長年飯不足，背裂赤日中。',114,'全唐诗/poet.song.197000.json','["長年飯不足，背裂赤日中。", "忍饑不肯懶，辛苦求年豐。", "今秋幸一熟，天意亦憚窮。", "庶幾債可了，或有餘粟舂。", "團欒共妻子，糠粃一笑同。", "焚香答天賜，力作人何功。", "君不見前年三百青銅米一斗，又不見去年蕨根掘盡不充口。", "妻孥長恐不相守，敢擬如今蘇息否。"]'),
('01a3ab9a-342f-49e7-b449-515288845e44','和馮眉州九日無酒韻','陳元晉','宋','宋诗','song-poetry','','[]','蜀日曀曀風凄凄，有美人兮愁楚羈。',128,'全唐诗/poet.song.197000.json','["蜀日曀曀風凄凄，有美人兮愁楚羈。", "白衣不來負佳節，士窮使我增歔欷。", "錦韉屢踏秦關月，寶刀尚染健兒血。", "尋思往事玩浮雲，目送孤鴻互明滅。", "醉鄉廣大無何有，無事唯當學犀首。", "不應來弔獨醒魂，却嫌閒却持螯手。", "吾儕臭味草木同，但須多植寒花叢。", "遇花開時即重九，天豈教人樽屢空。"]'),
('e3360f23-cf16-4e8a-a867-2f85d6ab6f99','贈符藥朱道士','陳元晉','宋','宋诗','song-poetry','','[]','君不見許旌陽，飛符走劍蛟龍降。',190,'全唐诗/poet.song.197000.json','["君不見許旌陽，飛符走劍蛟龍降。", "一朝功行滿仙籍，寶冊金丹來帝旁。", "又不見孫思邈，玉函方出千金藥。", "棲遲猶作地行仙，良以活人恩施博。", "要知天地德好生，鬼謀客邪胡由乘。", "有符有藥解濟世，此心即可通神明。", "桃椎耳孫樂虛靜，符水能靈藥能聖。", "呼雷麾電縛魑魅，二豎三彭俱聽命。", "困者以醒病者甦，孳孳予豈爲利圖。", "梓人作室橐駝樹，治民相國非殊塗。", "降魔要豎大法幢，起死要下黄昏湯。", "更頻物色合誰屬，請起江湖登廟堂。"]'),
('58a4a668-58e7-4f79-bf4c-cb365b089c56','胡文昌和東坡子由彭城月詩併錄澹菴新州以所和見示索和','陳元晉','宋','宋诗','song-poetry','','[]','澹菴眼似坡仙高，眇視軒冕如秋毫。',224,'全唐诗/poet.song.197000.json','["澹菴眼似坡仙高，眇視軒冕如秋毫。", "忠臣要作社稷計，那知平陸生風濤。", "當時蓋亦輕餘子，富貴轉頭真逝水。", "汗青不朽姓字香，百世聞風尚興起。", "函關正要封泥丸，金陵王氣開龍蟠。", "一書乞借尚方劍，搢紳環睨心爲寒。", "要扶鑾駕還都汴，鼎鑊在前顔不變。", "低頭辦了著南冠，歛手笑還丞相板。", "飛鳶跕跕古錦山，氣老益壯窮益堅。", "銀河流空月照地，肺肝洞作冰玉看。", "緬懷坡仙亦大好，詩比離騷興香草。", "持杯滿滿賀素娥，嶺海百年逢二老。", "聞孫趾美德不貧，清文高節猶前人。", "何當佳話重拈出，只慙授簡梁園客。"]'),
('72a2a320-8de9-487e-8987-9a816acbe7b4','採蓮','陳元晉','宋','宋诗','song-poetry','','[]','春山懶婦忻晝眠，門前女伴邀採蓮。',96,'全唐诗/poet.song.197000.json','["春山懶婦忻晝眠，門前女伴邀採蓮。", "含嚬行過寒烟浦，瞥上蘭舟悄無語。", "尋花不見花深深，見花不折空愁心。", "停橈看花紅更膩，却自低頭照秋水。", "娟娟沙際月一痕，催歸幾棹菱歌喧。", "葉底忽逢花並蒂，折歸月下乞郎看。"]'),
('5f7b0804-08b0-4cee-8ab0-b85c39f97ff5','楊南仲寓湖','陳元晉','宋','宋诗','song-poetry','','[]','紛紛市道交，翻覆雲雨手。',124,'全唐诗/poet.song.197000.json','["紛紛市道交，翻覆雲雨手。", "不如清風與明月，情分却於人耐久。", "夫君不受塵土污，湖上結茅誰與處。", "坐中只著風月我，有客敲門卿且去。", "凉生几席影沉杯，困眠醉舞相追陪。", "此時一笑真莫逆，中邊洞徹無纖埃。", "須知箇裏非久計，時來携手青雲裏。", "蓬萊山頂廣寒宮，放出清光滿天地。"]'),
('1ed9fefb-2f3c-4195-b904-63bcda7e4a57','上姚贛州鏞壽','陳元晉','宋','宋诗','song-poetry','','[]','東南之鎮曰會稽，扶輿清淑拱帝畿。',384,'全唐诗/poet.song.197000.json','["東南之鎮曰會稽，扶輿清淑拱帝畿。", "千巖萬壑氣盤礴，更有壽檜天與齊。", "托根后土閲千古，黛色蒼皮天一柱。", "鍾爲人傑堪棟國，恰似嵩高降申甫。", "君侯胸中百萬兵，年未四十俄專城。", "精神滿腹秋水瑩，談笑兩頰春風生。", "崎嶇贛右三百里，蛟鰐垂涎波浪起。", "遡流張膽作風帆，信如王尊乃勇耳。", "脫畧邊幅柔凶頑，解除苛嬈綏創殘。", "喚回和氣豁氛祲，事有至難談笑間。", "人口如碑沸傳誦，帝曰吾徒得君重。", "天風吹下紫泥封，趣入班行作儀鳳。", "大夫何以假守爲，真除屬厭民所期。", "虎頭岌嶪要彈壓，凝香森戟聊娛嬉。", "璇杓插子日南至，黄鍾飛灰雷出地。", "崆峒春早梅已香，釀入黄堂壽觴裏。", "醉來含笑看吳鈎，龍光夜半干斗牛。", "關河北望令人老，忠臣心與天爲謀。", "潢池正爾兵不弄，又說邊塵時澒洞。", "籌邊筦鑰寧無人，知待人豪爲國用。", "貂蟬冠高劍拄頤，丹青正與綠鬢宜。", "碧油幢下白羽扇，貔虎百萬惟指麾。", "雍容傳檄定三輔，頸縛單于歸釁鼓。", "手扶鑾駕還東都，宮殿千門總如故。"]'),
('445d9cbe-0e19-426e-8483-e0eaa5342e3a','上劉計使','陳元晉','宋','宋诗','song-poetry','','[]','水心吾師今昌黎，如椽巨筆光虹蜺。',192,'全唐诗/poet.song.197000.json','["水心吾師今昌黎，如椽巨筆光虹蜺。", "先公潜德粲碑版，却恨不識嵇中散。", "九苞五彩丹穴雛，不巢阿閣翔海隅。", "南來隻影方自笑，天假之逢挹光耀。", "一寒頓坐春風溫，賤子亦許扳龍門。", "子期九原不可叫，箏琶紛紛不同調。", "明公派自南軒來，祇今砥柱狂瀾回。", "一麾兩節嶺南北，盡是周程舊敭歷。", "書生彊附善類心，莫道冶躍非祥金。", "偶然短簿令公喜，上下雲龍固其志。", "山谷昔見蘇長公，自比小草依長松。", "牽聯名字香聞素，未必今人不如古。"]'),
('821c51eb-6640-420a-ad72-6b2f54ba9928','和胡文昌嘉禾篇','陳元晉','宋','宋诗','song-poetry','','[]','鄮山東翼帝王州，使君來自白鷺洲。',304,'全唐诗/poet.song.197000.json','["鄮山東翼帝王州，使君來自白鷺洲。", "下車三月課最優，賦辦不擾訟不留。", "哦詩卧閣政令修，和聲上暢天畀休。", "六丁下執旱魃囚，蠻琛航遠歸懷柔。", "向來瘡痏稍稍瘳，雨應六月如膏流。", "有禾雙穗來西疇，觀者喜氣同春浮。", "老父再拜千騎頭，此帝所賚非人求。", "三邊未靖哀虔劉，向來根本慮甚周。", "安得賣劍都買牛，豐年一飽百不憂。", "轉頭西風催歛揫，鼠雀亦覺歡啾啾。", "更令北望烟燧收，鐵衣更戍休葵丘。", "富民有詔封千秋，我生誰嘆命不猶。", "黄鷄白酒相獻酬，老翁市井兒嬉遊。", "擎香仰祝十二旒，垂拱萬年百祿遒。", "偉哉姬旦忠國謀，艱難民事陳嘉猷。", "仙人飛空白玉輈，霓旌來下風颼颼。", "手持五穟遺君侯，瑞圖合命椽筆修。", "晉之東序方天球，連理木頌那得儔。", "午窗香篆銷金虬，和公詩罷茶七甌。"]'),
('6ba7573c-d5cf-42aa-9fa0-eaeb8deac0fa','代餞轉運判官趙帑轄  其一','陳元晉','宋','宋诗','song-poetry','','[]','今代漢宗英，如公不數人。',48,'全唐诗/poet.song.197000.json','["今代漢宗英，如公不數人。", "清標高嶽柱，和氣藹湘春。", "宣室思才子，甘泉欠侍臣。", "平生劉子政，晚節更精神。"]'),
('1bd66f1d-46ad-4a52-9e4d-567697866e0a','代餞轉運判官趙帑轄  其二','陳元晉','宋','宋诗','song-poetry','','[]','憔悴湘濱客，懷哉有此逢。',48,'全唐诗/poet.song.197000.json','["憔悴湘濱客，懷哉有此逢。", "二星欣照映，三月愜遊從。", "公事如羹沸，歸心似酒醲。", "從今殊出處，別語且從容。"]'),
('2102c4bb-1547-4424-95ba-57bd4479a0d8','和蔡鐵窗韻','陳元晉','宋','宋诗','song-poetry','','[]','鐵窗詩價遠，應是到鷄林。',48,'全唐诗/poet.song.197000.json','["鐵窗詩價遠，應是到鷄林。", "修月有妙手，伴雲無出心。", "調高追郢曲，意古和虞琴。", "觸境勿多語，希聲是大音。"]'),
('59dfacee-e763-4dcf-a02f-a0cbc204464d','峽山','陳元晉','宋','宋诗','song-poetry','','[]','帆落榕根暮，禪扉半尚開。',48,'全唐诗/poet.song.197000.json','["帆落榕根暮，禪扉半尚開。", "逢僧如舊識，問我幾時來。", "潭靜鷗眠穩，雲深猿叫哀。", "篝燈看碑石，今古半蒼苔。"]'),
('93e1639e-1d0e-4534-b686-dd4bca9bbf0f','嚴陵市','陳元晉','宋','宋诗','song-poetry','','[]','暝色低平野，霜風放霽天。',48,'全唐诗/poet.song.197000.json','["暝色低平野，霜風放霽天。", "買杯逢竹所，索句立梅前。", "山曲雲歸寺，溪寒水带烟。", "茅簷聽殘雪，愁絕擁衾眠。"]'),
('f4e5129b-2785-4067-be40-f2e565551cff','帥節留先生兩年粵服氓獠安之一日疏十宜歸欲袖手板還丞相言者猶不之置上命以釐廷之祿解印東歸門生臨川陳元晉援後山送坡仙故事至惠之海豐而別作詩四章云  其一','陳元晉','宋','宋诗','song-poetry','','[]','手疏宜歸十，心知昨夢非。',48,'全唐诗/poet.song.197000.json','["手疏宜歸十，心知昨夢非。", "鴻冥空費弋，鷗舞早知機。", "風急推潮落，雲閑剩雨歸。", "攀轅多少淚，海岸濕斜暉。"]'),
('ce5eec28-141d-4220-b094-6a9b3d5ac05a','帥節留先生兩年粵服氓獠安之一日疏十宜歸欲袖手板還丞相言者猶不之置上命以釐廷之祿解印東歸門生臨川陳元晉援後山送坡仙故事至惠之海豐而別作詩四章云  其二','陳元晉','宋','宋诗','song-poetry','','[]','描畫終無說，歸來豈不榮。',48,'全唐诗/poet.song.197000.json','["描畫終無說，歸來豈不榮。", "事難工拙較，我自去留輕。", "過眼風波惡，懸空日月明。", "人生只恁是，孤鶴九臯聲。"]'),
('6a0e7dfa-0791-4003-8313-af13fd587e4b','帥節留先生兩年粵服氓獠安之一日疏十宜歸欲袖手板還丞相言者猶不之置上命以釐廷之祿解印東歸門生臨川陳元晉援後山送坡仙故事至惠之海豐而別作詩四章云  其三','陳元晉','宋','宋诗','song-poetry','','[]','拙無諧俗韻，老眼獨相奇。',48,'全唐诗/poet.song.197000.json','["拙無諧俗韻，老眼獨相奇。", "寒谷遲春到，東風盡日吹。", "身將三尺律，心不一毫欺。", "公與梅花外，南來誰我知。"]'),
('623860f0-443f-4382-a3be-7ebb046a5364','帥節留先生兩年粵服氓獠安之一日疏十宜歸欲袖手板還丞相言者猶不之置上命以釐廷之祿解印東歸門生臨川陳元晉援後山送坡仙故事至惠之海豐而別作詩四章云  其四','陳元晉','宋','宋诗','song-poetry','','[]','木種十年計，苓培千歲根。',48,'全唐诗/poet.song.197000.json','["木種十年計，苓培千歲根。", "三生疑宿植，九殞志酬恩。", "遠送竟須別，百懷難具論。", "任安窮自分，義不辱公門。"]'),
('259063db-e367-48c6-a835-2a86f473d02a','餞余倅鼎叟官滿東歸','陳元晉','宋','宋诗','song-poetry','','[]','丙年同佐牧，相與最情親。',48,'全唐诗/poet.song.197000.json','["丙年同佐牧，相與最情親。", "乘月登樓夜，隨風步屧春。", "報來陞轉速，歸去召除新。", "一劍舊肝膽，持將問大鈞。"]'),
('ab665832-6e8c-4237-9c44-3e597767f69e','晚步','陳元晉','宋','宋诗','song-poetry','','[]','鼓鐘燈火後，袖手過欄干。',48,'全唐诗/poet.song.197000.json','["鼓鐘燈火後，袖手過欄干。", "素月空中寂，踈星竹裏看。", "溪毛行步濕，潭影古心寒。", "此意我方適，亭亭夜未殘。"]'),
('2d760423-05e5-4c4b-8209-1a13cb2ab581','過桐廬縣','陳元晉','宋','宋诗','song-poetry','','[]','嚴陵耕釣處，清淑故依然。',48,'全唐诗/poet.song.197000.json','["嚴陵耕釣處，清淑故依然。", "樓館危臨水，人烟近倚天。", "客行桑下路，晨墾嶺頭田。", "遲我風帆便，津頭更覓錢。"]'),
('06076720-9bab-4ac6-96df-daa31d2e1f1b','雪作','陳元晉','宋','宋诗','song-poetry','','[]','簾捲虛堂曉，兒童笑語譁。',48,'全唐诗/poet.song.197000.json','["簾捲虛堂曉，兒童笑語譁。", "恍疑開月窟，渾是散天花。", "竹裏聞清響，江邊看玉槎。", "訪梅乘好興，著屐過鄰家。"]'),
('4a83c22d-8bc6-476d-98ef-fbf214c24164','送鄧帥參文舉得南雄守歸','陳元晉','宋','宋诗','song-poetry','','[]','風流耆舊傳，悃愊靜無華。',48,'全唐诗/poet.song.197000.json','["風流耆舊傳，悃愊靜無華。", "來重青油幙，歸乘皂蓋車。", "離筵傾柏葉，客路看梅花。", "聞有南來信，門前迓騎譁。"]'),
('7ef60282-9cd1-4271-a5a9-2f51c4199818','雨後  其一','陳元晉','宋','宋诗','song-poetry','','[]','忽雨乾坤變，將秋氣候寬。',48,'全唐诗/poet.song.197000.json','["忽雨乾坤變，將秋氣候寬。", "林亭欣濯濯，柳岸渺漫漫。", "一飯飽無那，連村枕可安。", "舉觴屬明月，急雨放雲端。"]'),
('c30b4641-7eca-4396-ab60-3abe3fae7b4c','雨後  其二','陳元晉','宋','宋诗','song-poetry','','[]','一雨郊原足，神功不作難。',48,'全唐诗/poet.song.197000.json','["一雨郊原足，神功不作難。", "向知天道邇，今幸物情安。", "童稚沾衣走，人家傍戶看。", "翻令五六月，春意轉江干。"]'),
('13e8d16f-432a-44cf-a4b6-75a729239ed4','喜雨','陳元晉','宋','宋诗','song-poetry','','[]','六月乃有此，豐年定可書。',48,'全唐诗/poet.song.197000.json','["六月乃有此，豐年定可書。", "真成天雨粟，到處水成渠。", "䆉稏香連畝，汙邪載滿車。", "所忻同一飽，未用嘆無魚。"]'),
('051764ef-7cb5-425d-a3e5-2a97498af6d2','輓饒武博二首  其一','陳元晉','宋','宋诗','song-poetry','','[]','方客戎幢右，俄旌墓道傍。',48,'全唐诗/poet.song.197000.json','["方客戎幢右，俄旌墓道傍。", "堂虛空老桂，星冷落魁芒。", "留世程文樣，傳家奏稿香。", "鄉評偕李謝，雖死有幽光。"]'),
('9b9bfca6-0e3b-40ab-ac8f-ecee85e4f6f0','輓饒武博二首  其二','陳元晉','宋','宋诗','song-poetry','','[]','內集儕甥舅，同登齒弟兄。',48,'全唐诗/poet.song.197000.json','["內集儕甥舅，同登齒弟兄。", "忘年情好密，開口肺肝傾。", "恍爾同醒醉，傷哉隔死生。", "朔風吹老淚，哀些不成聲。"]'),
('84bc5648-72db-43d2-8aea-41ffda32c218','代挽寺丞吳公','陳元晉','宋','宋诗','song-poetry','','[]','國事須才急，如公亦古人。',48,'全唐诗/poet.song.197000.json','["國事須才急，如公亦古人。", "江淮老麾節，俎豆哭軍民。", "圖憶籌邊舊，官傳結綬新。", "朔風吹老淚，泉路濕寒燐。"]'),
('3be7b79e-e3be-4454-9139-120b017533c4','贈歐陽承務','陳元晉','宋','宋诗','song-poetry','','["\u8861\u5c71"]','談天多巧中，名在士夫間。',48,'全唐诗/poet.song.197000.json','["談天多巧中，名在士夫間。", "行遍西江路，來遊南嶽山。", "病侵心緒懶，窮慣面皮頑。", "莫說功名事，祿書從捲還。"]'),
('be56530c-3dfe-405f-bdd8-41a9df54c2d3','挽德慶涂守二首  其一','陳元晉','宋','宋诗','song-poetry','','[]','九京嗟已矣，今吏孰如君。',48,'全唐诗/poet.song.197000.json','["九京嗟已矣，今吏孰如君。", "律己嚴三尺，活人寬一分。", "清名寒蜀雪，嘉誦藹南雲。", "杉柏風凄切，黄陂原上墳。"]'),
('bb230aea-09f6-40e8-bd59-e3b42f4acc6c','挽德慶涂守二首  其二','陳元晉','宋','宋诗','song-poetry','','[]','鄉枌生也晚，嶺外偶同寅。',48,'全唐诗/poet.song.197000.json','["鄉枌生也晚，嶺外偶同寅。", "齒我子姪行，情如兄弟親。", "不嫌同幕辯，要作一州春。", "滿澗多題字，回頭更愴神。"]'),
('e86f37a5-96de-418e-a385-f2ef059fd630','題羅浮山中閣','陳元晉','宋','宋诗','song-poetry','','[]','大海漫天駕葉舟，來登中閣問仙游。',64,'全唐诗/poet.song.197000.json','["大海漫天駕葉舟，來登中閣問仙游。", "泉聲急瀉三更雨，雲氣深藏六月秋。", "霧濕中天龍出洞，日騰滄海蜃收樓。", "禪床靜數愔愔息，身在清都最上頭。"]'),
('01b70653-ed07-4d00-9a2b-d34716946769','七月初十夜對月呈留粹中','陳元晉','宋','宋诗','song-poetry','','[]','人間寒信到階蛩，天外清商入井桐。',64,'全唐诗/poet.song.197000.json','["人間寒信到階蛩，天外清商入井桐。", "孤館無人同夜月，長年作客又秋風。", "想君局促重簾底，似我棲遲逆旅中。", "何事人生苦拘束，得閑來此一樽同。"]'),
('e8b5009f-aaa2-44e2-a7d5-573e71bd420e','越王臺','陳元晉','宋','宋诗','song-poetry','','[]','南州勝觀越王臺，天與詩人醉眼開。',64,'全唐诗/poet.song.197000.json','["南州勝觀越王臺，天與詩人醉眼開。", "雲漠漠邊蕃路遠，水茫茫處海潮回。", "人家一半藏烟樹，往事千重問石苔。", "料得清秋尤好在，一樽重約月明來。"]'),
('1594abe9-a50a-4a4a-835a-05efe43e8b30','慶涂權尉三首  其一','陳元晉','宋','宋诗','song-poetry','','[]','袖中光焰吐青蛇，獻策軍門鬢未華。',64,'全唐诗/poet.song.197000.json','["袖中光焰吐青蛇，獻策軍門鬢未華。", "豈是輕身探虎穴，要將赤手拔鯨牙。", "向來筆研渾無力，此去功名正未涯。", "小試柳營新號令，六花排陣寂無譁。"]'),
('30f2b1d1-8035-49df-b4a1-ddf72262ab24','慶涂權尉三首  其二','陳元晉','宋','宋诗','song-poetry','','[]','歲月遒於赴壑蛇，功名政要及年華。',64,'全唐诗/poet.song.197000.json','["歲月遒於赴壑蛇，功名政要及年華。", "平淮猶自須裴度，釣渭那能老子牙。", "舞袖巧懸嫌地褊，酒杯相屬記天涯。", "期君酣戰秋風裏，鼓率銜枚陣不譁。"]'),
('8df0e435-f3a7-4f44-b303-91616ac89a95','慶涂權尉三首  其三','陳元晉','宋','宋诗','song-poetry','','[]','朝憂猛虎夕長蛇，弔戰場文憶李華。',64,'全唐诗/poet.song.197000.json','["朝憂猛虎夕長蛇，弔戰場文憶李華。", "自笑病來寬带眼，那能老去植幢牙。", "如君政合登東閣，顧我惟堪老北涯。", "賓主秋風南浦路，旗鈴好聽捷音譁。"]'),
('b9cb5180-415b-4dd1-9bdd-5bece67ae565','王推官載酒來會於逍遥堂','陳元晉','宋','宋诗','song-poetry','','[]','路入烟蘿杳靄中，良宵一笑美人同。',64,'全唐诗/poet.song.197000.json','["路入烟蘿杳靄中，良宵一笑美人同。", "壺觴盡攬平湖月，絃管時飄別岸風。", "三宿未忘緣境勝，一燈相對坐詩窮。", "姓名要共青山久，看取當年玉局翁。"]'),
('cc99c750-3cf6-4277-afb3-267b801c6166','喜雨上項帥','陳元晉','宋','宋诗','song-poetry','','[]','精祈三日竟成霖，一瓣心香格帝歆。',64,'全唐诗/poet.song.197000.json','["精祈三日竟成霖，一瓣心香格帝歆。", "苖若遂枯無此水，粟將暴貴湧於金。", "時方多壘農爲急，公在三湘澤已深。", "自媿侏儒叨一飽，願推德意答天心。"]'),
('6eeb3b2c-a717-4836-b08f-398a664ee784','李徽猷病後許賞蓮而未酬小詩發一笑','陳元晉','宋','宋诗','song-poetry','','[]','僧夏分來一榻凉，愛蓮更擅水雲鄉。',64,'全唐诗/poet.song.197000.json','["僧夏分來一榻凉，愛蓮更擅水雲鄉。", "露融初日敷朝采，雨捲凉飈送晚香。", "天女羣參青葉髻，水仙爭護紫荷囊。", "一絲不挂根塵凈，莫怪先生久覆觴。"]'),
('b071995c-43ee-4060-8b81-38d57a584db2','和留少微豐湖懷坡仙韻','陳元晉','宋','宋诗','song-poetry','','[]','弔古誰翻楚些歌，百年陳跡愴懷多。',64,'全唐诗/poet.song.197000.json','["弔古誰翻楚些歌，百年陳跡愴懷多。", "春風草綠松根寺，夜雨燈寒窣堵波。", "老鶴舊曾陪杖履，閑鷗今尚護烟莎。", "憑君莫憶當時事，惆悵人間春夢婆。"]'),
('697dc26e-12f6-44a4-a48f-bb4437dd0e94','倉檄出惠陽督諸邑捕蝗','陳元晉','宋','宋诗','song-poetry','','[]','古來傳說驅蝗法，近歲驚聞田有蝗。',64,'全唐诗/poet.song.197000.json','["古來傳說驅蝗法，近歲驚聞田有蝗。", "無耐吏饕甘地惡，何辜民病重天殃。", "秋風要滿扶犁望，夏日寧辭走檄忙。", "高廩更令無雀鼠，使星尸祝幾爐香。"]'),
('54966ead-2930-4a41-8189-8d20d664cff8','題新昌蔡尉比春園四時載酒亭','陳元晉','宋','宋诗','song-poetry','','[]','蔡家亭子錦江涯，長約春風作歲華。',64,'全唐诗/poet.song.197000.json','["蔡家亭子錦江涯，長約春風作歲華。", "拚却百年渾是醉，莫教一日不開花。", "稱觴隨獲慈顔悅，問字時容客語譁。", "我若有園如箇樣，肯將雙鬢抗風沙。"]'),
('64f253b9-dcf8-4484-9425-54b0ac2ddfb9','紀遊再用前韻','陳元晉','宋','宋诗','song-poetry','','[]','松篁一徑夾長蛇，雲錦重重肅九華。',64,'全唐诗/poet.song.197000.json','["松篁一徑夾長蛇，雲錦重重肅九華。", "長夏飛泉傾石眼，半空懸磴啄簷牙。", "要知酒興并詩料，不在山巔即水涯。", "記取松間休喝道，山靈應怕俗聲譁。"]'),
('a7bac4b8-52f9-48c6-97d4-f1ae572949f2','過南安道中  其一','陳元晉','宋','宋诗','song-poetry','','[]','暑塗明發正愁予，佇立風簷氣不蘇。',64,'全唐诗/poet.song.197000.json','["暑塗明發正愁予，佇立風簷氣不蘇。", "擬戴星行方叱馭，誰驅雨至忽隨車。", "豈憐行道暍欲死，直恐良苗涸且枯。", "早覺南來鹽米賤，趁墟歸去總歡呼。"]'),
('bdbd0516-fc70-4941-92af-5498fd0c1af1','過南安道中  其二','陳元晉','宋','宋诗','song-poetry','','[]','火乘金伏勢方驕，天地圍爐萬物焦。',64,'全唐诗/poet.song.197000.json','["火乘金伏勢方驕，天地圍爐萬物焦。", "那信炎蒸天六月，却聞優渥雨三朝。", "頓添秋思生庭樹，頗覺春痕漲市橋。", "分我清風陪獨夜，又愁明月渺難招。"]'),
('bc32cc53-2866-4cac-ab58-193f832c1ce2','得主管仙都之命','陳元晉','宋','宋诗','song-poetry','','[]','頭銜清甚管仙都，吏責全無出有車。',64,'全唐诗/poet.song.197000.json','["頭銜清甚管仙都，吏責全無出有車。", "老去心情酬應懶，閑來親友往還踈。", "每嗤人作囚山賦，莫勸儂通光範書。", "只把窮愁博强健，世間得失本乘除。"]'),
('e049fb11-32c9-4b9e-aa86-ef68596bd390','擊毬口號戲陳統制','陳元晉','宋','宋诗','song-poetry','','[]','築場千步柳營東，樽俎精神坐折衝。',64,'全唐诗/poet.song.197000.json','["築場千步柳營東，樽俎精神坐折衝。", "星彈流空驚過鳥，霜蹄追電捷游龍。", "身輕鞍馬人如畫，膽落猩鼯穴已空。", "歸去翠眉環玉帳，釵兒多乞錦纏紅。"]'),
('97293336-7af6-4292-9d6f-08d8d06fdedd','題顔秀才夔詩編','陳元晉','宋','宋诗','song-poetry','','[]','延年一印付聞孫，文采風流今尚存。',64,'全唐诗/poet.song.197000.json','["延年一印付聞孫，文采風流今尚存。", "生長見聞誠叟里，交游唱和澹菴門。", "苦思那有酸寒氣，妙斲渾無斧鑿痕。", "問子何爲暗投璧，令吾端欲竪降旛。"]'),
('43929fd0-8798-4f60-83b6-a6b1c52f54d6','和項帥交帥印招十二邑令韻','陳元晉','宋','宋诗','song-poetry','','[]','同時製錦七宗英，更有珠聯五舜臣。',64,'全唐诗/poet.song.197000.json','["同時製錦七宗英，更有珠聯五舜臣。", "矚望諸賢皆邑最，和衷一語見情真。", "方時艱棘難爲政，隨事斟量可及民。", "緩急之中權闔闢，政須不失本心仁。"]'),
('42ddfab4-4fcd-40ab-afcf-a594f2b31397','信國魯夫人挽詩二首  其一','陳元晉','宋','宋诗','song-poetry','','[]','詎有陳平解久貧，共看眉案久如賓。',64,'全唐诗/poet.song.197000.json','["詎有陳平解久貧，共看眉案久如賓。", "從夫榮荷西清橐，承祖恪共南澗蘋。", "玉樹庭前雙使節，金花天上九恩綸。", "繡衣綵服今非昔，忍見堂萱雪後春。"]'),
('9e3943a6-6828-403d-a141-5e2359c247ee','信國魯夫人挽詩二首  其二','陳元晉','宋','宋诗','song-poetry','','[]','曾是王珪坐上人，孰知孟母德無鄰。',64,'全唐诗/poet.song.197000.json','["曾是王珪坐上人，孰知孟母德無鄰。", "長懷就養板輿日，一笑能回花縣春。", "詩感棘風知痛苦，歌翻薤露亦酸辛。", "送車千兩瑶塘路，奔走無從愧負薪。"]'),
('a95158af-0cad-4960-ba5d-05fad886a58b','判府大帥督參寶謨戶部先生持漕節來長沙繼陞帥守追惟平菴先生分教是邦越四十有九年而多士尊仰說服如一日廼市地立祠以慰士心祠成門下士陳某拜手稽首而詩之曰','陳元晉','宋','宋诗','song-poetry','','[]','佩璐騎麟返帝旁，屐痕所在尚芬芳。',64,'全唐诗/poet.song.197000.json','["佩璐騎麟返帝旁，屐痕所在尚芬芳。", "泉行地脈家家井，月到天心處處光。", "模範百年垂藻泮，蒸嘗千古奉桐鄉。", "教忠况有無窮澤，衮衮湘流一派長。"]'),
('fa3bdf4c-f625-4624-9bc3-3c2cc02f2e86','羅浮山多有道人倚嶔巖爲室僅可容膝引泉貫其間以供烹濯鑿山種豆人不滿二畝可了歲計油然自得也爲予言夜深月明時有虎觸戶山前後多黄鸝終日睍睆可愛與留粹中各賦詩','陳元晉','宋','宋诗','song-poetry','','[]','山家境界無畦畛，住處隨人意所便。',64,'全唐诗/poet.song.197000.json','["山家境界無畦畛，住處隨人意所便。", "澗汲巖棲忘世累，石耕畧種盡天年。", "時驚虎觸柴扉月，長聽鶑啼綠樹烟。", "不信却無人種杏，知從何處覓神仙。"]'),
('df12ed7a-09a9-419f-8662-e3addeebb1df','甲申乙酉丙戌四過釣臺有感','陳元晉','宋','宋诗','song-poetry','','[]','三年四過子陵臺，老我風霜兩鬢催。',64,'全唐诗/poet.song.197000.json','["三年四過子陵臺，老我風霜兩鬢催。", "望見雲山心已愧，夢登釣石眼爲開。", "乾坤清氣長如許，鐘鼎元勳安在哉。", "近百年來幾帆過，登臨多是覓官來。"]'),
('4128ee36-98ca-43b7-a2b1-c665bdb95fd2','上留提刑壽  其一','陳元晉','宋','宋诗','song-poetry','','[]','中秋清絕冠秋天，間氣生賢得月先。',64,'全唐诗/poet.song.197000.json','["中秋清絕冠秋天，間氣生賢得月先。", "一念來從金粟洞，三生曾伴赤松仙。", "繡衣踏遍江湖上，線履催歸雨露邊。", "且別崆峒朝帝去，它年來拍廣成肩。"]'),
('db4f24d0-0055-4fbf-8089-71dbfc97d2a8','上留提刑壽  其二','陳元晉','宋','宋诗','song-poetry','','[]','展開南極老人圖，是處青烟鵲尾爐。',64,'全唐诗/poet.song.197000.json','["展開南極老人圖，是處青烟鵲尾爐。", "秋露九原淪厚澤，春風一道泳康衢。", "萬金藥散疲羸活，三尺刑清怨嘆蘇。", "只此陰功誰比大，中書有考可酬無。"]'),
('8c735449-ad5f-4723-98b1-bb8f16a555c1','和鄧帥參追和東坡雪韻  其一','陳元晉','宋','宋诗','song-poetry','','[]','學舞腰支束素纖，回旋似怯曉風嚴。',64,'全唐诗/poet.song.197000.json','["學舞腰支束素纖，回旋似怯曉風嚴。", "飄窗淅瀝暗投璧，洒研紛披凍着鹽。", "應有飲羔圍暖帳，誰憐饑雀啅寒簷。", "憑欄獨聳詩肩瘦，對立西山玉幾尖。"]'),
('66de412e-e615-4043-ae10-6fce820a2014','和鄧帥參追和東坡雪韻  其二','陳元晉','宋','宋诗','song-poetry','','[]','破寒有喜報晨鴉，忽送詩筒雪賦車。',64,'全唐诗/poet.song.197000.json','["破寒有喜報晨鴉，忽送詩筒雪賦車。", "占歲便同天雨粟，寬憂解遣筆生花。", "瓊枝夸麗羞陳苑，玉樹爭妍比謝家。", "臘白纔呈春已動，扶桑霽影曉相叉。"]'),
('663f2e8b-bd50-4dd0-b943-889d652254b7','和陳守喜雨詩  其一','陳元晉','宋','宋诗','song-poetry','','[]','垤鸛無聲口舌乾，誰驅雷雨遍千山。',64,'全唐诗/poet.song.197000.json','["垤鸛無聲口舌乾，誰驅雷雨遍千山。", "頓蘇赤地千里旱，特出黄堂一念間。", "澤物功深無德色，豐年願遂有歡顔。", "爲霖祇恐思賢佐，千騎東隨鳳詔還。"]'),
('b5898906-90ea-458f-b09e-8b3162e96c90','和陳守喜雨詩  其二','陳元晉','宋','宋诗','song-poetry','','[]','誰念東南膏血乾，文移督迫積如山。',64,'全唐诗/poet.song.197000.json','["誰念東南膏血乾，文移督迫積如山。", "平時素號鑊湯底，不雨豈逃溝壑間。", "民病向來猶在耳，天威此去不違顔。", "從容宣室如前席，乞與枯荄生意還。"]'),
('21a1f555-b39d-4c33-939f-0c3b87223c8d','再和涂宣義喜雨','陳元晉','宋','宋诗','song-poetry','','[]','郡邑同寅禱旱乾，風霆來會雨千山。',64,'全唐诗/poet.song.197000.json','["郡邑同寅禱旱乾，風霆來會雨千山。", "真成雨粟從天下，只在爲雲翻手間。", "神不素餐無愧色，農期一飽足歡顔。", "豐年酒熟雞豚社，二老從今請往還。"]'),
('ca4730dd-f35e-47c5-8b43-5598d013bbc7','挽劉金部','陳元晉','宋','宋诗','song-poetry','','[]','忠清家法見聞中，蜀産凋零又到公。',64,'全唐诗/poet.song.197000.json','["忠清家法見聞中，蜀産凋零又到公。", "抗僞一門誠節誼，明倫數語最精忠。", "郎潜勇退聲名重，使傳賢勞惠利豐。", "時事方艱人物眇，可堪收淚灑悲風。"]'),
('94c85c8c-d974-41cf-9aef-2446239e7f67','贈劉賢良','陳元晉','宋','宋诗','song-poetry','','[]','十二書言天下事，氣如蕡直語加遒。',64,'全唐诗/poet.song.197000.json','["十二書言天下事，氣如蕡直語加遒。", "誰當心耻四郊壘，子獨眉攢萬國愁。", "刺手拔鯨何倜儻，劇談捫虱自風流。", "悠然且作新豐醉，定有人能說馬周。"]'),
('38628bfa-1c6d-4839-8001-030273436596','安撫徽猷郎中被召欲東賦詩見志乃以得歸閑退爲喜門人小子知先生之心也輒和嚴韻用暢高風  其一','陳元晉','宋','宋诗','song-poetry','','[]','莫管聲名草木知，人生待足是何時。',64,'全唐诗/poet.song.197000.json','["莫管聲名草木知，人生待足是何時。", "興纔盡處須回棹，塗到迷時漫泣岐。", "老我昨非今似是，笑渠小黠大還癡。", "山林晚覺中多味，不怪商顔只茹芝。"]'),
('d569bc5b-8cbe-4fb0-95e2-376bfb70b1ae','安撫徽猷郎中被召欲東賦詩見志乃以得歸閑退爲喜門人小子知先生之心也輒和嚴韻用暢高風  其二','陳元晉','宋','宋诗','song-poetry','','[]','聱叟揮車倦且歸，釣遊舊處足娛嬉。',64,'全唐诗/poet.song.197000.json','["聱叟揮車倦且歸，釣遊舊處足娛嬉。", "客懷自分三宜去，世事那無一可爲。", "晝日高眠甘茗乳，秋風清飲飽蓴絲。", "何當爲背奚奴錦，收拾潭州歸後詩。"]'),
('66075be8-85c4-420e-b0d3-4fe02adea1de','和柴大監留郎中遊鬰孤及喜雨之什  其一','陳元晉','宋','宋诗','song-poetry','','[]','冰壺清對玉衡秋，臺府同時盡勝流。',64,'全唐诗/poet.song.197000.json','["冰壺清對玉衡秋，臺府同時盡勝流。", "南國恩波如海闊，西江和氣接天浮。", "山川真借兩賢重，翰墨仍爲八境留。", "見說九重思魏笏，書帷更欲學君疇。"]'),
('c7edaec8-049d-445a-bc2f-1e115988610c','和柴大監留郎中遊鬰孤及喜雨之什  其二','陳元晉','宋','宋诗','song-poetry','','[]','農畝皇皇望有秋，肩赬背裂汗衣流。',64,'全唐诗/poet.song.197000.json','["農畝皇皇望有秋，肩赬背裂汗衣流。", "疲甿不得一飯飽，我輩應慚多食浮。", "烏尾督逋無迫遽，鼠牙有訟怕淹留。", "兩君一念回天速，天雨看看粟滿疇。"]'),
('690bfa7f-c842-4f8c-9a80-a5217b9cc217','韶石使君年丈扁舟過我於松桂林敬哦小詩留爲一日款就寄石洲主人以發千里外一笑也  其一','陳元晉','宋','宋诗','song-poetry','','[]','十五年前會五羊，都門再別九年强。',64,'全唐诗/poet.song.197000.json','["十五年前會五羊，都門再別九年强。", "君榮韶石州麾出，我窘文江縣債償。", "人世能消幾離別，征塗何用許奔忙。", "梅前菊後風光好，且爲儂留共一觴。"]'),
('5222937f-9c6e-4ad0-8ba7-df3d75ba1d7f','韶石使君年丈扁舟過我於松桂林敬哦小詩留爲一日款就寄石洲主人以發千里外一笑也  其二','陳元晉','宋','宋诗','song-poetry','','[]','黄雀長行萬里餘，煩渠就寄數行書。',64,'全唐诗/poet.song.197000.json','["黄雀長行萬里餘，煩渠就寄數行書。", "常懷李白詩無敵，莫怪韋郎跡也踈。", "玉節榮光何恨速，石洲風物正關渠。", "同年相逐雲龍處，應念吾儂乃一豬。"]'),
('7a3c993b-b1a7-45f0-be74-ee6bb34d3254','春日','陳元晉','宋','宋诗','song-poetry','','[]','金旛勝裏喚春歸，却後新正八日期。',32,'全唐诗/poet.song.197000.json','["金旛勝裏喚春歸，却後新正八日期。", "紅紫莫嫌春較晚，開遲應是落還遲。"]'),
('a5362397-d9c7-4d93-92d4-9dff90c64683','題曾審言所寓僧舍梅屋  其一','陳元晉','宋','宋诗','song-poetry','','[]','作屋延梅更鑿池，是花最與水相宜。',32,'全唐诗/poet.song.197000.json','["作屋延梅更鑿池，是花最與水相宜。", "橫斜清淺黄昏月，畫出孤山兩句詩。"]'),
('6a7a63c4-3670-4165-9379-391b2ab0f5fc','題曾審言所寓僧舍梅屋  其二','陳元晉','宋','宋诗','song-poetry','','[]','傾蓋知心兩玉人，竹君邂逅更情親。',32,'全唐诗/poet.song.197000.json','["傾蓋知心兩玉人，竹君邂逅更情親。", "能同此味花君子，來共團欒一笑春。"]'),
('8f90d2b0-4b21-4a43-ad4c-5a08c613f82f','獨夜  其一','陳元晉','宋','宋诗','song-poetry','','[]','月轉庭除夜未央，坐看梧影上東牆。',32,'全唐诗/poet.song.197000.json','["月轉庭除夜未央，坐看梧影上東牆。", "金風玉露方清絕，只欠探枝桂子香。"]'),
('161aa0b4-e5c1-4090-bf32-43ea6be91a65','獨夜  其二','陳元晉','宋','宋诗','song-poetry','','[]','雨作寒聲落枕邊，攪人愁緒不成眠。',32,'全唐诗/poet.song.197000.json','["雨作寒聲落枕邊，攪人愁緒不成眠。", "非關獨夜難排遣，爲怕秋風在眼前。"]'),
('044fb307-65fe-491d-a239-98361e7c5082','題西齋','陳元晉','宋','宋诗','song-poetry','','[]','唔咿一室特蘧廬，要讀人間未見書。',32,'全唐诗/poet.song.197000.json','["唔咿一室特蘧廬，要讀人間未見書。", "快著先鞭問前路，西崑玉府富珍儲。"]'),
('43ebfe37-546b-43a8-923f-04254f020bc8','梅仙峰','陳元晉','宋','宋诗','song-poetry','','[]','文陛無階寄履聲，驂鸞有路學仙靈。',32,'全唐诗/poet.song.197000.json','["文陛無階寄履聲，驂鸞有路學仙靈。", "長安宮殿今何處，祇有梅峯萬古青。"]'),
('6756b8b5-ebc2-4ace-85ba-f9a01511a1b8','謝童帥幹送滴酥','陳元晉','宋','宋诗','song-poetry','','[]','滴成詩句巧相粘，料得堂深凍未忺。',32,'全唐诗/poet.song.197000.json','["滴成詩句巧相粘，料得堂深凍未忺。", "剪水染雲天上手，何因得見玉纖纖。"]'),
('4de3f8d3-6966-4081-a209-004dcceba453','入庾嶺','陳元晉','宋','宋诗','song-poetry','','[]','梅花迎路客平安，此是江南盡處山。',32,'全唐诗/poet.song.197000.json','["梅花迎路客平安，此是江南盡處山。", "霜月正高花下飲，酒闌長嘯過梅關。"]'),
