('caa12a5d-92f6-431f-b3e7-36546dd3e4eb','詩一首','趙葵姬','宋','宋诗','song-poetry','','[]','柝聲默報早朝回，滿院春風繡戶開。',32,'全唐诗/poet.song.197000.json','["柝聲默報早朝回，滿院春風繡戶開。", "怪得無人理絲竹，綠陰深處摘青梅。"]'),
('d9092110-a014-4590-9731-68219a51ba58','送趙南仲出視江淮','郭庭芝','宋','宋诗','song-poetry','','[]','劍戟翩翩鐵騎攢，前軍飛渡潤州灣。',64,'全唐诗/poet.song.197000.json','["劍戟翩翩鐵騎攢，前軍飛渡潤州灣。", "烽連淮陸胡塵遠，月照金山漢壘寒。", "虎旅亦知平□易，龍庭不數靖邊難。", "來威顯允歌方叔，願附詩人唱凱還。"]'),
('e62925b7-f447-4477-9e2b-92bd33ecbad0','佛牙寺看桂因贈許秀才','郭庭芝','宋','宋诗','song-poetry','','[]','何來仙女散天花，剩得餘香伴佛牙。',32,'全唐诗/poet.song.197000.json','["何來仙女散天花，剩得餘香伴佛牙。", "留取高枝青漢上，秋風吹送到君家。"]'),
('c802c0ff-45e1-44b8-9a5b-832aea3661fc','自然仙井  其一','郭庭芝','宋','宋诗','song-poetry','','[]','仙翁去不還，石井烟霧白。',24,'全唐诗/poet.song.197000.json','["仙翁去不還，石井烟霧白。", "誰能躡其蹤，勾漏良吾宅。"]'),
('a29fbd51-0e92-468b-aa9a-cce7d74912ac','自然仙井  其二','郭庭芝','宋','宋诗','song-poetry','','[]','井空寒不流，汲取不知夏。',24,'全唐诗/poet.song.197000.json','["井空寒不流，汲取不知夏。", "披襟醉瑶華，白榆歷歷下。"]'),
('424a306f-9455-4f56-ad26-c06044f200ee','訪景山','許伯詡','宋','宋诗','song-poetry','','[]','奉陪南極老，來慕北山名。',48,'全唐诗/poet.song.197000.json','["奉陪南極老，來慕北山名。", "鑿石濃書墨，流觴款敘情。", "問誰挹仙袂，笑我縛塵纓。", "知是龍門客，終難卧孔明。"]'),
('fc65cfef-168a-4a81-a5b0-2919ae844af8','和許伯翊訪景山','陳師服','宋','宋诗','song-poetry','','[]','仙溪七十里，半世始聞名。',48,'全唐诗/poet.song.197000.json','["仙溪七十里，半世始聞名。", "一日見山面，千年懷友情。", "古匏浮晋醁，清水照塵纓。", "霜月亭亭白，連床話到明。"]'),
('b8380ee0-499a-462f-88ca-c8ef31d43923','冷泉亭看放水','陸垕','宋','宋诗','song-poetry','','[]','泉聲飛出閘，委折綠陰間。',48,'全唐诗/poet.song.197000.json','["泉聲飛出閘，委折綠陰間。", "此地原無暑，多時不入山。", "草欹疑石墜，水定見魚還。", "難得同龜鶴，游吟半日閑。"]'),
('6e30bab3-32e7-4d73-b0c6-297e512d85a3','句','朱天錫','宋','宋诗','song-poetry','','[]','百里歡聲歌扇底，萬家和氣酒盃中。',16,'全唐诗/poet.song.197000.json','["百里歡聲歌扇底，萬家和氣酒盃中。"]'),
('d43b0c08-a041-41ee-9993-2445ed8f78b5','浯溪  其一','林訪','宋','宋诗','song-poetry','','[]','靈武儲皇識事端，解將權術濟艱難。',32,'全唐诗/poet.song.197000.json','["靈武儲皇識事端，解將權術濟艱難。", "當時若徇區區節，宗社何由獲再安。"]'),
('bcc7a859-01c2-4373-9498-efcad12f52f4','浯溪  其二','林訪','宋','宋诗','song-poetry','','[]','文士相輕自古然，堪嗟嘲詠費雕鎸。',32,'全唐诗/poet.song.197000.json','["文士相輕自古然，堪嗟嘲詠費雕鎸。", "元顔文筆非餘子，未可毛疵議昔賢。"]'),
('d8646d59-25fb-4d5e-aee4-03c82c00e39a','無題','方元吉','宋','宋诗','song-poetry','','[]','一穗香烟到日斜，靜聽蜂報二時衙。',32,'全唐诗/poet.song.197000.json','["一穗香烟到日斜，靜聽蜂報二時衙。", "老僧不解傷春意，多採梨花作供花。"]'),
('f57a2553-f62a-4419-bd9b-625c252ac67a','題姚司戶萬翠亭','崔起之','宋','宋诗','song-poetry','','[]','名山繞旌川，未易千百計。',228,'全唐诗/poet.song.197000.json','["名山繞旌川，未易千百計。", "棲真聳其西，二幕相扞蔽。", "柳山與龍山，連亙殆無際。", "大鼇從東出，石鼓鑿奇瑞。", "華容接雞形，蔓衍若難制。", "維南有梓山，盤屹萬里勢。", "有殿曰甘露，崒嵂插天地。", "玉壺枕其北，鳬山復相比。", "磣嶺介鳳凰，大洞闡天祕。", "無奈分布廣，一蹴不可至。", "姚君天韻奇，氣概高一世。", "胸中飽丘壑，作亭非壯麗。", "獨能極遐觀，領略萬山翠。", "蒼玉無遁形，秀色歸一視。", "却笑昔人非，所見殊無異。", "東亭亂清暉，僅得翠微意。", "東山羅紅裙，未免聲色累。", "唯君別幽趣，徜徉樂清致。", "青山不改舊，領客時一醉。"]'),
('0b464527-497d-47ca-9ae2-4457eabda570','遊登高山','黄麟','宋','宋诗','song-poetry','','[]','上至登高眼界寬，蜜陀僧舍富琅玕。',64,'全唐诗/poet.song.197000.json','["上至登高眼界寬，蜜陀僧舍富琅玕。", "天雄峻塔淩穹漠，澤瀉巍階鐵護欄。", "虎腦已回仙枕夢，雞頭甯愧國香蘭。", "登臨豈止黄花日，川練常隨夜月寒。"]'),
('a4b31878-2d68-4b83-8984-0335c6d2fc23','和駱蘿憲分水嶺詩  其一','林致誠','宋','宋诗','song-poetry','','[]','一自端明去外臺，脩途松蓋屬誰栽。',32,'全唐诗/poet.song.197000.json','["一自端明去外臺，脩途松蓋屬誰栽。", "仁心既許推仁政，玉笋清班趁早排。"]'),
('bb2eb105-fcc0-43f1-9e7f-e7c69fc39699','和駱蘿憲分水嶺詩  其二','林致誠','宋','宋诗','song-poetry','','[]','莫言種木事平平，多少行人上玉京。',32,'全唐诗/poet.song.197000.json','["莫言種木事平平，多少行人上玉京。", "豈憚炎途依密蔭，雲天大芘盡蒙成。"]'),
('179ac52a-a466-4aa1-b14b-080635d0d848','和駱蘿憲分水嶺詩  其三','林致誠','宋','宋诗','song-poetry','','[]','照人風骨清如玉，振祖家聲遠若雷。',32,'全唐诗/poet.song.197000.json','["照人風骨清如玉，振祖家聲遠若雷。", "想對旅窗貪讀易，不知門外使車來。"]'),
('22e85b2d-a5f1-472a-b3ff-1963a18d5516','書至鵝湖訪先祖簡肅詩扁歲久不復存矣月老重飾一板令余書楬芝蘭室因題二十八字','林致誠','宋','宋诗','song-poetry','','[]','憶昔先翁此地經，曾揮詩筆掃青冥。',32,'全唐诗/poet.song.197000.json','["憶昔先翁此地經，曾揮詩筆掃青冥。", "我來徧索前修句，雷電何年敕六丁。"]'),
('ebe2139a-baba-4f24-a6ca-088c7a835d21','與廖檢法同行口占分水嶺詩  其一','駱羅憲','宋','宋诗','song-poetry','','[]','山路相隨步步高，忘懷携手上嵯峨。',32,'全唐诗/poet.song.197000.json','["山路相隨步步高，忘懷携手上嵯峨。", "掀髯長嘯青雲去，回首躋攀有許勞。"]'),
('1ae1c865-77bb-4068-a263-75f54598e971','與廖檢法同行口占分水嶺詩  其二','駱羅憲','宋','宋诗','song-poetry','','[]','世上平生懶所更，有懷真欲倣淵明。',32,'全唐诗/poet.song.197000.json','["世上平生懶所更，有懷真欲倣淵明。", "無端喚作鉛山尉，剛替渠人負弩行。"]'),
('be56fa60-8e26-418b-afac-57ec6d18abb3','與廖檢法同行口占分水嶺詩  其三','駱羅憲','宋','宋诗','song-poetry','','[]','山從頂上分閩越，四面群峰簇仗齊。',32,'全唐诗/poet.song.197000.json','["山從頂上分閩越，四面群峰簇仗齊。", "自是心同天廣大，不妨眼趁地高低。"]'),
('1f22aec0-91a1-41e2-906c-0ce4e7018484','與廖檢法同行口占分水嶺詩  其四','駱羅憲','宋','宋诗','song-poetry','','[]','盡道今年雨意稠，踏歌芒時偏東疇。',32,'全唐诗/poet.song.197000.json','["盡道今年雨意稠，踏歌芒時偏東疇。", "微官祇有年豐願，一飽高眠萬事休。"]'),
