('e66dbb72-51ff-4d62-a568-757868dcdf22','送鄔文伯','史彌寧','宋','宋诗','song-poetry','','[]','一世鄔文伯，三生鍾子期。',48,'全唐诗/poet.song.197000.json','["一世鄔文伯，三生鍾子期。", "風流到尊俎，酬倡迭壎箎。", "去棹趨蘭養，來韉趁菊時。", "南湖清鏡裏，明日欠君詩。"]'),
('70c1bdd0-0b9d-47cb-8cc0-1321f44b4e2f','江亭晚思二首  其一','史彌寧','宋','宋诗','song-poetry','','[]','風烟酬酢費吟牋，剩句殘章尚滿前。',32,'全唐诗/poet.song.197000.json','["風烟酬酢費吟牋，剩句殘章尚滿前。", "際晚奚囊收未盡，一時寄在白鷗邊。"]'),
('66cb3d4a-e1a8-4093-aaa0-b9bd20c32435','江亭晚思二首  其二','史彌寧','宋','宋诗','song-poetry','','[]','有底江鷗不耐煩，月明連夜送詩還。',32,'全唐诗/poet.song.197000.json','["有底江鷗不耐煩，月明連夜送詩還。", "沙頭接得重搜句，推與儂忙渠倒閑。"]'),
('fa7a322f-9907-4383-8862-f81a418bb6bd','鄭中卿惠蝤蛑','史彌寧','宋','宋诗','song-poetry','','[]','客窗不作侯鯖夢，隨分魚蝦薦一杯。',32,'全唐诗/poet.song.197000.json','["客窗不作侯鯖夢，隨分魚蝦薦一杯。", "食指怪生連夜動，敲門郭索送詩來。"]'),
('08e0d29d-5acf-4576-b712-978871ed6856','野塘秋鷺','史彌寧','宋','宋诗','song-poetry','','[]','玉立秋塘一振衣，竦肩莫是爲尋詩。',32,'全唐诗/poet.song.197000.json','["玉立秋塘一振衣，竦肩莫是爲尋詩。", "近來絕少元和樣，島瘦郊寒渠得之。"]'),
('0c582ab6-08be-475d-bc64-c3b7b103bd67','紫笑','史彌寧','宋','宋诗','song-poetry','','[]','芳苞暗解紫羅囊，香殺東風一味狂。',32,'全唐诗/poet.song.197000.json','["芳苞暗解紫羅囊，香殺東風一味狂。", "試問花神緣底笑，笑他鶑蝶爲春忙。"]'),
('a6cf239f-ec95-4075-b927-f0a92109a846','過臨江','史彌寧','宋','宋诗','song-poetry','','[]','嘉定有八禩，三月哉生明。',264,'全唐诗/poet.song.197000.json','["嘉定有八禩，三月哉生明。", "史子脫吏鞅，超然若登瀛。", "釃酒渡清江，風帆引歸程。", "僮奴忽報我，重客來相迎。", "推篷驚且喜，火急問姓名。", "云是遠近山，江湖舊有聲。", "各欲贄韻語，藉手論交情。", "倒屣延見之，驩甚如平生。", "近山屬思久，竚立詩未成。", "意者事工緻，一字百鍊精。", "遠山得句易，奔走隨東征。", "頗似誇雋捷，攙先求獻呈。", "顧予雖不敏，嘗試與子評。", "自古文章士，大率多相輕。", "二君富丘壑，氣象俱崢嶸。", "萬世所宗仰，尹任夷之清。", "譬彼蘭與菊，春媚或秋榮。", "底用角遲速，區區尚爭衡。", "端盍如奏雅，迭和韶鈞鳴。", "願言酬嘉惠，託身與齊盟。", "扁舟劈箭飛，懷抱何由傾。", "感子意勤拳，寫作江上行。"]'),
('5dad3f5a-5e92-4a7f-a7b2-bb70679e83c7','歸航','史彌寧','宋','宋诗','song-poetry','','[]','春岸移舟雪半消，長年忍冷轉塘坳。',32,'全唐诗/poet.song.197000.json','["春岸移舟雪半消，長年忍冷轉塘坳。", "數聲鴉軋催歸艣，屬玉驚飛上柳梢。"]'),
('f107fe2a-fce5-4b41-a5f7-cbdaa15cd488','即事','史彌寧','宋','宋诗','song-poetry','','[]','翠屏珠幌水沉烟，日日春風醉筦絃。',32,'全唐诗/poet.song.197000.json','["翠屏珠幌水沉烟，日日春風醉筦絃。", "得似南湖老漁隠，短蓑銅斗白鷗前。"]'),
('c1d6046d-8807-481f-8635-b5e13b179cd3','聞笛','史彌寧','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','卸帆沽酒荻花村，水色天光凈不分。',32,'全唐诗/poet.song.197000.json','["卸帆沽酒荻花村，水色天光凈不分。", "霜月凄凉何許笛，一聲吹裂洞庭雲。"]'),
('ec511d18-e2e2-4fe7-a03e-06ada9f398c6','紅雪','史彌寧','宋','宋诗','song-poetry','','[]','金衣花裏嚲春寒，桃杏牆頭正耐看。',32,'全唐诗/poet.song.197000.json','["金衣花裏嚲春寒，桃杏牆頭正耐看。", "苦被東風愛裝景，借些紅雪打闌干。"]'),
('e2694a10-2668-4e39-9ac8-f74890da9abf','舟中','史彌寧','宋','宋诗','song-poetry','','[]','西風吹上木蘭船，人訝今時李郭仙。',64,'全唐诗/poet.song.197000.json','["西風吹上木蘭船，人訝今時李郭仙。", "一抹烟光粘遠樹，十分山翠滴晴川。", "夕陽半在寒鴉外，秋色全歸過鴈邊。", "縱有清詩費摹寫，楮生爲我喚龍眠。"]'),
('b7dc0c6a-a878-477e-b3dd-f16335211b94','翟簿示似中秋高作命意着語殆與商素爭清讀至人與月忘年之句不覺擊節借五言爲韻賦詩答謝  其一','史彌寧','宋','宋诗','song-poetry','','[]','飲月漱吟齒，心事何輪囷。',24,'全唐诗/poet.song.197000.json','["飲月漱吟齒，心事何輪囷。", "醉舞影凌亂，子其謫僊人。"]'),
('e92d75f9-db99-4976-becc-ffc060572457','翟簿示似中秋高作命意着語殆與商素爭清讀至人與月忘年之句不覺擊節借五言爲韻賦詩答謝  其二','史彌寧','宋','宋诗','song-poetry','','[]','老蟾挂青冥，寒影墮秋渚。',24,'全唐诗/poet.song.197000.json','["老蟾挂青冥，寒影墮秋渚。", "流聲到楚澤，千古相溶與。"]'),
('87b8526f-c63d-4ad7-aa18-dca63a48afec','翟簿示似中秋高作命意着語殆與商素爭清讀至人與月忘年之句不覺擊節借五言爲韻賦詩答謝  其三','史彌寧','宋','宋诗','song-poetry','','[]','露氣粟我膚，棄捐掌中月。',24,'全唐诗/poet.song.197000.json','["露氣粟我膚，棄捐掌中月。", "高眼沒雲鴻，澄輝眇窮髮。"]'),
('0e3ae03a-4821-42b6-aea3-9d068f9b40c2','翟簿示似中秋高作命意着語殆與商素爭清讀至人與月忘年之句不覺擊節借五言爲韻賦詩答謝  其四','史彌寧','宋','宋诗','song-poetry','','[]','天風來廣寒，吹下雲錦裳。',24,'全唐诗/poet.song.197000.json','["天風來廣寒，吹下雲錦裳。", "雖無金錯刀，緹革余敢忘。"]'),
('de19c363-d521-4e94-befb-2ec322bbf917','翟簿示似中秋高作命意着語殆與商素爭清讀至人與月忘年之句不覺擊節借五言爲韻賦詩答謝  其五','史彌寧','宋','宋诗','song-poetry','','[]','歌子秋風疊，誦子明月篇。',24,'全唐诗/poet.song.197000.json','["歌子秋風疊，誦子明月篇。", "信有習鑿齒，勝讀書十年。"]'),
('a7ae53e3-30e6-4137-be29-7031274a4fd1','按圖志去城而南有巖曰金紫昔蕭千巖擅一世詩聲乾道間嘗寓家郡之西湖意其必有題詠鑱之崖壁一日訪之則了無所睹方重爲此巖太息而別乘示似佳篇勉之著語以紀其勝賦五十六字','史彌寧','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去城不隔五七里，雲竇誰鑱能怪奇。',64,'全唐诗/poet.song.197000.json','["去城不隔五七里，雲竇誰鑱能怪奇。", "石屋盡頭天罅坼，林柯缺處日光垂。", "山禽上下有餘樂，僊鼠往來無倦時。", "惜許千巖舊遊所，摩挱蘚壁欠渠詩。"]'),
('f5bcba0a-9fdd-4fed-85ac-39759e9d8088','題清湘管善甫青雲樓','史彌寧','宋','宋诗','song-poetry','','[]','湘山詩眼兩爭高，醉墨淋浪濕斗杓。',32,'全唐诗/poet.song.197000.json','["湘山詩眼兩爭高，醉墨淋浪濕斗杓。", "說似元龍徹欄楯，恐妨縱武上曾霄。"]'),
('bcd920d7-cc01-45f4-acba-19b7c81bf652','晴江觀鴨','史彌寧','宋','宋诗','song-poetry','','[]','鴨鴨新晴出翠蒲，春江水暖互相呼。',32,'全唐诗/poet.song.197000.json','["鴨鴨新晴出翠蒲，春江水暖互相呼。", "避人深入蒼烟去，莫是喬僊雙履無。"]'),
('149ffd48-e89c-4916-9d4e-c6386dac0a44','啜茗','史彌寧','宋','宋诗','song-poetry','','[]','瞢騰午困懶吟哦，鼎沸槍旗不厭多。',32,'全唐诗/poet.song.197000.json','["瞢騰午困懶吟哦，鼎沸槍旗不厭多。", "戰退睡魔三十里，安知門外有詩魔。"]'),
('1b33f5e1-cb7f-48a6-9b4c-58102e106ef7','秋蘭三絕  其一','史彌寧','宋','宋诗','song-poetry','','[]','葉葉低垂翠带長，花清榦瘦吐微香。',32,'全唐诗/poet.song.197000.json','["葉葉低垂翠带長，花清榦瘦吐微香。", "西風劣相添寒色，簇立蜻蜓凍欲僵。"]'),
('f89751b8-3c34-4771-b129-f9de8c189d9f','秋蘭三絕  其二','史彌寧','宋','宋诗','song-poetry','','[]','杜若江蘺汝弟兄，楚騷經裏總知名。',32,'全唐诗/poet.song.197000.json','["杜若江蘺汝弟兄，楚騷經裏總知名。", "雖然臭味略相似，畢竟還他骨格清。"]'),
('20b7f6ea-03fa-40b4-8809-e2eab5ae2e87','秋蘭三絕  其三','史彌寧','宋','宋诗','song-poetry','','[]','砌蠟成花淺带黄，紫莖綠葉媚秋光。',32,'全唐诗/poet.song.197000.json','["砌蠟成花淺带黄，紫莖綠葉媚秋光。", "不吟尚自清羸甚，怪得詩腰肖沈郎。"]'),
('46d9bd7a-4980-4312-8584-3097912d1ed0','簷滴','史彌寧','宋','宋诗','song-poetry','','[]','過雨秋簷不住聲，敲盆滴砌带詩清。',32,'全唐诗/poet.song.197000.json','["過雨秋簷不住聲，敲盆滴砌带詩清。", "料渠要學儂搜句，旋疊平平仄仄平。"]'),
('b16bcffc-9e1d-4fb1-9595-76e809962c1b','陸放翁畫像','史彌寧','宋','宋诗','song-poetry','','[]','詩酒江南劍外身，眼驚幻墨逼天真。',32,'全唐诗/poet.song.197000.json','["詩酒江南劍外身，眼驚幻墨逼天真。", "是誰不道君無對，世上元來更有人。"]'),
('44af40bc-af37-4fe1-a7fa-d3116da01be2','評詩','史彌寧','宋','宋诗','song-poetry','','[]','籌量節物細評詩，詩要天然莫强爲。',32,'全唐诗/poet.song.197000.json','["籌量節物細評詩，詩要天然莫强爲。", "蛩韻酸寒東野句，鶑吟富貴小山詞。"]'),
('19341b55-189a-42c2-9b2a-44e878ecaf87','懷白石','史彌寧','宋','宋诗','song-poetry','','[]','秋堂風露夜沉沉，頼有寒螿伴苦吟。',32,'全唐诗/poet.song.197000.json','["秋堂風露夜沉沉，頼有寒螿伴苦吟。", "詩句未蒼人自老，十年山水負知音。"]'),
