('c02a0122-18b2-40fe-bdee-8c9d8b94b8f9','題劉君鼎臣盤谷圖','史彌寧','宋','宋诗','song-poetry','','[]','崖壁開張半幅慳，權名人見若爲顔。',32,'全唐诗/poet.song.197000.json','["崖壁開張半幅慳，權名人見若爲顔。", "那知別有真丘壑，不在區區紙上山。"]'),
('8a376323-3f8f-4964-89ca-09e6252408eb','懷歸','史彌寧','宋','宋诗','song-poetry','','[]','全家索米又邊頭，冷落南湖一鏡秋。',32,'全唐诗/poet.song.197000.json','["全家索米又邊頭，冷落南湖一鏡秋。", "了却眼前兒女債，買蓑烟際伴閑鷗。"]'),
('2489afbb-cb38-447c-af19-b9d855bb3f11','荷恩堂','史彌寧','宋','宋诗','song-poetry','','[]','不才只合老林丘，也玷班行也典州。',32,'全唐诗/poet.song.197000.json','["不才只合老林丘，也玷班行也典州。", "慚愧一家都飽暖，君恩海樣若爲酬。"]'),
('d936bee7-28e6-42f0-a6a3-1d10a75ad208','弔和靖','史彌寧','宋','宋诗','song-poetry','','[]','風林輥雪冷驚鴉，來弔孤山處士家。',32,'全唐诗/poet.song.197000.json','["風林輥雪冷驚鴉，來弔孤山處士家。", "只有寒泉欠秋菊，一杯聊復薦梅花。"]'),
('b1b83a2c-c137-4d94-a821-f4d44baf0650','菊','史彌寧','宋','宋诗','song-poetry','','[]','癖好秋光勸不回，揮金一䴮買詩材。',32,'全唐诗/poet.song.197000.json','["癖好秋光勸不回，揮金一䴮買詩材。", "寒花也自矜前輩，曾與柴桑保社來。"]'),
('d639adaa-c5e3-49ae-8499-ff9ec3d88354','萸','史彌寧','宋','宋诗','song-poetry','','[]','不入湘纍俎豆閒，也分半席綴詩壇。',32,'全唐诗/poet.song.197000.json','["不入湘纍俎豆閒，也分半席綴詩壇。", "杜陵老眼明於鏡，醉撚西風子細看。"]'),
('7867a785-1099-4f43-941a-f3b7f2e03e31','燕','史彌寧','宋','宋诗','song-poetry','','[]','管鮑交情已矣夫，君看門上翟公書。',32,'全唐诗/poet.song.197000.json','["管鮑交情已矣夫，君看門上翟公書。", "茅簷不鄙頻來往，叔末衣冠得似渠。"]'),
('41b2197c-b36f-4562-84a2-ef0b17080b43','寺中觀梅','史彌寧','宋','宋诗','song-poetry','','[]','慈尊宴坐衆香國，環列毗耶彼上人。',32,'全唐诗/poet.song.197000.json','["慈尊宴坐衆香國，環列毗耶彼上人。", "老子也揩凡肉眼，來瞻清凈法王身。"]'),
('4ef50dd0-4af5-46d5-8dbd-bb1b32667e03','雲山詩境','史彌寧','宋','宋诗','song-poetry','','[]','天公收畫底論錢，借與山人換樣看。',64,'全唐诗/poet.song.197000.json','["天公收畫底論錢，借與山人換樣看。", "雲巘浮春晴嶂暖，烟崖積雪曉屏寒。", "平林淡抹精神嫵，小景橫陳氣象寬。", "定自米家船上買，不然那得許多般。"]'),
('48431151-305b-47e7-8acc-8b21758e3a91','鳩','史彌寧','宋','宋诗','song-poetry','','[]','着詩催得雨垂垂，連累林鳩逐婦歸。',32,'全唐诗/poet.song.197000.json','["着詩催得雨垂垂，連累林鳩逐婦歸。", "爲汝賦晴休怨望，自今已後免分飛。"]'),
('5e175b4a-dfca-4271-bba3-520fece6fee2','蛩螿','史彌寧','宋','宋诗','song-poetry','','[]','聲作饑鳶吟未休，蛩螿鬭合賦清秋。',32,'全唐诗/poet.song.197000.json','["聲作饑鳶吟未休，蛩螿鬭合賦清秋。", "被他聒得渾無句，獨力難勝衆楚咻。"]'),
('7dd87605-ee8a-47a5-a624-e6e0098996bf','和黄雲夫武攸見寄韻','史彌寧','宋','宋诗','song-poetry','','[]','詩名千古杜陵翁，身不勝窮道不窮。',64,'全唐诗/poet.song.197000.json','["詩名千古杜陵翁，身不勝窮道不窮。", "編簡湛酣君有味，江山彈壓我無功。", "穉凉庭院梧桐雨，晚照陂塘蓼荻風。", "如此秋光欠料理，故人緣底尚東蒙。"]'),
('43cc49f5-8b4e-41ff-a8c6-7a23bcdfb3ad','大閲','史彌寧','宋','宋诗','song-poetry','','[]','擐甲邊城教即戎，三軍錦繡曉光中。',64,'全唐诗/poet.song.197000.json','["擐甲邊城教即戎，三軍錦繡曉光中。", "影摇澬水旌旗動，聲震文山鼓角雄。", "馬慣揮戈翻塞雪，鴈驚鳴鏑響天風。", "十行忍負君王意，同向燕然勒雋功。"]'),
('15196461-09a0-49df-8695-b35c5da50d74','次韻黄倅喜雨','史彌寧','宋','宋诗','song-poetry','','[]','喚起神龍澤楚鄉，午天轉首失炎光。',32,'全唐诗/poet.song.197000.json','["喚起神龍澤楚鄉，午天轉首失炎光。", "怪生未到秋深處，早有蕭蕭葉響廊。"]'),
('6558a606-decf-4b16-89d6-10704429fc13','六亭爲邵陽登覽之勝識其名於千巖之詩稔矣廼今僅存其一方欲次第尋訪以仍舊貫不謂簿領得我心之所同然舂容大篇率先作倡而令君和章亦復繼至閔免賡酢用肩吾人相與祈成之意','史彌寧','宋','宋诗','song-poetry','','[]','晨光泫露華，秋聲亂風葉。',288,'全唐诗/poet.song.197000.json','["晨光泫露華，秋聲亂風葉。", "翛然步中庭，詩瘦單衣怯。", "塵銷玉宇浄，西爽浮雙睫。", "圍繞簿書叢，頗覺汗欲浹。", "吏散仍心清，窗泛鑪香浥。", "生平耆幽討，此意若爲愜。", "滄浪楚名郡，江澄山嵬嶪。", "流派瀟湘分，氣脈衡廬接。", "四序春無邊，萬象光有曄。", "閣束范寬手，天開畫屏摺。", "怡融田野間，夫耕而婦饁。", "林雞鳴喈喈，沙禽墮跕跕。", "千里趨農桑，渠肯事游俠。", "不晚刈黄雲，腰鎌忙劫劫。", "年豐多暇時，陳迹旋搜獵。", "六亭僅一存，感慨思足躡。", "訪古亟臨眺，樂此忘疲薾。", "騰身一柱峰，頫首百雉堞。", "懷哉千巖翁，騷壇未易躐。", "晝覽五言城，中宵勞夢蝶。", "詞鋒摧泰華，疇敢攖其鋏。", "有來二妙吟，驪珠粲盈笈。", "格律守蕭規，欲和可容輒。", "荒園竚更新，成趣期日涉。"]'),
('47839cc1-45bb-4e21-8c67-affc84c5b6bf','僧窗','史彌寧','宋','宋诗','song-poetry','','[]','朝市踆踆走利名，道人許樣不關情。',32,'全唐诗/poet.song.197000.json','["朝市踆踆走利名，道人許樣不關情。", "西窗夢破梅花曉，敲月數聲鐘磬清。"]'),
('72703203-61bf-47ed-9b25-3cea59de5b1e','賦鴈','史彌寧','宋','宋诗','song-poetry','','[]','雲慘胡天倦客程，西風失喜到江城。',32,'全唐诗/poet.song.197000.json','["雲慘胡天倦客程，西風失喜到江城。", "自傳屬國書來後，獵獵聲名動漢京。"]'),
('4f556545-689b-49c2-949c-c9ae4616ac5c','通守黄子說解印造朝之日江梅輒花天其或者以相行色耶取風人託物之義賦詩餞別致繾綣意','史彌寧','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鵷甃霜明欺曉色，一笑巡簷梅摘索。',256,'全唐诗/poet.song.197000.json','["鵷甃霜明欺曉色，一笑巡簷梅摘索。", "犯寒小隊出郊坰，攀折南枝餞行客。", "此客端的梅樣清，秋水爲神月爲魄。", "瑶葩粲日耿林園，玉樹凌空挺標格。", "懸知僊種出閩嶠，分得幽姿來楚澤。", "蘼蕪蘅芷遜孤芳，萬綠千紅俱避席。", "共惟別駕東閤郎，戰退膏粱凜冰檗。", "流傳好語到前村，是誰不道君清白。", "手調金鼎升廟廊，穩繼大門名烜赫。", "朅來得此歲寒友，氣味深長殊莫逆。", "相期嚼蕊吐瑰詞，更擬浮香醉瓊液。", "天飈吹起朝玉皇，香案前頭顔咫尺。", "回班爛熳賞西湖，不妨頻著孤山屐。", "明朝風月半凄凉，老我滄浪尚萍迹。", "滿城稚耋重相思，江路攀轅累千百。", "歸驄蹋雪度關山，有句先春寄來驛。"]'),
('959cc325-24aa-4e13-83e4-8c8a21b2fb1f','登鴈峰','史彌寧','宋','宋诗','song-poetry','','[]','□□□□□□□，□句揮毫手不停。',32,'全唐诗/poet.song.197000.json','["□□□□□□□，□句揮毫手不停。", "□鴈旁觀偷筆法，倉忙書破楚天青。"]'),
('cd35a22e-5f9c-4ed8-a671-b2485a88399f','溪橋','史彌寧','宋','宋诗','song-poetry','','[]','凍吟肩聳學劉叉，癡坐山房井底蛙。',32,'全唐诗/poet.song.197000.json','["凍吟肩聳學劉叉，癡坐山房井底蛙。", "財過溪橋風景別，淡烟和月罩梅花。"]'),
('8931273d-3500-41be-b0f3-8ddfb58020ec','絕湖','史彌寧','宋','宋诗','song-poetry','','[]','一湖春淥萬山圍，著我蘭舟自在飛。',32,'全唐诗/poet.song.197000.json','["一湖春淥萬山圍，著我蘭舟自在飛。", "老子行藏有神助，順風出去順風歸。"]'),
('11341514-5345-4a76-9121-4bf6cea5c391','讀楚騷','史彌寧','宋','宋诗','song-poetry','','[]','一蕊青鐙手自挑，霜風木葉下亭臯。',32,'全唐诗/poet.song.197000.json','["一蕊青鐙手自挑，霜風木葉下亭臯。", "篆香銷盡寒灰塌，細嚼梅花味楚騷。"]'),
('9a280a75-8435-437f-8a2c-1f3805207a0f','郡圃紅白蓮競放斐然短歌呈似席間諸丈','史彌寧','宋','宋诗','song-poetry','','[]','東園水亭良佳哉，紅白藕花前後開。',96,'全唐诗/poet.song.197000.json','["東園水亭良佳哉，紅白藕花前後開。", "千機織就雲錦段，萬玉琢成風露杯。", "南隣女兒學淡抹，强嫌傅粉無豔色。", "北隣女兒學淡妝，剛道施朱涴天質。", "紅兒雪兒俱絕奇，安用底苦相嘲嗤。", "道人明眼付一笑，綠尊喚客花前嬉。"]'),
('948565ec-8c25-493b-9a89-6e3b75346ca8','題湘西廖次高水南真趣','史彌寧','宋','宋诗','song-poetry','','[]','買他磐石作比隣，誰道風烟不屬君。',32,'全唐诗/poet.song.197000.json','["買他磐石作比隣，誰道風烟不屬君。", "占斷好山猶可在，無端吞併一江雲。"]'),
('450bbae4-fc67-453e-a4e4-dd54c3ba6b37','王令君惠示用少陵韻奉和','史彌寧','宋','宋诗','song-poetry','','[]','邵陵壁立三奇峰，溫泉雲山接長龍。',96,'全唐诗/poet.song.197000.json','["邵陵壁立三奇峰，溫泉雲山接長龍。", "西北谽谺幾崖谷，烟霏深瑣文僊屋。", "黄冠禱雨躡瑶壇，鏘然環珮松風寒。", "阿香驅雷天地轉，靈虬激水瀟湘翻。", "將迎鶴馭誰來往，惻惻勤民賢令長。", "已欣一稔寬百憂，更讀君詩毛骨爽。"]'),
('afebd73e-f337-4ae3-bbf3-cd13a7cbd27b','題臨川晏子直百花林','史彌寧','宋','宋诗','song-poetry','','[]','溪園歌筦日紛紛，錦繡香中扶醉人。',32,'全唐诗/poet.song.197000.json','["溪園歌筦日紛紛，錦繡香中扶醉人。", "斗酒不嫌呼李白，倩渠品藻一林春。"]'),
('29b76e31-6e7d-4ca9-9103-6b8d2c07033f','寄慥齋弟','史彌寧','宋','宋诗','song-poetry','','[]','鷗鷺逢人問歸信，三年作客負滄洲。',32,'全唐诗/poet.song.197000.json','["鷗鷺逢人問歸信，三年作客負滄洲。", "詩袍醉帽黄埃底，羞見扶風馬少游。"]'),
('06e17fb7-cc57-4efc-9290-fe8d86b95e13','繡衣行送趙道中寺丞','史彌寧','宋','宋诗','song-poetry','','[]','東門祖帳何駢闐，繡衣使者發汝川。',218,'全唐诗/poet.song.197000.json','["東門祖帳何駢闐，繡衣使者發汝川。", "星軺未遠竹坡側，風采已馳梅嶺邊。", "潢池带刀吾赤子，威信憑渠半幅紙。", "寸兵尺鐵曾不煩，坐令悔悟安田里。", "化頑一日歸吾仁，此特細事胡足云。", "頻年慘慘楚氛惡，旱潦呼天天莫聞。", "民須粒食缾無粟，非公誰捄溝壑辱。", "傾囷倒廩不遐遺，十一州人均穀腹。", "安得天下使者心公心，盡變愁歎爲謳吟。", "君不見鄉來使蜀韓忠獻，起危饑民七百萬。", "又不見傅公擁節京西時，獄訟不苛傳經典。", "公今陰德能穹崇，活人手段如兩翁。", "于嗟活人手段如兩翁，名位它日將無同。"]'),
('9c1d3ef9-ef1e-41b5-9170-00de8564409e','賦桂隠用王從周韻','史彌寧','宋','宋诗','song-poetry','','[]','詩禪在在談風月，未抵江西龍象窟。',96,'全唐诗/poet.song.197000.json','["詩禪在在談風月，未抵江西龍象窟。", "爾來結習蓮社叢，誰歟超出行輩中。", "我知桂隠傳衣處，玄機參透涪仙句。", "蕭蕭吟鬢天風吹，有酒喚客斟酌之。", "渠伊放浪真達者，詩成醉卧清陰下。", "只恐香名吹上天，不容花底長陶然。"]'),
('589fecbb-d385-41b2-bc73-2d46c28b18c6','次韻陳慈明五絕句  其一','史彌寧','宋','宋诗','song-poetry','','[]','幾年枉挂右丞圖，未辦家山瓜芋區。',32,'全唐诗/poet.song.197000.json','["幾年枉挂右丞圖，未辦家山瓜芋區。", "騎馬紅塵歸計晚，逢人囁囁話江湖。"]'),
('80bf91cc-a7d6-4227-9de1-5a6f5e6e3b3e','次韻陳慈明五絕句  其二','史彌寧','宋','宋诗','song-poetry','','[]','小春梅玉點烟村，花信從今第一番。',32,'全唐诗/poet.song.197000.json','["小春梅玉點烟村，花信從今第一番。", "緣底吟窗印疎影，梢梢偃月破黄昏。"]'),
('1bd2e3fe-c56f-4017-a4d2-54cb725fbce4','次韻陳慈明五絕句  其三','史彌寧','宋','宋诗','song-poetry','','[]','南湖經雨綠瀰漫，偏照詩人兩眼寒。',32,'全唐诗/poet.song.197000.json','["南湖經雨綠瀰漫，偏照詩人兩眼寒。", "一笑鷗邊時獨速，吟魂飛不到愁端。"]'),
('2d211474-bf49-43cc-94dc-21d20cd44ac2','次韻陳慈明五絕句  其四','史彌寧','宋','宋诗','song-poetry','','[]','買得湖陰數頃秋，斬新窗戶俯清流。',32,'全唐诗/poet.song.197000.json','["買得湖陰數頃秋，斬新窗戶俯清流。", "了無俗子溷人意，況有清尊澆客愁。"]'),
('9bad0c9d-b1c3-4555-9a9e-6c49eedbd0df','次韻陳慈明五絕句  其五','史彌寧','宋','宋诗','song-poetry','','[]','羨子尋詩盟未寒，鼎來健句壓還還。',32,'全唐诗/poet.song.197000.json','["羨子尋詩盟未寒，鼎來健句壓還還。", "不妨小緩丹霄步，雨笠烟蓑伴我閑。"]'),
('59fcfafa-bd70-4b98-9c6d-2315d875dc45','次韻王令君禱雨用杜草堂韻','史彌寧','宋','宋诗','song-poetry','','[]','疲甿吾所矜，可忍浚膏血。',96,'全唐诗/poet.song.197000.json','["疲甿吾所矜，可忍浚膏血。", "每事既厥心，其敢憚煩屑。", "旱魃偶挻災，慨念腸欲熱。", "牋天走羣望，精神重澡雪。", "一雨斗清凉，炎歊隨蕩滅。", "多稼復如雲，指日看秀結。", "感通翻覆手，田里洗愁絕。", "禱禜荷同寅，肝膽無楚越。"]'),
('f4d4b195-7c56-46b6-aaab-84fcc46a64eb','邵陽郡圃梅坡','史彌寧','宋','宋诗','song-poetry','','[]','粲玉梢頭出小亭，忍寒索笑太清生。',32,'全唐诗/poet.song.197000.json','["粲玉梢頭出小亭，忍寒索笑太清生。", "楚山活脫青屏樣，影得疎花分外明。"]'),
('ef3410dc-4d5c-409e-b42b-829c94d66cf3','和黄倅懷歸','史彌寧','宋','宋诗','song-poetry','','[]','鴈聲切切楚鄉來，似喚秋光入酒杯。',64,'全唐诗/poet.song.197000.json','["鴈聲切切楚鄉來，似喚秋光入酒杯。", "好景欠人同歷覽，歸程爲我小遲回。", "一天風月詩囊富，千里江山畫軸開。", "祇恐黄華簪未了，日邊丹檢已相催。"]'),
('aa7d520f-de72-403a-ae34-76738d17ff04','題蕭氏竹坡','史彌寧','宋','宋诗','song-poetry','','[]','鮮碧緣坡古徑深，夜窗風雨作龍吟。',32,'全唐诗/poet.song.197000.json','["鮮碧緣坡古徑深，夜窗風雨作龍吟。", "自從八葉傳芳後，數到孫枝玉滿林。"]'),
('65cc105e-3b84-42c3-93eb-fd81e7e9977d','讀千巖續藁','史彌寧','宋','宋诗','song-poetry','','[]','詩老毫端別有春，巖前草木也精神。',32,'全唐诗/poet.song.197000.json','["詩老毫端別有春，巖前草木也精神。", "錦囊留得靈犀在，辟盡人間俗子塵。"]'),
('aa24bd5f-004c-42e3-95e5-ae63150bd496','丁丑歲中秋日劭農於城南得五絕句  其一','史彌寧','宋','宋诗','song-poetry','','[]','楚俗秋來也勸耕，西風招我出郊坰。',32,'全唐诗/poet.song.197000.json','["楚俗秋來也勸耕，西風招我出郊坰。", "此行不負尋詩眼，隊隊雲山擁畫屏。"]'),
('0c7a3cb0-307f-4226-8acd-e2e3ce383cb4','丁丑歲中秋日劭農於城南得五絕句  其二','史彌寧','宋','宋诗','song-poetry','','[]','說似田家好著忙，賸培宿麥接青黄。',32,'全唐诗/poet.song.197000.json','["說似田家好著忙，賸培宿麥接青黄。", "定知不落薰風後，萬壟晴催煮餠香。"]'),
('48f222bc-0c3b-417d-9eba-e5470e157c48','丁丑歲中秋日劭農於城南得五絕句  其三','史彌寧','宋','宋诗','song-poetry','','[]','人事當先莫靠天，蚤修陂堰貯清泉。',32,'全唐诗/poet.song.197000.json','["人事當先莫靠天，蚤修陂堰貯清泉。", "來年未必晴明久，萬一晴明溉得田。"]'),
('18cd0370-c005-4871-9b51-5c1decb4df07','丁丑歲中秋日劭農於城南得五絕句  其四','史彌寧','宋','宋诗','song-poetry','','[]','家家童穉笑迎門，接得翁歸酒半醺。',32,'全唐诗/poet.song.197000.json','["家家童穉笑迎門，接得翁歸酒半醺。", "鄰舍相呼來屋裏，聽翁解說勸農文。"]'),
('91cfcbe4-83f0-4c9a-950b-3911516f41c4','丁丑歲中秋日劭農於城南得五絕句  其五','史彌寧','宋','宋诗','song-poetry','','[]','箯輿幸自到山南，尚有清杯可共銜。',32,'全唐诗/poet.song.197000.json','["箯輿幸自到山南，尚有清杯可共銜。", "何似更行三二里，大家相伴看雲巖。"]'),
('497dbe91-ef47-4771-9189-dcc2e4afa65f','送武岡法曹江叔文','史彌寧','宋','宋诗','song-poetry','','[]','赬烏噴曉金溶溶，入簷漲帽梅花風。',224,'全唐诗/poet.song.197000.json','["赬烏噴曉金溶溶，入簷漲帽梅花風。", "寒香喚我度籬落，蹋破蘚碧巡芳叢。", "彌襟清興不可柰，甕雲渴想佳人同。", "長須急走喘且汗，曰有重客過匆匆。", "撐犂頗亦眷岑絕，跫音滿尉逃虛空。", "出門一粲輒傾蓋，巖電爛爛驚王戎。", "長牋銜袖照屋壁，明珠大貝來龍宮。", "建安昔者富奇士，迄今代有文章公。", "兒童慣見此客否，氣象盍求古人中。", "翻思槐市出處異，一官何幸俱湘東。", "夜闌秉燭浮大白，款接軟語春怡融。", "公車薦墨行蜚動，騰身穩去陪鴛鴻。", "得時要不負所學，鼎鼎事業摩蒼穹。", "平生琢句肯浪與，持此餞別今文通。"]'),
('a3c2f48a-5e9c-46e7-8bf5-ec2f272db88f','靜吟','史彌寧','宋','宋诗','song-poetry','','[]','居官役役簿書間，及到家山困往還。',32,'全唐诗/poet.song.197000.json','["居官役役簿書間，及到家山困往還。", "若欲靜吟無俗累，算來却是客中閑。"]'),
('32343404-3210-42ca-a445-77371d66f5cd','小軒窠石','史彌寧','宋','宋诗','song-poetry','','[]','密傍軒窗開小池，巧安窠石俯清漪。',32,'全唐诗/poet.song.197000.json','["密傍軒窗開小池，巧安窠石俯清漪。", "道人不愛閑花草，祇種缾蕉和水梔。"]'),
('f8db5cfe-6e58-469f-8326-86164303d4c3','和邵陽張茂才青蓮花韻  其一','史彌寧','宋','宋诗','song-poetry','','[]','清標別是一家春，風帽飄飄翠染勻。',32,'全唐诗/poet.song.197000.json','["清標別是一家春，風帽飄飄翠染勻。", "貪向波間弄明月，謫僊居士□前身。"]'),
('531dc780-47d2-40bc-9117-07b8ff4d0c51','和邵陽張茂才青蓮花韻  其二','史彌寧','宋','宋诗','song-poetry','','[]','昨夜羣僊宴十洲，再三招我伴清游。',32,'全唐诗/poet.song.197000.json','["昨夜羣僊宴十洲，再三招我伴清游。", "酒酣忽跨長鯨去，碧玉杯盤散不收。"]'),
('1712ceb5-169d-4b42-a13c-9dce61e58fb0','贈蘇道士','史彌寧','宋','宋诗','song-poetry','','[]','一卷麻衣易洗心，絃琴山水是知音。',32,'全唐诗/poet.song.197000.json','["一卷麻衣易洗心，絃琴山水是知音。", "有時槃礴晴窗下，隨手雲烟噴曉林。"]'),
('5354365e-efb5-4098-bea5-7db9ff12e59a','雨中覓句','史彌寧','宋','宋诗','song-poetry','','[]','舂鉏似厭覓詩材，飛向溪心喚不回。',32,'全唐诗/poet.song.197000.json','["舂鉏似厭覓詩材，飛向溪心喚不回。", "頼有漁翁相尉薦，雨中撐得一篇來。"]'),
('47673593-2225-4517-aacc-22b666a81df3','過梅塢','史彌寧','宋','宋诗','song-poetry','','[]','此老胸襟玉雪清，逃禪畫裏著茅亭。',32,'全唐诗/poet.song.197000.json','["此老胸襟玉雪清，逃禪畫裏著茅亭。", "箇般雅淡須吾輩，俗子何曾有半星。"]'),
('610d48d1-2278-4240-a66e-528230bc7bf8','題它山善政侯廟','史彌寧','宋','宋诗','song-poetry','','[]','粲曉輕舠掠水飛，趁閑來款長官祠。',64,'全唐诗/poet.song.197000.json','["粲曉輕舠掠水飛，趁閑來款長官祠。", "雲巒著色四時畫，石瀨有聲千古詩。", "華黍幾沾膏澤潤，甘棠長起後人思。", "渠伊不盡爲霖意，除却梅龍誰得知。"]'),
('7f12744b-0e14-48a8-b7bb-73ea87657a67','竹所夜思','史彌寧','宋','宋诗','song-poetry','','[]','保社荒寒欠主盟，此君却解以詩鳴。',32,'全唐诗/poet.song.197000.json','["保社荒寒欠主盟，此君却解以詩鳴。", "風窗滿耳吟秋句，比似儂詩渠更清。"]'),
('ce5f6415-d68e-454a-bc6d-3c522052a544','再次王宰翟簿喜雨聯句韻','史彌寧','宋','宋诗','song-poetry','','[]','旱魃重爲妖，點雨如點血。',96,'全唐诗/poet.song.197000.json','["旱魃重爲妖，點雨如點血。", "一念神所矜，蜚廉變騷屑。", "靈螭卷天河，千里洗袢熱。", "二妙喜欲顛，飲豪賡白雪。", "雲烟落溪藤，傳玩幾漫滅。", "韓孟不可作，吟社誰與結。", "頼有飛鳬僊，鸞棲等超絕。", "娛我清廟音，熏蕤聽疏越。"]'),
('1f52bc90-de86-4b32-8ad2-f95a6296d20f','妙峰亭晚望','史彌寧','宋','宋诗','song-poetry','','[]','峭峰頂上著危亭，四面山開雲錦屏。',32,'全唐诗/poet.song.197000.json','["峭峰頂上著危亭，四面山開雲錦屏。", "穠淡淺深多變態，天公浪費幾丹青。"]'),
('4f57c453-eb71-4a91-82f7-0917812c9812','次韻黄貳車三絕句  其一','史彌寧','宋','宋诗','song-poetry','','[]','菩提坊裏著詩豪，佳木繁陰暑易逃。',32,'全唐诗/poet.song.197000.json','["菩提坊裏著詩豪，佳木繁陰暑易逃。", "不用移文勒回駕，箇中境界儘清高。"]'),
('9bd4c2c1-410b-4a63-87b2-003b7fd51a5a','次韻黄貳車三絕句  其二','史彌寧','宋','宋诗','song-poetry','','[]','我本無心山上山，隨風聊復過滄灣。',32,'全唐诗/poet.song.197000.json','["我本無心山上山，隨風聊復過滄灣。", "等閑償了爲霖願，却歛神功紫翠間。"]'),
('02ec6b9e-623b-4af6-8342-978e33376e5a','次韻黄貳車三絕句  其三','史彌寧','宋','宋诗','song-poetry','','[]','了却文書可是癡，幅巾行散任風吹。',32,'全唐诗/poet.song.197000.json','["了却文書可是癡，幅巾行散任風吹。", "揮毫颯颯詩驚雨，灑面蕭蕭雨送詩。"]'),
('1f946b75-1648-471d-97c1-839542d659d3','賦棲真觀月季','史彌寧','宋','宋诗','song-poetry','','[]','茶薌從臾訪棲真，闖戶蔫紅絕可人。',32,'全唐诗/poet.song.197000.json','["茶薌從臾訪棲真，闖戶蔫紅絕可人。", "不逐羣芳更代謝，一生享用四時春。"]'),
('497e391b-5fef-4ca9-a7eb-a7cfcd61668a','六亭','史彌寧','宋','宋诗','song-poetry','','[]','我不能如叔子登峴首，名配此山垂不朽。',220,'全唐诗/poet.song.197000.json','["我不能如叔子登峴首，名配此山垂不朽。", "又不能如少陵登吹臺，酒酣懷古胸崔嵬。", "但見穹崖翠阜清絕處，愛此出奇不盡之詩材。", "邵陽城中景何好，峻屏四面森圍繞。", "西南諸峰尤蔚然，地接衡廬青未了。", "天將圖畫開湘堧，雲木羅立呈鮮妍。", "上有蟬聯百雉之粉堞，下有鱗差萬瓦之晴烟。", "人指山形似龍躍，繡谷崢嶸露頭角。", "遐觀捧出頷底珠，背負凌虛勢騰踔。", "一爪突起扶杏岡，一爪盤踞蒼雪傍。", "翹尾蜿蜒卷寒碧，便擬爲霖蘇八荒。", "老我躋攀興不淺，醉吟拍拍詩瓢滿。", "祇言此樂與人同，誰子看山能具眼。"]'),
('f8f18fae-c588-4adc-a41d-4c461d4b5385','詩禪','史彌寧','宋','宋诗','song-poetry','','[]','詩家活法類禪機，悟處工夫誰得知。',37,'全唐诗/poet.song.197000.json','["詩家活法類禪機，悟處工夫誰得知。", "尋著這些關{捩犬=友}子，國風雅頌不難追。"]'),
('c316b0d5-0c6e-4ca2-99e4-3bb2273fa747','吟天','史彌寧','宋','宋诗','song-poetry','','[]','流水孤村三兩家，夕陽牛背載寒鴉。',32,'全唐诗/poet.song.197000.json','["流水孤村三兩家，夕陽牛背載寒鴉。", "扶筇笑入梅花去，箇樣吟天嘉不嘉。"]'),
('149a3887-02aa-4f28-b7b0-a9785e372996','東林雲上人見過','史彌寧','宋','宋诗','song-poetry','','[]','瘦藤十載別康廬，五老山中安穩無。',32,'全唐诗/poet.song.197000.json','["瘦藤十載別康廬，五老山中安穩無。", "霜後詩禪來訪我，爲言面目带清臞。"]'),
('66f9834c-6f87-4658-af32-561c1771745b','西風','史彌寧','宋','宋诗','song-poetry','','[]','幹了巖犀奔拒霜，又催茱菊趁重陽。',32,'全唐诗/poet.song.197000.json','["幹了巖犀奔拒霜，又催茱菊趁重陽。", "白蘋紅蓼倉黄染，冷笑西風有底忙。"]'),
('14baf3e1-9b28-41cd-9400-82c02834976b','木犀  其一','史彌寧','宋','宋诗','song-poetry','','[]','一段長長寂寞秋，著鞭芙菊尚包羞。',32,'全唐诗/poet.song.197000.json','["一段長長寂寞秋，著鞭芙菊尚包羞。", "攙先飽綻黄金粟，不落西風第二籌。"]'),
('799b9a02-6bec-4953-a0d4-6c541bf48be3','木犀  其二','史彌寧','宋','宋诗','song-poetry','','[]','壽藤伴我倚秋風，老去無詩意轉慵。',32,'全唐诗/poet.song.197000.json','["壽藤伴我倚秋風，老去無詩意轉慵。", "只是看花非覓句，清香錯認惱沖龍。"]'),
('58626e63-4e2b-48bd-b1bb-8c71477ce391','觀畫','史彌寧','宋','宋诗','song-poetry','','[]','江山梅竹好精神，漁父畦丁也逼真。',32,'全唐诗/poet.song.197000.json','["江山梅竹好精神，漁父畦丁也逼真。", "終是有些堪恨處，畫中更欠著詩人。"]'),
('71ee86c3-4b57-4a47-91ee-fd2e7ff301bd','次鄔文伯城南夜歸韻','史彌寧','宋','宋诗','song-poetry','','[]','孤嶼清江落木天，十分詩思滿歸船。',32,'全唐诗/poet.song.197000.json','["孤嶼清江落木天，十分詩思滿歸船。", "巖犀稛載香浮鼻，一味書窗惱夜眠。"]'),
('79efaa3c-1bab-4428-a261-8a0b6fde00b9','送陳法曹文卿兼柬松窗','史彌寧','宋','宋诗','song-poetry','','[]','幸無風雨窘重陽，且喚龍丘倒菊觴。',64,'全唐诗/poet.song.197000.json','["幸無風雨窘重陽，且喚龍丘倒菊觴。", "糜樣交情愁隔闊，酒般歸興笑奔忙。", "郎君足下雲霄近，阿母堂前日月長。", "若見南閩舊同社，爲言詩鬢已蒼浪。"]'),
('550184c7-bee3-411d-b32e-d8cda57dcdd4','偶述','史彌寧','宋','宋诗','song-poetry','','[]','農忻膏澤了春耕，客免深泥阻去程。',32,'全唐诗/poet.song.197000.json','["農忻膏澤了春耕，客免深泥阻去程。", "日裏放晴終夜雨，天公兩下做人情。"]'),
('2f74744e-f477-48e4-b5f1-ebaceac82968','送蘇道士','史彌寧','宋','宋诗','song-poetry','','[]','七十臞僊鬢未秋，肯來爲我說真休。',32,'全唐诗/poet.song.197000.json','["七十臞僊鬢未秋，肯來爲我說真休。", "歸歟恐負青山約，跨鶴吹笙挽不留。"]'),
('2bed46c5-ac7c-466c-8f56-18f8bfd50e77','懷歸','史彌寧','宋','宋诗','song-poetry','','[]','倚閣南湖一釣舟，西風將夢到鄉州。',32,'全唐诗/poet.song.197000.json','["倚閣南湖一釣舟，西風將夢到鄉州。", "蛙蠅名利苦多事，薄有田園歸去休。"]'),
('216e5792-e179-4346-9b8e-68b55b2a5c4a','訪孤山','史彌寧','宋','宋诗','song-poetry','','[]','曾把梅詩細品題，逋僊去後可容追。',32,'全唐诗/poet.song.197000.json','["曾把梅詩細品題，逋僊去後可容追。", "君看疎影暗香句，二百年來無此詩。"]'),
('03a61b9f-125f-49e2-a2c7-890f1bdc6e39','霜柳','史彌寧','宋','宋诗','song-poetry','','[]','十分冬暖學春華，嫋嫋垂楊映日斜。',32,'全唐诗/poet.song.197000.json','["十分冬暖學春華，嫋嫋垂楊映日斜。", "一色淡黄霜染就，看來祇欠带棲鴉。"]'),
('4c7eb53b-b730-468a-9f3c-f2c4744e0ad7','燈夕','史彌寧','宋','宋诗','song-poetry','','[]','東風劫劫趁芳辰，調柳唆梅著處新。',64,'全唐诗/poet.song.197000.json','["東風劫劫趁芳辰，調柳唆梅著處新。", "翠筦聲中千里月，銀花影裏萬家春。", "樓臺拚飲夜不夜，羅綺飄香人看人。", "抖擻吟懷歌樂歲，江山分外長精神。"]'),
('7e755b40-633c-445d-b052-cacfa828ba48','老境','史彌寧','宋','宋诗','song-poetry','','[]','老境尋詩一字無，錦囊枵腹怨奚奴。',32,'全唐诗/poet.song.197000.json','["老境尋詩一字無，錦囊枵腹怨奚奴。", "多君俎豆庚桑子，不省今吾非故吾。"]'),
('142482b4-adf4-446b-bae2-1aaaed9f2b4b','再入湖南境','史彌寧','宋','宋诗','song-poetry','','[]','我本人間有髮僧，只堪林下續傳燈。',32,'全唐诗/poet.song.197000.json','["我本人間有髮僧，只堪林下續傳燈。", "君恩强遣司民社，千里江山笑不能。"]'),
('b9d00387-128e-4dee-98cf-eeb6a2b50b21','暑夕汎月次王令君韻  其一','史彌寧','宋','宋诗','song-poetry','','[]','趁凉延客早，待月放船遲。',48,'全唐诗/poet.song.197000.json','["趁凉延客早，待月放船遲。", "河朔一尊酒，湘干六月時。", "鶑喉翻白紵，兔穎掃烏絲。", "羨殺王明府，長城五字詩。"]'),
('dc237701-ebd7-4e20-88e1-2aa4d03711dc','暑夕汎月次王令君韻  其二','史彌寧','宋','宋诗','song-poetry','','[]','吟社有如此，終當讓一頭。',48,'全唐诗/poet.song.197000.json','["吟社有如此，終當讓一頭。", "功名吾已晚，富貴子何愁。", "努力看書最，偷閑且拍浮。", "清游未可負，只尺荻花秋。"]'),
('5ead1b7e-969e-45bf-ae87-df3cfc41825b','無詩','史彌寧','宋','宋诗','song-poetry','','[]','合向青林岸幅巾，却來閙裏著吟身。',32,'全唐诗/poet.song.197000.json','["合向青林岸幅巾，却來閙裏著吟身。", "竹君門外私相語，兩日無詩羞殺人。"]'),
('de9fe0c2-fb18-47d2-a3d3-937f97c76a1e','周晦叔所宅之左一坡隠然而高有竹萬箇架小軒於翠霧蒼雪間日彈琴讀書其下軒外鳴泉清駛若與弦誦之聲相答愛其境勝爲賦一絕','史彌寧','宋','宋诗','song-poetry','','[]','竹根碧澗落寒聲，竹外雙溪抵鏡明。',32,'全唐诗/poet.song.197000.json','["竹根碧澗落寒聲，竹外雙溪抵鏡明。", "滿袖天風吟不徹，坡頭直有許多清。"]'),
('23c546ac-e54d-4484-a594-71c0fe01faa2','浮驂','史彌寧','宋','宋诗','song-poetry','','[]','天凈風平水不痕，浮驂带雪繫籬根。',32,'全唐诗/poet.song.197000.json','["天凈風平水不痕，浮驂带雪繫籬根。", "欺寒酒興崢嶸甚，又訪梅花過別村。"]'),
('4b30e553-64ce-4f7e-b695-c5397befc405','書蘇道士江行圖後  其一','史彌寧','宋','宋诗','song-poetry','','[]','叟也胸中天地寬，雲烟衮衮出毫端。',32,'全唐诗/poet.song.197000.json','["叟也胸中天地寬，雲烟衮衮出毫端。", "如何萬里經行處，不費晴窗半日看。"]'),
('b97f3ad0-9664-44c9-9e2e-db4049875e65','書蘇道士江行圖後  其二','史彌寧','宋','宋诗','song-poetry','','[]','詩酒漂零自在身，吳檣楚柂往來頻。',32,'全唐诗/poet.song.197000.json','["詩酒漂零自在身，吳檣楚柂往來頻。", "拂開數匹臨川紙，一一江山是故人。"]'),
('f6b3f3b8-a254-4ecb-b26c-c0d57a80a37c','書蘇道士江行圖後  其三','史彌寧','宋','宋诗','song-poetry','','[]','飄然雲鶴老江湖，匠出烟波絕世無。',32,'全唐诗/poet.song.197000.json','["飄然雲鶴老江湖，匠出烟波絕世無。", "一見昏眸爲渠豁，半生空挂輞川圖。"]'),
('7f49a994-306e-4dfd-bcba-c3f2e6687748','有惠廬山圖者','史彌寧','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','生平巖岫飽躋攀，忽得雲巒挂壁間。',32,'全唐诗/poet.song.197000.json','["生平巖岫飽躋攀，忽得雲巒挂壁間。", "不怕老來無脚力，閉門端坐看廬山。"]'),
('c86dff2c-8988-4ffc-802f-d8d1ee005f0e','香澗老衲示似玉林首倡極道竹溪宴月之樂玉林勉以屬和  其一','史彌寧','宋','宋诗','song-poetry','','[]','長松翠竹拱晴波，不飲其如月色何。',32,'全唐诗/poet.song.197000.json','["長松翠竹拱晴波，不飲其如月色何。", "珍重阿連能好事，高軒携酒夜深過。"]'),
('e95c8f60-e02e-4846-bb2a-3bebb74cd65c','香澗老衲示似玉林首倡極道竹溪宴月之樂玉林勉以屬和  其二','史彌寧','宋','宋诗','song-poetry','','[]','孤令青蓮欠所親，月邊和影是三人。',32,'全唐诗/poet.song.197000.json','["孤令青蓮欠所親，月邊和影是三人。", "何如洗醆溪光裏，弟勸兄酬汎玉輪。"]'),
('da0ae008-c274-4d63-8284-7b444b88aa99','琮上人以詩惠茶筍','史彌寧','宋','宋诗','song-poetry','','[]','解道碧雲句，三生湯惠休。',48,'全唐诗/poet.song.197000.json','["解道碧雲句，三生湯惠休。", "試春輟鷹爪，斸雨餉貓頭。", "夢境可容到，饞涎那復流。", "舌端吾薦取，倘不負珍投。"]'),
('b9a5ecd7-5a42-47aa-9bc9-8f18c429b527','又次韻楊梅三絕句  其一','史彌寧','宋','宋诗','song-poetry','','[]','財到南村六月時，累累紅紫玉低垂。',32,'全唐诗/poet.song.197000.json','["財到南村六月時，累累紅紫玉低垂。", "筠籠送似露猶濕，更費支郎七字詩。"]'),
('10535389-67be-401d-8cd8-57bda8a13f7a','又次韻楊梅三絕句  其二','史彌寧','宋','宋诗','song-poetry','','[]','桃李漫山等俗流，諸楊汝是荔支儔。',32,'全唐诗/poet.song.197000.json','["桃李漫山等俗流，諸楊汝是荔支儔。", "當時若貢長生殿，又得真妃笑點頭。"]'),
('8b7985cd-5513-424d-906e-43bbf47e4253','又次韻楊梅三絕句  其三','史彌寧','宋','宋诗','song-poetry','','[]','釀蜜搓成絳雪團，莫嫌風味欠儒酸。',32,'全唐诗/poet.song.197000.json','["釀蜜搓成絳雪團，莫嫌風味欠儒酸。", "此詩此果君知麽，一樣驪珠粲玉盤。"]'),
