('d25103f6-3fb8-478c-8f33-81712b97ee15','邵陽界上同友人山行','史彌寧','宋','宋诗','song-poetry','','[]','杜宇聲中歷翠微，澗泉决决瀉幽奇。',32,'全唐诗/poet.song.197000.json','["杜宇聲中歷翠微，澗泉决决瀉幽奇。", "與君笑入白雲去，柱杖前頭儘是詩。"]'),
('08427a05-811b-4f3b-be55-3736fc16f2b6','醴陵道上飲別故人被酒困坐竹輿因賦','史彌寧','宋','宋诗','song-poetry','','[]','雞聲催起度江鄉，病酒無憀客路長。',32,'全唐诗/poet.song.197000.json','["雞聲催起度江鄉，病酒無憀客路長。", "掩上轎窗無隻句，著何面目見春光。"]'),
('27c05b78-a1c1-465d-810a-2e0deeae43c8','夏日遊九龍巖','劉夢符','宋','宋诗','song-poetry','','[]','突兀靈巖古，紆迴石磴升。',48,'全唐诗/poet.song.197000.json','["突兀靈巖古，紆迴石磴升。", "地幽忘日烈，壁峭喜雲蒸。", "峰頂池如月，山根水欲冰。", "摩挲可鎸處，大字紀中興。"]'),
('27e66417-686c-459c-93ad-417b91bcbff2','遊月巖書二絕以紀其清  其一','趙虞臣','宋','宋诗','song-poetry','','[]','蘭著秋花分外奇，月巖清坐聽枰棋。',32,'全唐诗/poet.song.197000.json','["蘭著秋花分外奇，月巖清坐聽枰棋。", "笑譚相與同心處，更近新凉八月時。"]'),
('eac970ad-2ce8-482f-980e-3b299c90a48c','遊月巖書二絕以紀其清  其二','趙虞臣','宋','宋诗','song-poetry','','[]','茲游閑適實清奇，恍對柯山一局棋。',32,'全唐诗/poet.song.197000.json','["茲游閑適實清奇，恍對柯山一局棋。", "興盡相呼下山去，歸途猶趁日西時。"]'),
('7b3469bd-ffcf-4a55-9330-49c66e456880','題北高峰石松','范師孟','宋','宋诗','song-poetry','','[]','根盤巨石四時青，陌上香泥豈敢侵。',32,'全唐诗/poet.song.197000.json','["根盤巨石四時青，陌上香泥豈敢侵。", "不但詠誇奇異跡，也須珍重歲寒心。"]'),
('ee6d20a7-d1de-40ff-bef5-9044c9ec8f84','龍多山','文師敬','宋','宋诗','song-poetry','','[]','我家龍多西，出門山在目。',240,'全唐诗/poet.song.197000.json','["我家龍多西，出門山在目。", "杖履三十里，兄弟穿雲宿。", "山上有頃田，巖洞多重複。", "石囤如內空，可容萬億斛。", "奇古一仙臺，清絕三梵屋。", "千歲大夫松，萬竿君子竹。", "四時風颼颼，多寒而少燠。", "天低星日近，舉首心自肅。", "不敢高聲呼，恐帝謂予黷。", "轉盼四方寬，萬山皆俯伏。", "幽人來避世，松柏可充腹。", "何勞苦煎炮，自有雲蒸熟。", "朝易暮楞嚴，隨意伴幽獨。", "天下真樂在，安用名利逐。", "我亦知此樂，倚門望良速。", "入山未要深，且歸問寢餗。", "男兒天下志，未忍同草木。", "他時素志遂，人進我則縮。", "來此寄餘生，分此山林福。", "吾心與道俱，出處應可卜。"]'),
('f2067076-4eb4-4ce2-838a-0eade5cb543b','玉蝶泉','張珪','宋','宋诗','song-poetry','','[]','仙人修煉地，玉井著神功。',48,'全唐诗/poet.song.197000.json','["仙人修煉地，玉井著神功。", "日月雙輪見，陰陽兩竅通。", "可堪清澈底，那更施無窮。", "尚冀丹砂力，當澆塵念空。"]'),
('345b4278-3c05-4a3f-85a5-3cca05626505','石門峰','吳弘鈺','宋','宋诗','song-poetry','','[]','橫石架廣門，天風自來去。',24,'全唐诗/poet.song.197000.json','["橫石架廣門，天風自來去。", "夜半聞洞簫，知是神遊處。"]'),
('71cfae9c-bda9-421b-86e0-c87cf56efdf3','題趙千里夜潮圖卷','篤世南','宋','宋诗','song-poetry','','[]','風濤洶湧千堆雪，拍岸翻空倒銀闕。',32,'全唐诗/poet.song.197000.json','["風濤洶湧千堆雪，拍岸翻空倒銀闕。", "雁聲驚起一江秋，萬里無雲掛明月。"]'),
('726918ee-ec9e-4853-80cf-ee4eaae247c8','白石山','林斗南','宋','宋诗','song-poetry','','[]','路迥縈紆行木杪，脚力窮時山更好。',160,'全唐诗/poet.song.197000.json','["路迥縈紆行木杪，脚力窮時山更好。", "苦吟轉覺嘉句慳，遠望方知衆山小。", "登臨自昔知幾人，留題石暗蒼苔新。", "吁嗟開闢歲時久，名字湮沒多無聞。", "細觀天地無窮極，百歲浮生真一息。", "少和靈運縱垂名，俯仰之間亦陳迹。", "何如大人能達觀，古今等視猶晨昏。", "朝菌靈芝皆死爾，彼有修短何足言。", "往來盤薄何爲者，祇爲幽懷未渠舍。", "憑闌一覽萬境空，轍迹何須遍天下。"]'),
('42bc7540-e079-44a4-976b-cb248f264a97','止止庵即事','詹琰夫','宋','宋诗','song-poetry','','[]','小結茅庵倚薜蘿，主人心事定如何。',64,'全唐诗/poet.song.197000.json','["小結茅庵倚薜蘿，主人心事定如何。", "春風枕上邯鄲夢，夜雨燈前雲水歌。", "歲月不堪頻把玩，山林偏稱小婆娑。", "年來欲問長生訣，止止庵中養太和。"]'),
('186b62d1-c0bf-46b9-8e87-205e046529a5','題三賢堂','嘉定太學生','宋','宋诗','song-poetry','','[]','和靖東坡白樂天，幾年秋菊薦寒泉。',32,'全唐诗/poet.song.197000.json','["和靖東坡白樂天，幾年秋菊薦寒泉。", "如今往事都休問，且爲官司趁酒錢。"]'),
('350193e5-3d66-42ba-8f98-058fc76d3863','送袁侍郎','嘉定太學生','宋','宋诗','song-poetry','','[]','天眷頻年惜挂冠，誰令今日遠長安。',64,'全唐诗/poet.song.197000.json','["天眷頻年惜挂冠，誰令今日遠長安。", "舉幡莫遂諸生願，祖帳應多行路難。", "去草豈知因害稼，彈烏何事却驚鸞。", "韓非老子還同傳，憑仗時人品藻看。"]'),
('f6959120-5810-4fa7-b655-0baaf8c517af','句','湖州士子','宋','宋诗','song-poetry','','[]','可憐戴工部，獨樹不成林。',12,'全唐诗/poet.song.197000.json','["可憐戴工部，獨樹不成林。"]'),
('b28a4e28-d8cc-454d-90ef-e228018f046e','詠馬當山寧江廟','章劼','宋','宋诗','song-poetry','','[]','驚濤洶湧江勢惡，一山屹立真瓌奇。',192,'全唐诗/poet.song.197000.json','["驚濤洶湧江勢惡，一山屹立真瓌奇。", "正如匹馬勇赴敵，萬夫辟易莫敢支。", "氤氳山腋雲氣聚，焜燿廟貌神靈棲。", "風帆浪舶香火盛，旱魃雨厲牛羊刲。", "三元水府各雄據，此實上元開府處。", "陰兵擐甲揚靈旗，紹興勤王寬北顧。", "塗金大扁于湖書，八法森森鬼神護。", "通犀寶带釃龍珠，羅獻渠渠嚴掌故。", "我曹一拜王之庭，坎坎擊鼓牲酒陳。", "蕭騷古木雲四合，路左怪石蹲麒麟。", "人心傾止形勢壯，區區馬跡何庸神。", "秋風願借一帆便，笠潭正好羹鱸蓴。"]'),
('6001d146-ea3e-4462-8034-ca84f759acf5','別母','苗氏女','宋','宋诗','song-poetry','','[]','桃花飛盡馬塍春，此日辭家淚滿巾。',32,'全唐诗/poet.song.197000.json','["桃花飛盡馬塍春，此日辭家淚滿巾。", "豈是比鄰無嫁處，千山萬水逐行人。"]'),
('45606036-32ee-4042-a84f-0d4188623aa7','送劉正甫赴南徐幕府','江西舉老','宋','宋诗','song-poetry','','[]','此翁文彩自權奇，抹過鹽車十萬蹄。',64,'全唐诗/poet.song.197000.json','["此翁文彩自權奇，抹過鹽車十萬蹄。", "筆下何多春草句，胸中定有辟塵犀。", "戴公山下竹三徑，米老庵前雲一溪。", "蓮幕退思湖上客，一編爲我賦新詩。"]'),
('603babc2-9890-4384-82e1-5e3b8898e90d','與客九日遊龍山以塵世難逢開口笑分韻得口字','劉汝進','宋','宋诗','song-poetry','','[]','縱步龍山顛，放舟龍蕩口。',48,'全唐诗/poet.song.197000.json','["縱步龍山顛，放舟龍蕩口。", "羣然雁鶩行，雜之牛馬走。", "我拙不能詩，我病不能酒。", "試問賞花人，還有菊花否。"]'),
('b0cdcfe1-8681-478b-80a7-1e18a0c51033','三賢祠','鄭子思','宋','宋诗','song-poetry','','[]','飛鳳屹立萬仞壁，下有深淵不可測。',176,'全唐诗/poet.song.197000.json','["飛鳳屹立萬仞壁，下有深淵不可測。", "問訊深淵有何物，驕然桀鷔護巢穴。", "尋常任意自出沒，砥柱中流噴濤雪。", "舟人偶有毫厘失，挫手嬰鱗即粉骨。", "每到王正上七日，昂頭掉尾見金脊。", "霽嚴收怒了無迹，共與邦人供踏蹟。", "灘頭雞卜人得吉，鼓吹鞦韆總春色。", "但見五采文煥發，盡是前賢醉鴉墨。", "今來古往幾風月，要之勿用果何益。", "莫邪尚不終磨滅，筇杖一躍肯跼蹐。", "我龍會見乘霹靂，起作甘霖沛天澤。"]'),
('a01b26c0-efee-4c2a-a1de-26f1134086b2','送鄭嚴州四首  其一','陳鑒之','宋','宋诗','song-poetry','','[]','諸賢適江海，梧竹孤鳳吟。',48,'全唐诗/poet.song.197000.json','["諸賢適江海，梧竹孤鳳吟。", "願言正王度，祈招嗣清音。", "亦爲膠西董，反慰及物心。", "未可賦柏舟，天眷宗社深。"]'),
('a0131a7c-0342-4044-9f1f-de4ac231ec1f','送鄭嚴州四首  其二','陳鑒之','宋','宋诗','song-poetry','','[]','父老迎使君，舟楫桐江波。',48,'全唐诗/poet.song.197000.json','["父老迎使君，舟楫桐江波。", "那知使君心，一片烟雨蓑。", "杖藜對客星，清風雙嵯峨。", "沙鷗公故人，應爲小婆娑。"]'),
('565c3805-b119-43fe-a20b-257e6654fc98','送鄭嚴州四首  其三','陳鑒之','宋','宋诗','song-poetry','','[]','嚴山少平田，嚴俗稀惰民。',48,'全唐诗/poet.song.197000.json','["嚴山少平田，嚴俗稀惰民。", "書生坐黄堂，肯詫硎刃新。", "定以清凈化，坐嘯物自春。", "綠野人荷鋤，使君聊岸巾。"]'),
('58281969-9d05-4b7a-b68c-9b81fb085000','送鄭嚴州四首  其四','陳鑒之','宋','宋诗','song-poetry','','[]','善端誰獨無，所化有蘭鮑。',48,'全唐诗/poet.song.197000.json','["善端誰獨無，所化有蘭鮑。", "時容拜床下，孺子似可教。", "山川頓修阻，心折東去棹。", "徘徊堤柳春，帆腹風欲飽。"]'),
('dfab142b-55ca-4d3e-a1a3-409313ab8c8e','遣興','陳鑒之','宋','宋诗','song-poetry','','[]','踏遍苕溪石，梅花又滿林。',48,'全唐诗/poet.song.197000.json','["踏遍苕溪石，梅花又滿林。", "山川春入望，宇宙月知心。", "一紀別鄉井，八年無雁音。", "危巢老松頂，日暮有歸禽。"]'),
('6993f828-110f-4bf6-97d5-bf05c1c81a99','會稽秋日觀山','陳鑒之','宋','宋诗','song-poetry','','[]','荒塍間流水，蠹葉風颼飀。',120,'全唐诗/poet.song.197000.json','["荒塍間流水，蠹葉風颼飀。", "前山與幽人，亭亭共清秋。", "遠近日明晦，隠見雲去留。", "木末一叟歸，犬鳴茅舍幽。", "憶昔典午東，劍佩森名流。", "勝地慰遠懷，茲焉久綢繆。", "漁磯與樵逕，今有斯人不。", "池石老苔髮，空餘螺蚌遊。", "世有古今異，郢歌聊自酬。", "醉眼時摩挲，此山即前修。"]'),
('7a9df4b2-ab11-4ae6-b9d5-3f01e843c0b6','過吳江','陳鑒之','宋','宋诗','song-poetry','','[]','垂虹四年別，淼淼來夢境。',96,'全唐诗/poet.song.197000.json','["垂虹四年別，淼淼來夢境。", "今晨整芒屨，柳風吹鬢影。", "春光徹重淵，蛟困綠波靜。", "遠帆有無處，小立爲徐領。", "浩歌翁自得，白髮亂垂頸。", "一室世誰如，三萬六千頃。", "平生卜鄰意，此際味差永。", "翁肯平分歟，吾其辦漁艇。"]'),
('5c98757c-2a73-4665-8e29-34e63aba738f','暮登蓬萊閣','陳鑒之','宋','宋诗','song-poetry','','[]','危欄散湮鬰，已暮亦登臨。',48,'全唐诗/poet.song.197000.json','["危欄散湮鬰，已暮亦登臨。", "鼓角孤城月，山川萬古心。", "鸛棲松霧重，鷗卧渚烟深。", "客子終何託，婆娑且醉吟。"]'),
('b4a59c40-6cb4-41fc-b930-b425055260f1','秋晚','陳鑒之','宋','宋诗','song-poetry','','[]','瘦盡芙蓉菊又殘，客遊懷抱更登山。',32,'全唐诗/poet.song.197000.json','["瘦盡芙蓉菊又殘，客遊懷抱更登山。", "秋光老矣歸何處，只在愁人雙鬢間。"]'),
('ac4dd30a-bacd-4e4e-8aee-9c1d67fda1d7','晚登京口倅廳富覽二首  其一','陳鑒之','宋','宋诗','song-poetry','','[]','窮途逢偉觀，小閣江萬里。',48,'全唐诗/poet.song.197000.json','["窮途逢偉觀，小閣江萬里。", "薄暮岸幅巾，寒烟四山起。", "天河注平淮，斗柄卧蘆葦。", "欲返還少留，燈青客船尾。"]'),
('2001d131-8a9f-4574-92ad-f76f0e84033d','晚登京口倅廳富覽二首  其二','陳鑒之','宋','宋诗','song-poetry','','[]','孫劉昔虎視，鐵騎如風雷。',48,'全唐诗/poet.song.197000.json','["孫劉昔虎視，鐵騎如風雷。", "白水列蒼嶂，今焉侑予杯。", "功名詫一時，空雲暫崔嵬。", "衲子真英雄，一龕老巖隈。"]'),
('c65f4541-3b75-41b9-8df5-1345cddee114','古詩四首奉寄陳宗之兼簡敖臞翁  其一','陳鑒之','宋','宋诗','song-poetry','','[]','雌雄烏一色，烈焰玉石分。',48,'全唐诗/poet.song.197000.json','["雌雄烏一色，烈焰玉石分。", "子桑十日雨，英概君摩雲。", "麈尾失羈思，襟裾蘭茝芬。", "是豈如蟨驉，書圃同鋤芸。"]'),
('29666a8d-790d-47d6-a028-52e786556a23','古詩四首奉寄陳宗之兼簡敖臞翁  其二','陳鑒之','宋','宋诗','song-poetry','','[]','君隠萬人海，嘯咏足勝流。',48,'全唐诗/poet.song.197000.json','["君隠萬人海，嘯咏足勝流。", "我墮寂寞濱，嵌巖一筇秋。", "蟠鬰向誰吐，天圍蘆荻洲。", "劈箭客帆去，何日回吾舟。"]'),
('bfdd1653-93cf-484b-af5b-0d2f0e59a893','古詩四首奉寄陳宗之兼簡敖臞翁  其三','陳鑒之','宋','宋诗','song-poetry','','[]','甘旨娛母顔，雍雍春滿室。',48,'全唐诗/poet.song.197000.json','["甘旨娛母顔，雍雍春滿室。", "咿啞索梨棗，諸兒爭繞膝。", "波明再茁桐，露滌清吟筆。", "人生如此足，富貴刀頭蜜。"]'),
('b412fac6-5e01-480f-a006-c29f684e2295','古詩四首奉寄陳宗之兼簡敖臞翁  其四','陳鑒之','宋','宋诗','song-poetry','','[]','亭亭會山閣，四面秋澄鮮。',48,'全唐诗/poet.song.197000.json','["亭亭會山閣，四面秋澄鮮。", "槃礴一代英，披衣俯飛鳶。", "邇來幾星聚，清樽壓雲烟。", "九轉得奇訣，分惠毋獨仙。"]'),
('4ce1e66a-69e2-41ef-8b29-64ccd081eed5','西湖晚望','陳鑒之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','過雨長堤葱翠濕，小橋人靜支筇立。',32,'全唐诗/poet.song.197000.json','["過雨長堤葱翠濕，小橋人靜支筇立。", "一縷竿頭顫霜鯽，風動青蒲見蓑笠。"]'),
('3b1ce7e0-4fc0-40ce-abd6-0a150a90910f','京口江閣和友人韻','陳鑒之','宋','宋诗','song-poetry','','[]','良辰仍我輩，斗酒大江邊。',48,'全唐诗/poet.song.197000.json','["良辰仍我輩，斗酒大江邊。", "小閣納萬里，一帆來九天。", "世塵黄鵠外，詩興白鷗前。", "地勝吾衰矣，長懷李謫仙。"]'),
('b9b5cfa9-4cc7-4096-b98e-b7ad4970a63b','題鄭承事所作蕙蘭三首  其一','陳鑒之','宋','宋诗','song-poetry','','[]','蘭如君子蕙如士，此評吾得之涪翁。',32,'全唐诗/poet.song.197000.json','["蘭如君子蕙如士，此評吾得之涪翁。", "有餘不足姑勿論，畢竟清幽氣類同。"]'),
('7a65f78f-24bb-4c59-a9da-bc75ccc3fc9e','題鄭承事所作蕙蘭三首  其二','陳鑒之','宋','宋诗','song-poetry','','[]','托迹不辭巖谷深，異於蕭艾亦何心。',32,'全唐诗/poet.song.197000.json','["托迹不辭巖谷深，異於蕭艾亦何心。", "清風披拂自多事，斜日淡雲香滿林。"]'),
('56479b33-75d4-4307-8021-98d1cdcc25c5','題鄭承事所作蕙蘭三首  其三','陳鑒之','宋','宋诗','song-poetry','','[]','鄭君欲與蘭寫真，心神暗與蘭俱春。',32,'全唐诗/poet.song.197000.json','["鄭君欲與蘭寫真，心神暗與蘭俱春。", "詩家三昧正如此，境融意會今何人。"]'),
('86483099-6f62-4962-b667-f4d9a670d131','晚凉湖邊放步','陳鑒之','宋','宋诗','song-poetry','','[]','暑氣湖山薄，晚風巾袂凉。',48,'全唐诗/poet.song.197000.json','["暑氣湖山薄，晚風巾袂凉。", "蟬鳴便柳蔭，鷺立領荷香。", "大舸鼓聲遠，小軒茶味長。", "獨遊元更好，細細踏斜陽。"]'),
('c5283cab-a274-48d3-a474-80b1d68b20d4','有感','陳鑒之','宋','宋诗','song-poetry','','[]','淋雨何人記子桑，朱門車馬漲塵黄。',32,'全唐诗/poet.song.197000.json','["淋雨何人記子桑，朱門車馬漲塵黄。", "百年友誼須英概，畫虎何妨效季良。"]'),
('4fcf077f-b70a-49bc-8f28-08281e288d19','月下見桂花欣然會心賦二十八字','陳鑒之','宋','宋诗','song-poetry','','[]','萬卉千葩春事足，一巖桂自壯秋光。',32,'全唐诗/poet.song.197000.json','["萬卉千葩春事足，一巖桂自壯秋光。", "清泠風露月侵午，天上人間相對香。"]'),
('22c1b6d3-ccd8-4f22-a15a-885971ce1bd1','同劉叔泰放步湖邊入靈芝寺坐依光良久叔泰誦坡仙好把西湖比西子之句予因賦古風一首','陳鑒之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劉郎喚我出，勝處意所便。',108,'全唐诗/poet.song.197000.json','["劉郎喚我出，勝處意所便。", "清寒柳桃風，濃淡杉檜烟。", "僧廬自生香，步繞古佛前。", "依光偶不扃，坐數禽聯翩。", "平林度清磬，遥隄簇歸船。", "湖山露真態，鷗點溶溶天。", "形容幾吟筆，剛道妝抹妍。", "莫作西子看，正如姑射仙。", "相知喜值予，微笑生清漣。"]'),
('a96fadaa-099b-4434-b709-dfab19bbfba7','探梅','陳鑒之','宋','宋诗','song-poetry','','[]','驢蹇飈寒獵帽裙，吟肩山聳酒微醺。',64,'全唐诗/poet.song.197000.json','["驢蹇飈寒獵帽裙，吟肩山聳酒微醺。", "彎彎竹逕霏霏雪，小小溪橋淡淡雲。", "忽邂逅時真得侶，向空濛處細飄芬。", "回天力量知誰似，笑挽春來首策勳。"]'),
('441c6ca9-bbf6-45bd-84b5-c8ef0a6dd481','再到京口','陳鑒之','宋','宋诗','song-poetry','','[]','問訊金焦亡恙否，雙鼇依舊據寒流。',64,'全唐诗/poet.song.197000.json','["問訊金焦亡恙否，雙鼇依舊據寒流。", "塔邊浪戰嵌巖石，木末雲扶縹緲樓。", "楓葉蓼花新醉雨，山容客鬢兩添秋。", "海天一鏡舟如豆，忘却塵緇季子裘。"]'),
('378d024d-10dc-4eec-b94d-047c17a001cf','與客夜飲蠟燭有花客請賦之','陳鑒之','宋','宋诗','song-poetry','','[]','圓蒲促坐話情真，蠟炬能花似有神。',32,'全唐诗/poet.song.197000.json','["圓蒲促坐話情真，蠟炬能花似有神。", "畢竟蜂鬚膏馥在，酒邊依舊十分春。"]'),
('070cc797-e3d1-414a-805d-ffa499fc186a','蔣實齋出示孟浩然畫像因賦二絕  其一','陳鑒之','宋','宋诗','song-poetry','','[]','吟鞭遥指鹿門歸，水色山光件件詩。',32,'全唐诗/poet.song.197000.json','["吟鞭遥指鹿門歸，水色山光件件詩。", "縮項鯿魚元自好，當年應悔識王維。"]'),
('a5c6472a-ad64-4e60-8cf1-148ad82eba3e','蔣實齋出示孟浩然畫像因賦二絕  其二','陳鑒之','宋','宋诗','song-poetry','','[]','誦詩縱不忤龍顔，榮貴無過是好官。',32,'全唐诗/poet.song.197000.json','["誦詩縱不忤龍顔，榮貴無過是好官。", "未必一僮隨瘦馬，千年傳作畫圖看。"]'),
('a4ae58fa-e5f4-45d8-bff9-f74620641a18','送方粹仲適會稽','陳鑒之','宋','宋诗','song-poetry','','[]','正好鑪亭語夜分，朔風征帽浙江濆。',64,'全唐诗/poet.song.197000.json','["正好鑪亭語夜分，朔風征帽浙江濆。", "天低雁带參差樹，山遠舟橫黯淡雲。", "龜解不妨時換酒，鯨呿元自妙爲文。", "千巖萬壑心如水，二尺檠邊剩著勳。"]'),
('2c5bd2fe-e40b-4fe3-b004-6288842923c2','到三聖廟坐池亭久之記以四十字','陳鑒之','宋','宋诗','song-poetry','','[]','倦踏軟塵陌，琳宮取次行。',48,'全唐诗/poet.song.197000.json','["倦踏軟塵陌，琳宮取次行。", "紅桃窺瀲灧，翠柳立虛明。", "眼底得詩料，耳根猶市聲。", "黄冠邀啜茗，猶有舊交情。"]'),
('10f20cd5-92d7-4a0b-b751-852e9917e4a1','同潘孔時飲總宜園孔時出寶晉數帖呼道人吹簫次日有詩予用韻答之','陳鑒之','宋','宋诗','song-poetry','','[]','六橋秋新宜醉吟，舉杯共聽巖鶴音。',80,'全唐诗/poet.song.197000.json','["六橋秋新宜醉吟，舉杯共聽巖鶴音。", "危亭三面立老竹，寶晉數帖清人心。", "凉蟬不敢喧夕曛，洞簫聲繞山腰雲。", "摇摇歸艇水紋裂，山紫天青河漢白。", "想君獨立對空闊，一鷺毛寒藕花月。"]'),
('58cae740-b9b4-44af-9b25-6b0188c3f485','包家山和潘孔時','陳鑒之','宋','宋诗','song-poetry','','[]','危闌納納萬里天，此景不作西子妍。',80,'全唐诗/poet.song.197000.json','["危闌納納萬里天，此景不作西子妍。", "荒蹊斗折喬木末，小亭棋布層崖巔。", "陽侯作意娛我醉，潮頭百尺來樽前。", "遊蜂低回殢花露，一鳥急去拖林烟。", "年來祇可作橘隠，四人聊學商山仙。"]'),
('12ede63b-18ec-49a9-a8c4-d4b57a0666a3','送陳仁叔之越','陳鑒之','宋','宋诗','song-poetry','','[]','生世可無友，吾友得仁叔。',168,'全唐诗/poet.song.197000.json','["生世可無友，吾友得仁叔。", "行己嚴尺度，色夷氣清穆。", "蠅頭觀世態，麈尾露心曲。", "大江渺愁人，風欲飽帆腹。", "重陽兩日是，不共一杯菊。", "吾儕跡浮萍，同是客京轂。", "作討俱出此，正爾未免俗。", "倘有廩可指，一笑如魯肅。", "寒窗共短檠，何用戒征軸。", "所以窮杜陵，恨欠突兀屋。", "波寒凈沙石，露重老林木。", "莫言衣带水，後會殊未卜。", "越山君舊遊，我亦曾寄目。", "邇來平安否，細與問修竹。"]'),
('411285ea-9c6a-4ec3-83d5-832c4ab637e4','寄題長溪楊耻齋梅樓樓乃其先世讀書之所','陳鑒之','宋','宋诗','song-poetry','','[]','乃翁愛書書滿樓，萬軸插架堪汗牛。',224,'全唐诗/poet.song.197000.json','["乃翁愛書書滿樓，萬軸插架堪汗牛。", "乃翁愛梅梅繞樓，千年老幹如蒼虬。", "梅護群書俗塵絕，書對梅梢滋味別。", "有時掩卷靜倚闌，檐角一枝擎淡月。", "雁行編簡相從久，筆硯收功竟無負。", "兒孫登樓凜生敬，謂此梅花乃先友。", "一新丹雘煥枅栱，黄卷依然對姬孔。", "汲泉不是灌梅花，培養君家讀書種。", "袍香青紫雲路同，盛事何翅繼乃翁。", "後來應有跨竈者，百花頭上文正公。", "吾知乃翁好梅意，不獨區區爲名第。", "霜飈天地慘無色，誰得東皇第一義。", "惟梅氣稟獨超卓，首送春風入書幄。", "對之心地悟理學，此是天民尹先覺。"]'),
('6ded97bb-c698-4d29-999b-6d3e9a84119c','春晚野步','陳鑒之','宋','宋诗','song-poetry','','[]','容易老春工，扶藜趁好風。',48,'全唐诗/poet.song.197000.json','["容易老春工，扶藜趁好風。", "蛙跳蒲細細，燕沒絮濛濛。", "沽酒亦可醉，有懷誰與同。", "長松古須鬣，無語對繁紅。"]'),
('f005fa9c-62db-4f85-ada2-9a4c81bb174e','客新安賦喜雨歌呈守齋倪史君','陳鑒之','宋','宋诗','song-poetry','','[]','良苗正要雨肥綠，火傘張空驅日轂。',196,'全唐诗/poet.song.197000.json','["良苗正要雨肥綠，火傘張空驅日轂。", "枝頭忽作少女風，轉眼排檐萬銀竹。", "爲新安民殊可憐，插空亂巘無多田。", "雨纔終日水半壁，方晴又望霓橫天。", "是邦若要宜稼穡，好似嬰兒調乳食。", "祇今田甫渴甘澍，賢侯憂民見顔色。", "鼓聲坎坎神來臨，不歆牲酒歆侯心。", "睡龍蘇醒聽約束，拏攫雲霧層崖陰。", "澗泉將涸兮亂流，嘉穎欲槁兮光浮。", "田翁戴笠兒跨牛，欣欣相對歌賢侯。", "爭言一雨神所賜，非侯何以蒙神休。", "天惠賢侯福吾土，長是五日一風兮十日一雨。"]'),
('7c1005bf-61a8-4a1b-ad64-3f7b46fbe208','守齋和張倅古巖詩予用韻賦三絕呈守齋  其一','陳鑒之','宋','宋诗','song-poetry','','[]','天然石屋兩三僧，趺坐寒雲几上生。',32,'全唐诗/poet.song.197000.json','["天然石屋兩三僧，趺坐寒雲几上生。", "想見瓦鑪烟斷處，一函經對萬松清。"]'),
('08c1d219-3b08-484e-960f-3f0ed2062325','守齋和張倅古巖詩予用韻賦三絕呈守齋  其二','陳鑒之','宋','宋诗','song-poetry','','[]','貳車林下喜逢僧，眼底千峰逸興生。',32,'全唐诗/poet.song.197000.json','["貳車林下喜逢僧，眼底千峰逸興生。", "五馬未遊心已到，吟牋零亂岫雲清。"]'),
('da4aea51-8cbf-4644-9c1d-7e83de8a966a','守齋和張倅古巖詩予用韻賦三絕呈守齋  其三','陳鑒之','宋','宋诗','song-poetry','','[]','澹泊賢侯似衲僧，功深心地棗梨生。',32,'全唐诗/poet.song.197000.json','["澹泊賢侯似衲僧，功深心地棗梨生。", "畫堂歌舞聊娛客，客退依然禪榻清。"]'),
('e040e24b-8907-4186-b650-d12be4f7332a','題問政山','陳鑒之','宋','宋诗','song-poetry','','[]','馮軾邦君侈畫熊，却來問政翠崖翁。',64,'全唐诗/poet.song.197000.json','["馮軾邦君侈畫熊，却來問政翠崖翁。", "祇應兄念玄真子，不是堂無齊蓋公。", "千載棣華垂盛事，兩叢慈竹亦清風。", "跨鸞時過宣平老，明月簫聲在半空。"]'),
('faee8342-9d9f-45f9-84b2-821d2995fc2e','守齋示予遊問政山和陳廣文詩予用韻呈守齋','陳鑒之','宋','宋诗','song-poetry','','[]','小隊名山訪古歸，雪雲不解聽招麾。',64,'全唐诗/poet.song.197000.json','["小隊名山訪古歸，雪雲不解聽招麾。", "瓊瑶千嶂插空闊，珠璧一詩爭崛奇。", "興逸聊茲遊赤石，民安何待化潢池。", "妓圍如畫心如水，鬒髮從渠映玉碑。"]'),
('037bc8c3-595d-4ba2-b0eb-246a15132d36','夏夜','陳鑒之','宋','宋诗','song-poetry','','[]','鵲影翻高樹，螢光出淺莎。',48,'全唐诗/poet.song.197000.json','["鵲影翻高樹，螢光出淺莎。", "牆低天宇闊，樓小月明多。", "清吹徐徐至，微雲緩緩過。", "欲談無與共，默坐養天和。"]'),
('9a6791d1-560c-44da-bfa5-34b98d968ec1','題陳景說詩稿後  其一','陳鑒之','宋','宋诗','song-poetry','','[]','今人宗晚唐，琢句亦清好。',24,'全唐诗/poet.song.197000.json','["今人宗晚唐，琢句亦清好。", "碧海掣長鯨，君慕杜陵老。"]'),
('a3624297-94a1-429e-bdb7-01c6b7d8269d','題陳景說詩稿後  其二','陳鑒之','宋','宋诗','song-poetry','','[]','月明孤嶼雲，一鶴唳清夜。',24,'全唐诗/poet.song.197000.json','["月明孤嶼雲，一鶴唳清夜。", "和之以君詩，竹牖寒燈下。"]'),
('faabad0d-18da-4183-b2df-b4fb7fea2caa','題陳景說詩稿後  其三','陳鑒之','宋','宋诗','song-poetry','','[]','倚馬揮萬言，跨馿哦一字。',24,'全唐诗/poet.song.197000.json','["倚馬揮萬言，跨馿哦一字。", "遲速不須論，紉雲看奇思。"]'),
('c1af698f-236e-4594-a11b-8cbdc2f242fb','和守齋戶部家居書懷','陳鑒之','宋','宋诗','song-poetry','','[]','抽身龍尾外，一壑本來心。',48,'全唐诗/poet.song.197000.json','["抽身龍尾外，一壑本來心。", "書卷竹陰潤，筆牀花氣侵。", "耿光增魏笏，雅趣寓陶琴。", "隠几時搜句，忘言兀似瘖。"]'),
('c1e6c9b7-f305-4e1a-bb15-80a845e554f1','同倪善之納凉壽芳','陳鑒之','宋','宋诗','song-poetry','','[]','沿階草軟翠流長，境靜蒲荷覺更香。',32,'全唐诗/poet.song.197000.json','["沿階草軟翠流長，境靜蒲荷覺更香。", "清坐小亭叢竹近，暫停團扇受風凉。"]'),
('384db8b8-b34c-4f2f-823c-422a8a1c1fd2','和友人題唐明皇楊太真對弈圖','陳鑒之','宋','宋诗','song-poetry','','[]','風流陣退却圍棋，心醉妖妍落子遲。',32,'全唐诗/poet.song.197000.json','["風流陣退却圍棋，心醉妖妍落子遲。", "還記兵行南詔否，輸贏應不到雙眉。"]'),
('f9782476-9549-4dc9-b6b3-293e5692969e','京口甘露寺登眺','陳鑒之','宋','宋诗','song-poetry','','[]','吹帽海風鴉背起，馮夷知我酒微醺。',64,'全唐诗/poet.song.197000.json','["吹帽海風鴉背起，馮夷知我酒微醺。", "樓臺氣壓金焦浪，鍾鼓聲飛淮浙雲。", "戈甲虎爭餘塊石，榛蕪鼪嘯幾斜曛。", "山僧不管興亡事，清坐閑披貝葉文。"]'),
('0e2a9a22-cde7-4ccd-9dc3-d9cedb0cf825','陪守齋至玉湖書院作','陳鑒之','宋','宋诗','song-poetry','','[]','天垂大溪碧，近樹齊遠山。',192,'全唐诗/poet.song.197000.json','["天垂大溪碧，近樹齊遠山。", "水氣涵野色，縹緲亭數間。", "維昔文節公，孤標凜群姦。", "飄然兩屐齒，雲巖遍躋攀。", "此地足佳致，差不遠市闤。", "壽峰顧而喜，築屋娛親顔。", "吳興富臺榭，往往携歌鬟。", "公獨抱書來，小舟破潺湲。", "花澹水紋麗，鳥啼人意閑。", "讀易發妙藴，不惟評馬班。", "著述五百卷，星芒照人寰。", "天街幾綉鞍，蹀躞趨豹關。", "河來砥柱立，一老菰蒲灣。", "守齋領客遊，秋風韻枯菅。", "我誦壁間文，徙倚蘚石斑。", "德人不可見，月白漁舟還。"]'),
('ce50f67c-6c4c-4624-9b59-c87fef9566c1','題嚴子陵釣臺','陳鑒之','宋','宋诗','song-poetry','','[]','渭濱一叟髮垂素，西伯與之無雅故。',112,'全唐诗/poet.song.197000.json','["渭濱一叟髮垂素，西伯與之無雅故。", "幡然爲捨釣魚竿，八極風雲生指顧。", "先生少與文叔遊，眼看日角興炎劉。", "胡爲掉頭不肯住，垂綸依舊披羊裘。", "周文虛己師賢哲，光武規模欠宏闊。", "三公清坐臺閣尊，先生回首桐江月。", "桐江月色無古今，白波蒼嶂幽人心。"]'),
('6eb77a2e-0aca-42a8-83a2-f0ce3977fb00','題村學圖','陳鑒之','宋','宋诗','song-poetry','','[]','田父龍鍾雪色髯，送兒來學尚腰鎌。',32,'全唐诗/poet.song.197000.json','["田父龍鍾雪色髯，送兒來學尚腰鎌。", "先生莫厭村醪薄，醴酒雖醲有楚鉗。"]'),
('85c2331e-2dc6-42dd-b1f3-8a1de77ed6e1','畢履和惠端硯余以大歙硯報之佐以一詩','陳鑒之','宋','宋诗','song-poetry','','[]','履和惠端硯，玉質馬肝色。',144,'全唐诗/poet.song.197000.json','["履和惠端硯，玉質馬肝色。", "我有大硯卧蠶紋，元是新安龍尾石。", "持以答佳貺，聊爾見此心。", "極知不是雙南金，未足報君綠綺琴。", "我得履和硯，清潤如履和。", "天然粹德非琢磨，秋江印月平不波。", "君得剛甫硯，朴鈍若剛甫。", "不能輕捷隨人後，默默寒窗守愚魯。", "端硯入手喜有餘，展開古帖聊學書。", "大硯知君不負渠，墨池飛出北溟魚。"]'),
('fc31cd75-1e45-4fa4-819c-dae09827c29b','題畫梅水仙山礬三友圖','曾由基','宋','宋诗','song-poetry','','[]','野梅清靖節，水仙韻坡公。',48,'全唐诗/poet.song.197000.json','["野梅清靖節，水仙韻坡公。", "山谷秀而野，厥有山礬風。", "陶蘇黄三君，時異風味同。", "後人思典刑，寫入畫圖中。"]'),
('fa76e6e2-f336-4fe9-90a6-e8834d645ca3','贈貴官家小姬','曾由基','宋','宋诗','song-poetry','','[]','小蠻初按曲，趁拍入凉州。',48,'全唐诗/poet.song.197000.json','["小蠻初按曲，趁拍入凉州。", "宮羽偶失次，回眸顧部頭。", "部頭色微嗔，面赭含嬌羞。", "低鬟語同伴，周郎曾顧不。"]'),
('1d953ef2-ca9b-4bf7-9425-6cfdabbe078a','用坡仙鬰孤臺韻送鄭繡使還朝','曾由基','宋','宋诗','song-poetry','','[]','人人羨登仙，去作上界遊。',100,'全唐诗/poet.song.197000.json','["人人羨登仙，去作上界遊。", "誰知世蒙恩，公其晦叔流。", "衆芳正回春，一葉偶似秋。", "靈修豈數化，宿莽休檻洲。", "却憐貪榮人，前後幾蜃樓。", "策今陳洛陽，疏肯諛滄州。", "閶闔浮雲開，臺閣清風留。", "所期共推慶曆車，可復偏重元祐舟。"]'),
('f4ff4234-8b6c-4e4f-bb5a-070ca82f2e23','賀林正字','曾由基','宋','宋诗','song-poetry','','[]','道山羣玉聚，前輩說乾淳。',48,'全唐诗/poet.song.197000.json','["道山羣玉聚，前輩說乾淳。", "近代豈乏士，清時頼有君。", "誰傳艾軒派，喜得嫡孫親。", "所欠非榮進，名流萬古芬。"]'),
('03012583-23b9-4d31-86a1-6acd042c4b58','遊益公平園懷宜春周宰頌詩','曾由基','宋','宋诗','song-poetry','','[]','丞相非嗔客，名流每舉樽。',48,'全唐诗/poet.song.197000.json','["丞相非嗔客，名流每舉樽。", "魚烹惟沼在，鶴化有軒存。", "惜欠堯夫子，幸生夷簡孫。", "平泉落誰手，文獻說平園。"]'),
('67a977cc-41bb-4b04-96a1-ea026485768b','病起幽園檢校','曾由基','宋','宋诗','song-poetry','','[]','病起無情緒，池邊日幾回。',48,'全唐诗/poet.song.197000.json','["病起無情緒，池邊日幾回。", "蟲聲低覆草，螺殻細生苔。", "暑退蘆將變，秋殘蓼續開。", "久消環繞迹，全若未嘗來。"]'),
('bf4139fc-96a7-4ecb-a57d-8ea0fc5355f7','送廣西鄭經幹並簡經略','曾由基','宋','宋诗','song-poetry','','[]','五嶺宜人地，君今捧檄行。',48,'全唐诗/poet.song.197000.json','["五嶺宜人地，君今捧檄行。", "但拚窮徹骨，不到黯無聲。", "婉畫從違裏，編氓休戚情。", "祖筵誰執爵，三祝石先生。"]'),
('6b285d2d-7e26-4958-810f-faaec7458bfa','古寺','曾由基','宋','宋诗','song-poetry','','[]','殘經閑竹几，瀹茗供花瓷。',48,'全唐诗/poet.song.197000.json','["殘經閑竹几，瀹茗供花瓷。", "法窟寂無語，禪容晚带饑。", "蟲縈道子畫，蛩響外孫碑。", "風定聞疎磬，玄關却自知。"]'),
('440dd521-fa85-40ce-96d8-b2ac342c206b','趙歲寒昆季三人拉李學諭余同遊南湖次歲寒韻','曾由基','宋','宋诗','song-poetry','','[]','紫麒麟楦豈身榮，腹有詩書氣便清。',64,'全唐诗/poet.song.197000.json','["紫麒麟楦豈身榮，腹有詩書氣便清。", "野酌雅宜招勝士，貴遊大半是宗英。", "主翁舊有登堂約，古樹今知夾道迎。", "賸欲索梅同一笑，却隨畫角弄初更。"]'),
('6b1f9ae3-e5de-4362-a786-8d59b32d105a','宦轍','曾由基','宋','宋诗','song-poetry','','[]','宦轍馳驅塵滿襟，解鞍呼酒小登臨。',64,'全唐诗/poet.song.197000.json','["宦轍馳驅塵滿襟，解鞍呼酒小登臨。", "天垂碧處秋江浄，山弄紫時西日沉。", "韓記合還渠老手，王詩似不要新吟。", "撐天拄地吾儒事，過耳飛禽空好音。"]'),
('2254f4a6-70fe-4a4d-aee7-d0712783c1b2','與中朝故人','曾由基','宋','宋诗','song-poetry','','[]','自憐骨相太邅迍，爲米折腰依舊貧。',64,'全唐诗/poet.song.197000.json','["自憐骨相太邅迍，爲米折腰依舊貧。", "古史多看多警省，新詩愈改愈精神。", "與游造物真知己，怕說天朝多故人。", "蘭菊有時忙不得，世間桃李幾番新。"]'),
('ba7858f7-dac1-491c-ba87-04c3b4fbb2f5','胡講書赴張國錄講席之招良月也','曾由基','宋','宋诗','song-poetry','','[]','初日融霜泮水清，鵠袍翔集宿中庭。',64,'全唐诗/poet.song.197000.json','["初日融霜泮水清，鵠袍翔集宿中庭。", "先生有道如陽月，太白占祥聚德星。", "安定重來闡湖學，橫渠端坐講西銘。", "自憐一唯無傳久，避席何時覿典刑。"]'),
('a1f0af00-e0ad-4e40-9d20-e22d66437a5c','送玉堂守永嘉','曾由基','宋','宋诗','song-poetry','','[]','衮衮諸公塞要津，獨當椽筆演絲綸。',64,'全唐诗/poet.song.197000.json','["衮衮諸公塞要津，獨當椽筆演絲綸。", "久陪清禁聊均佚，誰道明河不可親。", "畿郡喜迎賢太守，帝旁却欠直詞臣。", "逸才畢竟九天憶，應謂禁中須此人。"]'),
('8c8c63d5-63ac-466c-a8c5-33fe1c5d7284','余秋責余不歸責之誠是也余非敢忘鄉井而答以詩','曾由基','宋','宋诗','song-poetry','','[]','兔狡應多穴，狐妖解首丘。',24,'全唐诗/poet.song.197000.json','["兔狡應多穴，狐妖解首丘。", "一巢鳩樣拙，何計老菟裘。"]'),
('94b4d67e-5e88-46db-b5af-e927bc5f65ce','西湖冰合忽見小舟','曾由基','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四望黯同雲，平湖墮銀漢。',24,'全唐诗/poet.song.197000.json','["四望黯同雲，平湖墮銀漢。", "一葉柳邊來，應是寒澌泮。"]'),
('7418b5d1-bd63-415d-8d21-dba4d871bbe8','嘲蠟梅','曾由基','宋','宋诗','song-poetry','','[]','孤芳不被雪霜欺，占得南枝最崛奇。',32,'全唐诗/poet.song.197000.json','["孤芳不被雪霜欺，占得南枝最崛奇。", "氣骨不凡風韻少，呂醫初見退之詩。"]'),
('683c7898-01b4-40c8-bfd8-e3b6065c33eb','聚景園追凉','曾由基','宋','宋诗','song-poetry','','[]','五雲縹緲護簷牙，不是尋常富貴家。',32,'全唐诗/poet.song.197000.json','["五雲縹緲護簷牙，不是尋常富貴家。", "樹樹風蟬凉意足，衣巾時復墮槐花。"]'),
('18652308-80c4-4ff8-bb80-8de353d9f865','題昌黎傳後','曾由基','宋','宋诗','song-poetry','','[]','唐治百年生退之，行藏端的係興衰。',32,'全唐诗/poet.song.197000.json','["唐治百年生退之，行藏端的係興衰。", "三書何用干時宰，天使斯人欲有知。"]'),
('5749fdde-679e-496a-b9c8-db7dabc88fe1','題潘庭堅樂府後奉簡陳僉書','曾由基','宋','宋诗','song-poetry','','[]','性靈底物堪陶冶，郢曲彌高和彌寡。',32,'全唐诗/poet.song.197000.json','["性靈底物堪陶冶，郢曲彌高和彌寡。", "錦囊勿使六丁偷，會有昌黎賞東野。"]'),
('4a5a13a3-10be-40ff-b45f-bb790fa51fcd','晚思','曾由基','宋','宋诗','song-poetry','','[]','風號谷應樹聲喧，陰雨瀟瀟南北村。',32,'全唐诗/poet.song.197000.json','["風號谷應樹聲喧，陰雨瀟瀟南北村。", "倦翼投林舟宿港，滿懷秋思立黄昏。"]'),
('1e6023a5-e971-4339-ab98-a103d028729c','題陳陟屺寺','曾由基','宋','宋诗','song-poetry','','[]','幽泉落竇碎瓊聲，疑是朝天環珮鳴。',32,'全唐诗/poet.song.197000.json','["幽泉落竇碎瓊聲，疑是朝天環珮鳴。", "遶寺杉松皆雨露，不應秋葉似恩輕。"]'),
('41e064d9-d737-430f-9c2e-6db2570e42c2','題御愛牡丹','曾由基','宋','宋诗','song-poetry','','[]','天香不數魏姚家，玉砌雕欄護絳紗。',32,'全唐诗/poet.song.197000.json','["天香不數魏姚家，玉砌雕欄護絳紗。", "聞說弓旌遍巖穴，憐才應是勝憐花。"]'),
('bd543d7a-432c-4a91-a3c1-5be21999a46e','西湖夜景','曾由基','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閒窗放入四山青，古篆無烟氣自清。',32,'全唐诗/poet.song.197000.json','["閒窗放入四山青，古篆無烟氣自清。", "風不鳴條花著露，一湖春月萬蛙聲。"]'),
('9211042a-a8bc-4a31-991c-55be2b66499e','偶作  其一','曾由基','宋','宋诗','song-poetry','','[]','才退愁無友，時艱悔有家。',24,'全唐诗/poet.song.197000.json','["才退愁無友，時艱悔有家。", "鄉心慙杜宇，世事付楊花。"]'),
('e1b86ae8-f81a-458e-b885-2a24665e454d','偶作  其二','曾由基','宋','宋诗','song-poetry','','[]','故山荏苒失歸期，顔尚如丹鬢已絲。',64,'全唐诗/poet.song.197000.json','["故山荏苒失歸期，顔尚如丹鬢已絲。", "憶昔師門傳拙賦，迄今客路懶工詩。", "不傷遲暮無豪舉，却喜聰明減舊時。", "便把蝸廬題退隠，何時買得草堂基。"]'),
('dcfb4fd6-0ffa-451d-922b-6f76f64b23b3','偶作  其三','曾由基','宋','宋诗','song-poetry','','[]','遣愁時復賦篇章，此是書生習未忘。',32,'全唐诗/poet.song.197000.json','["遣愁時復賦篇章，此是書生習未忘。", "小吏豈堪人看覷，酒邊生怕带詩狂。"]'),
('4a5ef79b-fe5d-4908-ba77-5f671fe4136e','與陳剛父論詩','曾由基','宋','宋诗','song-poetry','','[]','少陵久矣跨鯨遊，近說西江沸不休。',64,'全唐诗/poet.song.197000.json','["少陵久矣跨鯨遊，近說西江沸不休。", "雙井發源注南海，百川分港失東流。", "君懷正印高懸眼，我抉玄關笑點頭。", "半世工夫緣底事，旁人却作等閑求。"]'),
('e3e93d03-0b28-4c9e-b408-6bbce719ba3a','答詩友徵近詩','曾由基','宋','宋诗','song-poetry','','[]','寄傲西峰未肯東，論文舊約幾時同。',64,'全唐诗/poet.song.197000.json','["寄傲西峰未肯東，論文舊約幾時同。", "不知傑句真何用，便有虛名豈療窮。", "珍重遠書徵近作，疎蕪故我欠新功。", "每慙時輩多豪逸，點筆成章杯酒中。"]'),
('9ec7a775-ad02-4000-9a8d-80dfa4fea519','題楊敬之贈項斯詩後','曾由基','宋','宋诗','song-poetry','','[]','今古銷沉幾項斯，由來作者不祈知。',32,'全唐诗/poet.song.197000.json','["今古銷沉幾項斯，由來作者不祈知。", "看渠一片憐才意，合把黄金鑄敬之。"]'),
('b81ba718-b15f-4ffb-9953-e96abed4cb91','西湖夜景','曾由基','宋','宋诗','song-poetry','','["\u897f\u6e56"]','處處芙蕖處處堂，閑行何地不清香。',32,'全唐诗/poet.song.197000.json','["處處芙蕖處處堂，閑行何地不清香。", "歸舟又趁晚凉急，十里湖光蘸夕陽。"]'),
('6ee1aa8e-dd62-41a8-bbd8-0a04322615d5','遊宜春北巖','曾由基','宋','宋诗','song-poetry','','[]','宦軀真沐漆，放懷北巖去。',228,'全唐诗/poet.song.197000.json','["宦軀真沐漆，放懷北巖去。", "行行如蔍境，漸入幽絕處。", "濕翠欲霑衣，晴雲亂生屨。", "灘聲時抑揚，嵐氣互吞吐。", "松寒韻笙竽，碣石狀鍾虡。", "朱實嫋碧藤，白羽明翠塢。", "提壺忌人醒，市醑邀我沽。", "野果枝頭尋，水樂空中度。", "飲少輒頹玉，山靈勞拱護。", "起來一凭欄，件件是佳句。", "此景幾百年，却待予全付。", "吟成石點頭，喜極石應語。", "何處一鳴鶴，而作賞音和。", "仰峯人所仰，隔江不受呼。", "正如山中人，九詔不一顧。", "傳聞唐衛公，挾冊曾此寓。", "臯夔讀何書，瑰譽響千古。", "一生拗介甫，政坐讀書誤。", "公乎儻可作，同草遂初賦。"]'),
('0a44cb43-e44f-4b49-bb0f-80d2520163eb','元夕同友街遊','曾由基','宋','宋诗','song-poetry','','[]','月韻梅梢漏未央，緩尋夢境小相羊。',64,'全唐诗/poet.song.197000.json','["月韻梅梢漏未央，緩尋夢境小相羊。", "萬家燈火天無夜，十里綺羅風自香。", "勝友何如羅粉黛，清談端可厭笙簧。", "吳儂休作築城舞，胡越年來共一疆。"]'),
('1766e09f-e5ef-49b8-a6bb-028fbd3b7732','元夕酒倦','曾由基','宋','宋诗','song-poetry','','[]','解酲貢浪語，欲困且長謠。',48,'全唐诗/poet.song.197000.json','["解酲貢浪語，欲困且長謠。", "古篆生春靄，新湯響夜潮。", "喜尋搜句伴，怕有看燈招。", "背却笙歌閙，鳴琴慰寂寥。"]'),
('e9a722c9-e6eb-4c23-864f-b0a80c6346e6','中書程先生委校勘春秋分紀大參李雁湖文集因元夕戲成一絕','曾由基','宋','宋诗','song-poetry','','[]','雪柳梢頭閙玉梅，萬家燈火月樓臺。',32,'全唐诗/poet.song.197000.json','["雪柳梢頭閙玉梅，萬家燈火月樓臺。", "校讎幸不開天上，省得扶藜太乙來。"]'),
('ec8f801d-09b7-4207-a336-f759c834bf23','春日田家三首  其一','黄大受','宋','宋诗','song-poetry','','[]','凜寒陵熙春，誰爲禦其侮。',96,'全唐诗/poet.song.197000.json','["凜寒陵熙春，誰爲禦其侮。", "酸風吹積雪，濃雲灑飛雨。", "農夫荷耒耜，俶載耕斥鹵。", "爲其有身累，寧免自辛苦。", "妻兒送中飯，凍凌强欲吐。", "晚歸極困倦，倒睡带泥土。", "朝來天光開，紅紫新媚嫵。", "南園踏青人，日暮猶歌舞。"]'),
('7374c584-7778-44d9-83d7-232af3cfb291','春日田家三首  其二','黄大受','宋','宋诗','song-poetry','','[]','二月祭社時，相呼過前林。',156,'全唐诗/poet.song.197000.json','["二月祭社時，相呼過前林。", "磨刀向豬羊，穴地安釜鬵。", "老幼相後先，再拜整衣襟。", "釃酒卜筊杯，庶知神靈歆。", "得吉共稱好，足慰今年心。", "祭餘就廣坐，不間富與貧。", "所會雖里閭，亦有連親姻。", "持殽相遺獻，聊以通殷勤。", "共說天氣佳，晴暖宜蠶春。", "且願雨水勻，秋熟還相親。", "酒酣歸路暄，桑柘影在身。", "傾欹半人扶，大笑亦大嗔。", "勿謂濁世中，而無羲皇民。"]'),
('9b4a3f5b-4c43-4dc6-ac0f-ca6aed6d54b4','春日田家三首  其三','黄大受','宋','宋诗','song-poetry','','[]','清明百草春，家家上丘墓。',84,'全唐诗/poet.song.197000.json','["清明百草春，家家上丘墓。", "南鄰去年冬，禍痛及翁嫗。", "酒殽羅新阡，蹙頞見追慕。", "舊時細君墳，望見淚已注。", "紙錢風飄飄，世用此文具。", "其間無紙者，已無子孫故。", "有紙與無紙，百步五十步。"]'),
('36264f67-77b0-43be-b32b-d6b4a76414aa','偶成  其一','黄大受','宋','宋诗','song-poetry','','[]','高唐作夢時，宋玉乃得見。',36,'全唐诗/poet.song.197000.json','["高唐作夢時，宋玉乃得見。", "那知賦說夢，夢外雲雨怨。", "此賦苟不作，應無列女傳。"]'),
('8de88610-aa2a-4d86-9d48-2f1abbc21e54','偶成  其二','黄大受','宋','宋诗','song-poetry','','[]','蕨薇生山巔，長不踰蓬蒿。',36,'全唐诗/poet.song.197000.json','["蕨薇生山巔，長不踰蓬蒿。", "松柏生澗底，歲久還干霄。", "稟質自不同，托身奚必高。"]'),
('ed6e5891-ba7c-4886-8497-8f3c560d4611','偶成  其三','黄大受','宋','宋诗','song-poetry','','[]','綠草何自來，蔓延滿中庭。',36,'全唐诗/poet.song.197000.json','["綠草何自來，蔓延滿中庭。", "前朝方芟夷，茲視忽已盈。", "竹間幽蘭花，數四移乃成。"]'),
('38c67de6-5dcd-48b6-a81c-5555134693bc','讀四皓傳','黄大受','宋','宋诗','song-poetry','','[]','白雲茫茫歌紫芝，人間無路瞻尨眉。',80,'全唐诗/poet.song.197000.json','["白雲茫茫歌紫芝，人間無路瞻尨眉。", "太子介使招忽往，高祖問省心先知。", "翁身商山名八極，此時不出漢事危。", "敢惜雙足惜漢鼎，非私劉氏私黔黎。", "欠呵千年橘中棋，華陰墮馿者爲誰。"]'),
('315a7d96-7360-489a-944a-5f5222619b8d','老寋行','黄大受','宋','宋诗','song-poetry','','[]','朔風狂驚岷峨流，帝敕雲螭藩四州。',128,'全唐诗/poet.song.197000.json','["朔風狂驚岷峨流，帝敕雲螭藩四州。", "頷珠千載化老寋，一變爲回鐍川鍵。", "蠶叢簸弄幾爲翻，欲捲全蜀淪腥膻。", "瞿塘下連滄海脈，愁積溟漲牽鰲極。", "臣冰呼天天不聞，快斥金翅清江氛。", "連環不解萬古鐵，陽侯依舊千江月。", "紫庭登奏尤其元，西州之功不補愆。", "清源血食天地久，其於冰兮亦何有。"]'),
('ca26a19e-40a0-4b01-8d43-9f36a7acbed7','昭潭寄內人','黄大受','宋','宋诗','song-poetry','','[]','不接安書動隔年，二千里外極懸懸。',64,'全唐诗/poet.song.197000.json','["不接安書動隔年，二千里外極懸懸。", "老親强健知勤饌，諸子癡頑恐費鞭。", "幸有田園堪卒歲，使知詩禮可無錢。", "客中亦有風流罪，長伴梅花對月眠。"]'),
('a0be1fa9-dd6f-4872-b1cc-fa221f7653b8','由洞庭入五田','黄大受','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一汀紅糝蓼花天，滴滴清寒曉露圓。',64,'全唐诗/poet.song.197000.json','["一汀紅糝蓼花天，滴滴清寒曉露圓。", "回首洞庭山半點，傷心桂嶺路三千。", "詩魂夜寄青林月，漁唱聲回綠樹烟。", "却笑陶朱不如我，我無西子與同船。"]'),
('bbc5b5c5-1045-4f4d-9302-6ede241b1b92','油口夜飲醉卧一室及覺三鼓矣秋夜新冷雨濕蟲鳴展轉不能成寐於是浩然有歸志','黄大受','宋','宋诗','song-poetry','','[]','一榻翛然著醉儂，沉沉清夜大槐宮。',64,'全唐诗/poet.song.197000.json','["一榻翛然著醉儂，沉沉清夜大槐宮。", "夢回作惡酒氣重，枕上不眠歸興濃。", "點滴落階添悶雨，清哀遶壁訴寒蟲。", "計行良未成端緒，何處高樓撞曉鍾。"]'),
('beb8814e-38fd-49b7-8761-62e4600f2a78','沙頭秋晚','黄大受','宋','宋诗','song-poetry','','[]','霜風吹凍玉池冰，留滯周南尚未行。',64,'全唐诗/poet.song.197000.json','["霜風吹凍玉池冰，留滯周南尚未行。", "病久故園千里夢，夜寒孤舍一枝燈。", "愁緣南賈歸舟影，心斷黄蘆落雁聲。", "老劍已閑頭已白，祇堪吟詠課歸程。"]'),
('3494f780-479c-4435-964f-dad93047e650','竹','黄大受','宋','宋诗','song-poetry','','[]','虛心懷月明，勁節挺玉立。',24,'全唐诗/poet.song.197000.json','["虛心懷月明，勁節挺玉立。", "豈是外春風，春風無處入。"]'),
('689661e6-80b6-42ac-bf8b-95fec9d5b55f','宿岳陽張漕書堂','黄大受','宋','宋诗','song-poetry','','[]','雲低風轉冷，黯黯起秋陰。',48,'全唐诗/poet.song.197000.json','["雲低風轉冷，黯黯起秋陰。", "薄暮細雨過，小窗寒氣侵。", "關山千里夢，骨肉十年心。", "病意兼歸意，攢眉寫萬金。"]'),
('00afe1a8-3fe9-43b4-9290-2b5cee05b8e5','廉泉','黄大受','宋','宋诗','song-poetry','','[]','一泓落古寺，三赤開方池。',144,'全唐诗/poet.song.197000.json','["一泓落古寺，三赤開方池。", "懷山决瀆後，爍石流金時。", "君看此廉泉，不增亦不虧。", "炯炯玉色透，燦燦金沙輝。", "朅來臨古亭，石銚行相隨。", "呼童試春芽，活火烹新奇。", "一咽利喉吻，再啜心神怡。", "泠然清風來，玉液通華池。", "憶我心地初，與水同一幾。", "心泉本無事，何必希夷齊。", "曰泉已强名，况復有是非。", "一笑付自然，貪廉吾不知。"]'),
('49976344-6329-4586-8beb-ddba8e5370a9','寧化白水磜甲子春','黄大受','宋','宋诗','song-poetry','','[]','雪瀑從天下，餘流亦建瓴。',48,'全唐诗/poet.song.197000.json','["雪瀑從天下，餘流亦建瓴。", "雙崖秋氣逼，九地殷雷聲。", "虎穴山川險，蛟涎草木腥。", "負鹺由此徑，異日不堪行。"]'),
('5ed447df-5be4-4a18-a1c4-6c123f4deca8','晚步','黄大受','宋','宋诗','song-poetry','','[]','扇小葛衣輕，風清草路平。',48,'全唐诗/poet.song.197000.json','["扇小葛衣輕，風清草路平。", "水聲逢石怒，烟素近山明。", "喚犢牛回顧，驚人犬倒行。", "耨夫方到屋，月已屋頭生。"]'),
('d09d9155-8f32-4ff2-b567-2f411bc058f8','荆州人種秧擊缶于田間以樂農者嗚呼其猶有先王之世之遺意歟','黄大受','宋','宋诗','song-poetry','','[]','鼓聲響答缶聲喧，歌笑聲多日易昏。',32,'全唐诗/poet.song.197000.json','["鼓聲響答缶聲喧，歌笑聲多日易昏。", "尚有樂農遺意在，要知此地近中原。"]'),
('d7c8f0e1-8aee-4660-a766-861fae6f66e6','呈魯齋提刑伯','黄大受','宋','宋诗','song-poetry','','[]','散盡黄金與客休，田園不爲子孫謀。',32,'全唐诗/poet.song.197000.json','["散盡黄金與客休，田園不爲子孫謀。", "白頭更自嫌多累，尚有瀟湘萬卷樓。"]'),
('69030e48-c0ea-4056-85b7-df740b4ac1a8','江行萬里圖','黄大受','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雪山西來接海白，天之所以限南北。',352,'全唐诗/poet.song.197000.json','["雪山西來接海白，天之所以限南北。", "誰人胸裏著輿圖，揮斥荆吳入綃墨。", "濃濃淡淡兩岸山，烟波瀰茫江面寬。", "水空漠漠鳥飛絕，漸看漸遠天漫漫。", "客舟泝流先後去，風帆飽腹如飛舞。", "有時小艇絕波來，不知何處橫江渡。", "鍾山隠隠開金陵，雨花臺前留玉京。", "汀洲劣處小孤出，垂楊綠引潯陽城。", "蘄黄紫翠照卷雪，武昌樓臺半明滅。", "周郎赤壁杳難憑，洞庭寒烟濛孤月。", "西江耿耿沙籀清，三十六灣斜照明。", "黄陵廟深楚山闊，九疑成削黏天青。", "我來展軸驚快覩，恍然對面水仙府。", "片時行盡江南天，吊古何勞出門去。", "南巡真人忘却歸，軒轅龍去眇難追。", "咸池曲絕誰奏樂，風雨啼痕滿竹枝。", "六朝虎士工設險，蹴踏滄波當揮劍。", "血流不惜惜江流，肯放飛埃過天塹。", "濫觴曾聞蕩雍丘，楫聲若爲空悠悠。", "江聲至今恨不盡，枉白萬古英雄頭。", "兩階干羽享波后，八公草木今健否。", "長安正在碧雲邊，斜日西風重回首。"]'),
('f6c50a18-93ab-4d1f-a26c-9036e01ffe72','梅川呈同舟游仲發時中流失舟故云','黄大受','宋','宋诗','song-poetry','','[]','投晚鍾公渡放船，急流送我轉千山。',64,'全唐诗/poet.song.197000.json','["投晚鍾公渡放船，急流送我轉千山。", "羣犀戲浴江含石，饑雁悲鳴櫓下灘。", "吟骨欲投魚腹葬，夢魂那許蝶身閑。", "可憐八尺奇男子，不作當年跛足看。"]'),
('531be045-b4c0-4b11-8bf3-b134b9ed9189','遣載入閩從李守約','黄大受','宋','宋诗','song-poetry','','[]','考亭高弟說烏洲，小子何妨作遠遊。',64,'全唐诗/poet.song.197000.json','["考亭高弟說烏洲，小子何妨作遠遊。", "問學再三勤講貫，立身第一在操脩。", "機心僅可文章用，邪說毋從釋老求。", "更做程文須典實，年來華藻近輕浮。"]'),
('1e33d25d-84bb-4d1e-b539-d017d3d4c238','即事','黄大受','宋','宋诗','song-poetry','','[]','路轉欹橋曲，陰陰石磴低。',48,'全唐诗/poet.song.197000.json','["路轉欹橋曲，陰陰石磴低。", "紫藤藟碧樹，紅葉繡清溪。", "草露明侵徑，秋香暗刺衣。", "前灘水聲好，欲趁釣魚磯。"]'),
('321344a2-8b70-4432-a458-973047d613b1','織女蟲','黄大受','宋','宋诗','song-poetry','','[]','灝氣逼星河，佳期匝眼過。',48,'全唐诗/poet.song.197000.json','["灝氣逼星河，佳期匝眼過。", "草間聞織急，天上想寒多。", "燭裏顰挑錦，邊頭冷枕戈。", "終宵弄機杼，柰此月明何。"]'),
('59c6b4bf-3dde-489a-818d-425db8d03938','早作','黄大受','宋','宋诗','song-poetry','','[]','星光欲沒曉光連，霞暈紅浮一角天。',32,'全唐诗/poet.song.197000.json','["星光欲沒曉光連，霞暈紅浮一角天。", "乾盡小園花上露，日痕恰恰到窗前。"]'),
('c67e403c-33d4-4645-9895-ee71d9482701','歸來','黄大受','宋','宋诗','song-poetry','','[]','近日多騷客，吾衰不可追。',48,'全唐诗/poet.song.197000.json','["近日多騷客，吾衰不可追。", "松間哦魯頌，花下看唐詩。", "好鳥山深語，寒蟬日暮悲。", "此聲良叶律，新句總堪疑。"]'),
('711afbbc-b284-4ea4-a79a-cc8098fc82b2','公安','黄大受','宋','宋诗','song-poetry','','[]','市人屋井底，棟與江堤平。',252,'全唐诗/poet.song.197000.json','["市人屋井底，棟與江堤平。", "大江壓堤來，浩浩勢欲傾。", "古堤騰長蛇，獨與江爭衡。", "積流增巨漲，飄突萬馬驚。", "油河與之合，盤渦沸淜騰。", "折旋聲洶涌，吞汲翻長鯨。", "微茫隔岸村，百尺崩沙赬。", "中流有行舟，來往如飛蠅。", "巨風推銀山，性命鴻毛輕。", "設險護東南，天巧如揭繩。", "用武莫若荆，豪雄所交爭。", "玄德欲興劉，於焉深經營。", "坐據此要湍，進退窺敵情。", "時事一阨塞，拂衣開西扃。", "至今聞西偏，城治餘丘陵。", "湯湯橫乎前，何畏百萬兵。", "善衛保其吭，坐待其師崩。", "更能用吾長，談笑收其贏。", "何者非神機，用之須人英。", "機略失所用，山川無常形。", "休兵不敢論，凄咽含餘情。"]'),
('871511a2-89c0-43e0-99f9-5822ee4f4201','中秋舟次沙津','黄大受','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去年中秋月，照我入桂城。',168,'全唐诗/poet.song.197000.json','["去年中秋月，照我入桂城。", "今年中秋月，送我到江陵。", "桂林二千八百里，城邊買船發春水。", "瀟湘六月寒如冰，洞庭湖中秋氣生。", "峽江西來雪波急，片帆带雨烟中濕。", "胡雁不來蘆葦秋，風林淅瀝生人愁。", "反思前年風露好，月入金罇醉將倒。", "如今飄落千萬山，烟波瀰漫幾時還。", "露香堂中千百甕，玉瓶取醉風吹夢。", "今宵弦管閙繁華，燈火沙頭一萬家。", "爭似詩翁弄江月，微吟還自汲江花。"]'),
('963d97ad-9cee-46bb-af02-a9d62c6e94f8','鬰孤','黄大受','宋','宋诗','song-poetry','','[]','臺高日欲暝，晚眺眼增明。',48,'全唐诗/poet.song.197000.json','["臺高日欲暝，晚眺眼增明。", "疊嶂羅雲樹，雙流抱粉城。", "低浮烟萬棟，清送月三更。", "尚約秋吟夜，江聲带雨聽。"]'),
('ad3c6aa2-28bc-490c-90b1-7ad5b96456c5','病起','黄大受','宋','宋诗','song-poetry','','[]','煮藥爐邊過一春，瘦骸唯與病相親。',64,'全唐诗/poet.song.197000.json','["煮藥爐邊過一春，瘦骸唯與病相親。", "雨多藥裹易生暈，潤透巾紗懶拂塵。", "枕上最宜思過眚，靜中倒得養精神。", "不辭小現維摩詰，只恐今無問病人。"]'),
('5e460421-93ea-4d15-8286-e2b12b8d4496','枝江九日簡周宰','黄大受','宋','宋诗','song-poetry','','[]','日車不照出郊車，門外天陰雲尚麤。',64,'全唐诗/poet.song.197000.json','["日車不照出郊車，門外天陰雲尚麤。", "青州未有居士供，白衣知是誰家奴。", "江山有恨橫饑眼，茱菊無情對卧壺。", "贏得閑關吟苦句，定無人敢喚催租。"]'),
('bbe2e0db-744d-45b7-9f06-93db37c79243','公安寓館夜立觀前用載韻','黄大受','宋','宋诗','song-poetry','','[]','翛翛一古觀，我到夜何其。',48,'全唐诗/poet.song.197000.json','["翛翛一古觀，我到夜何其。", "仙磬吟風殿，幽人汲露池。", "星沉螢聚水，月倒兔懸籬。", "四起鍾聲亂，凌風欲化肌。"]'),
('3dc30037-d1ba-4a1f-a879-21fefa30a794','秋夜讀書','黄大受','宋','宋诗','song-poetry','','[]','青燈敞虛堂，微風動衣襟。',48,'全唐诗/poet.song.197000.json','["青燈敞虛堂，微風動衣襟。", "兀坐耽塵編，起觀星河沉。", "古人豈可見，所希見其心。", "終然發永歎，不寐鳴床琴。"]'),
('4b484dd6-d44d-464b-ab11-555c9626f41d','梅','黄大受','宋','宋诗','song-poetry','','[]','自見梅開後，相看不暫離。',48,'全唐诗/poet.song.197000.json','["自見梅開後，相看不暫離。", "只因愁落去，不忍看繁時。", "佳實羹堪味，遺音角可期。", "牡丹專富貴，春盡却空枝。"]'),
('bf32c14d-6515-4c9d-8dbc-49cee5f9a147','謁九江趙守','陽枋','宋','宋诗','song-poetry','','[]','浮舟湓浦春，民謠舉欣欣。',168,'全唐诗/poet.song.197000.json','["浮舟湓浦春，民謠舉欣欣。", "問民寧底樂，州有賢使君。", "帝胄擢清班，江國煩慇懃。", "儀型金玉相，肝腸錦繡紋。", "周南藹忠厚，大雅卓不羣。", "固本屹磐石，理兵無絲棼。", "城堅萬里長，氣壯三邊軍。", "短吟亟搜枯，弄斧當郢斤。", "聊此窺一斑，所見諧所聞。", "願公慨神州，邊腹久中分。", "五嶽判地氣，三光離天文。", "倒竭五湖波，一洗九陵氛。", "鐘彝勒偉曄，汗史照芳芬。", "此烈丈夫耳，循常奚足云。"]'),
('4727713f-e5cd-4bfd-a277-dc5683fcec15','瀝鼻峽','陽枋','宋','宋诗','song-poetry','','[]','雙穴流清泉，古來名有自。',48,'全唐诗/poet.song.197000.json','["雙穴流清泉，古來名有自。", "至今存一息，呼吸竅萬類。", "山以泉爲津，石以穴爲鼻。", "無形本諸天，有質著乎地。"]'),
('e5aec66f-b43f-457e-a44a-899778ae5107','遊下竺飛來峰和存子姪韻','陽枋','宋','宋诗','song-poetry','','[]','嵯峨擅北高，幽靜還西竺。',48,'全唐诗/poet.song.197000.json','["嵯峨擅北高，幽靜還西竺。", "虎蹲石根奇，龍蟠藤蔓曲。", "面橫白水湖，背列濃嵐谷。", "鳥碎山逾空，起予詩不俗。"]'),
('4bb6f700-de4e-497d-b4c7-805766778196','過九江望見廬山立雪一峰和全父弟韻','陽枋','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','阻風桑落洲，悠然見廬山。',72,'全唐诗/poet.song.197000.json','["阻風桑落洲，悠然見廬山。", "白雪滿蓮峰，皓矗九霄間。", "新晴破積陰，天宇豁開顔。", "玩圖仰斯人，懷古涕潸潸。", "準擬進扁舟，躡屐登螺鬟。", "飽諳風月歸，庶幾無虛還。"]'),
('27299d48-13bd-4c77-9809-0417e0c51ec4','和趙景賢使君入昌溪即事','陽枋','宋','宋诗','song-poetry','','[]','東出峽如筒，北行溪似線。',241,'全唐诗/poet.song.197000.json','["東出峽如筒，北行溪似線。", "晨發怯春寒，午炊喜破晛。", "灘高石嶔𡼭，浪急珠璣濺。", "平生憂患心，對此倍兢戰。", "棹夫捷如風，舞篙接飛縴。", "昔觀武陵圖，今見武陵面。", "巖叢放斧斤，掛壁發葱蒨。", "半天矗亂峰，橫烟鎖寒練。", "猿鳥生意深，詩筆寫豪健。", "先生巖壑姿，對此聊自厭。", "險極復推奇，一覽嗟未遍。", "老眼仰貪看，花生渾欲焰。", "人喚不回頭，决眥强自勉。", "造化藏秘奇，人生能幾見。", "夙昔困塵埃，比來得清玩。", "異境延高吟，勝覽愜幽念。", "直疑紫霧深，秘隠豐城劍。", "便欲於此中，遯世真無悶。", "朝餐色䰐鬖鬖，暮遊光瀲灧。", "還恐利名牽，回首成健羨。"]'),
('c7ebcfed-5881-44d6-9810-dfbc3db2bcec','峽州程彥彪簽判賦桃花菊讀之良有佳致嗣韻敬呈覺其東塗西抹也','陽枋','宋','宋诗','song-poetry','','[]','羣芳發天機，妍媸太紛競。',288,'全唐诗/poet.song.197000.json','["羣芳發天機，妍媸太紛競。", "秋菊繁有徒，色以黄爲正。", "淵明具卓識，主一無多柄。", "日鋤三徑荒，取友霜松勁。", "後人悅紛華，逐物情其性。", "不見黄居中，方隅靡從令。", "綠衣尊間色，心憂切吟詠。", "陶菊抱幽姿，漢廣絕游泳。", "紅紫雜賦形，變化理難竟。", "妖嬈妬端莊，超乘誇捷逕。", "黄花秋露中，心與晚色凈。", "品類富脂鉛，盛服粧亦靚。", "佛頭詫奇裝，桃花卑異姓。", "殿荷呼是兄，先梅可稱孟。", "就中甘作君，今古有同敬。", "伊其標上藥，隠居重題評。", "汲泉擷芬英，神功治未病。", "味真乏佳色，苦坐芳筵屏。", "輕身引華年，蓍龜堪鑑鏡。", "獨立傲秋霜，高風誰景行。", "嘉哉夷齊賢，不仕西周盛。", "解約紫茱君，梗檜延福慶。", "登高睨八荒，期活蒼生命。", "君家甕頭春，胚腪歸酒聖。"]'),
('3cb22c68-151e-46c9-97de-54bb4ab2581d','紹慶府教廳瑞麥','陽枋','宋','宋诗','song-poetry','','[]','耕稼問黔巑，禾黍慳培塿。',288,'全唐诗/poet.song.197000.json','["耕稼問黔巑，禾黍慳培塿。", "秀實僅有之，嘉祥藐烏睹。", "府主金華仙，農事躬緬縷。", "暖律笑吹鄒，長府肯爲魯。", "節用寓封殖，寬征從字撫。", "去年民病穫，公把漏天補。", "今年趁春耕，公有月額雨。", "至和委來牟，兩岐分藝圃。", "雙秀可奇觀，三穎駭珍吐。", "一如荀氏龍，頭角森踽踽。", "一如賈氏虎，偉彪稱最怒。", "友于好弟兄，長岐支傴僂。", "芒穎乍崢嶸，襁褓辭嫗姆。", "苗脈共根株，萬物本乎祖。", "見說西家牛，二犢同一乳。", "瑣碎衆難并，異聞杳前古。", "歸功二千石，爲言物有主。", "憶昔辛丑間，紅塵飛白羽。", "陸海沈炊烟，原田沒榛楛。", "殿角深顧憂，宅西命山甫。", "太平登九年，魚鳬藹生聚。", "長嘯孤雲端，漢中我疆宇。", "片心天地通，助順知已許。", "畜繁田不蕪，麥瑞富高庾。"]'),
('4318ee6f-bfd8-479c-8396-4376fdb48e8c','壽李夔州乃翁','陽枋','宋','宋诗','song-poetry','','[]','乾月生真賢，老子其猶龍。',252,'全唐诗/poet.song.197000.json','["乾月生真賢，老子其猶龍。", "主靜以觀動，萬籟鳴秋蟲。", "片心閒淵明，結社同遠公。", "俯仰身世浮，妍華收晴虹。", "堂迥妙香凝，超然天地通。", "至懷三釜外，真味一甌中。", "震長可代父，物生辰與同。", "正東權發育，造化誰能窮。", "艮居東北隅，生意來重重。", "高枝翔鳳凰，𡄸喈鳴梧風。", "嘗聞乾一氣，稟付人稀逢。", "公全六畫陽，何始復何終。", "杞菊不足蔬，芝苓非所供。", "剛健自無息，天人知共宗。", "世無飛昇客，浪說呂仙翁。", "世無武陵源，異境空蟠胸。", "惟公秉乾德，七十元舂容。", "舉家秀而賢，無非乾所鍾。", "生生之謂易，笑言支長筇。", "舉杯問蒼天，天高杳無從。", "我欲携羲篇，相隨鶴山峰。"]'),
('a61be466-e9a6-4b28-8a49-d2b44face1c8','崑嶽有佳人四章壽黄循齋  其一','陽枋','宋','宋诗','song-poetry','','[]','崑嶽有佳人，婀娜蒼松姿。',72,'全唐诗/poet.song.197000.json','["崑嶽有佳人，婀娜蒼松姿。", "金石結根柯，綠葉瓊瑶枝。", "抱陽爐峰春，毓英巴水滋。", "絲苓濯繁霜，清樾摇坤陲。", "亭亭拔烟蘿，渠厦誰當支。", "工師胡弗來，歲寒心自知。"]'),
('155841aa-4daf-4887-ab18-1fca641ec0f2','崑嶽有佳人四章壽黄循齋  其二','陽枋','宋','宋诗','song-poetry','','[]','崑嶽有佳人，猗猗凌霜竹。',72,'全唐诗/poet.song.197000.json','["崑嶽有佳人，猗猗凌霜竹。", "叢篠列委翳，蕭森散清郁。", "常虛君子心，而聳高人目。", "嫋嫋鸞鳳棲，濃濃露華沐。", "玉兔投西隅，金烏出晹谷。", "瑟僴不可諼，聊爾爲君祝。"]'),
('0ae5a68f-7315-4755-84d6-9c73a28149c8','崑嶽有佳人四章壽黄循齋  其三','陽枋','宋','宋诗','song-poetry','','[]','崑嶽有佳人，神龜支其床。',72,'全唐诗/poet.song.197000.json','["崑嶽有佳人，神龜支其床。", "問龜生何年，太素含混茫。", "問龜何所餐，沆瀣凝秋陽。", "問龜何所知，一理周八荒。", "佳人拊龜笑，我心非汝量。", "大化難淺測，縮首宜深藏。"]'),
('83bed716-5618-4cf4-888d-08d94f31c00c','崑嶽有佳人四章壽黄循齋  其四','陽枋','宋','宋诗','song-poetry','','[]','崑嶽有佳人，挺挺雲中鶴。',72,'全唐诗/poet.song.197000.json','["崑嶽有佳人，挺挺雲中鶴。", "帝鄉迴鶩心，人寰寓其託。", "仰雲引圓吭，九皋窮碧落。", "瀛湘滄海身，稻粱寄情薄。", "昨夢世未醒，清唳不容寞。", "鳴陰子必和，天理亦昭灼。"]'),
('71c43b7b-6aea-4a02-8e53-26bda181b60c','開慶元年二兒自白水之江陵閒作數語送行且勸歸也','陽枋','宋','宋诗','song-poetry','','[]','舉家出三峽，去鄉二千里。',264,'全唐诗/poet.song.197000.json','["舉家出三峽，去鄉二千里。", "卜築罄囊資，苟全留白水。", "誅茅炊赤稻，稊稗日嵌齒。", "芥根充鼎實，屢空啜清泚。", "殘編發空箱，矮窗聊復爾。", "晝誦夜無燈，早寢接晏起。", "江國多雪霜，木火謝司燬。", "凍沍襲重茅，刮肌復侵髓。", "瓶儲斗升粒，食聚三百指。", "子行其謂何，艱難急生理。", "輕財性則然，苦節此時矣。", "荆江萃交朋，酬答寧容已。", "長語廢百事，頻遊迷短晷。", "接䍦防倒著，拍手兒童恥。", "食息在顧養，交抨繫金柅。", "有懷趙乙囊，勿錯孟嘗履。", "泉竭云自中，風驚吹戍壘。", "廩粟不可縻，市門亦難倚。", "我老驚太衰，孫稚要提耳。", "來歲屬庚申，上旬逢丙子。", "人事顧天時，溝壑虞近止。", "梅臘早還家，濁醪同酌兕。"]'),
('602ca38a-5de0-4ee9-9046-1527b5980427','與存子姪王南運上風聯句','陽枋','宋','宋诗','song-poetry','','[]','舟行緩東去，波蹙疑西流。',156,'全唐诗/poet.song.197000.json','["舟行緩東去，波蹙疑西流。", "塵揚頻閉目，草偃付囘眸。", "翩翩泝岸鷺，緩緩沿波鷗。", "聚沱留積滓，逆浪集浮漚。", "門窺雨斜入，窗望山相留。", "棹苦掌痕腫，烟囘眥淚浮。", "客舟上急急，我楫去悠悠。", "一程分兩日，半月僅三州。", "僕嗔糧易竭，客怨利難謀。", "柁斜橫水面，人宿避沙頭。", "嘯想武陵虎，化催西海虬。", "欲寄風伯語，聊以吾詩投。", "何如還借順，咫尺登瀛洲。"]'),
('c989b133-3597-4228-88e2-5b9143e71ea6','送謝方伯赴試','陽枋','宋','宋诗','song-poetry','','[]','春桑催蠶日遲遲，春蠶食葉開文闈。',144,'全唐诗/poet.song.197000.json','["春桑催蠶日遲遲，春蠶食葉開文闈。", "桃源雖好不可住，高人夢繞故山薇。", "金雞啁哳喚出日，輕舟短棹風吹衣。", "莫問虹梁春燕入，莫吟西堂春草萋。", "水光山色二千里，助君筆底龍蛇飛。", "丹成九轉天上去，五雲膠轕黄金扉。", "回首故鄉烟靄暮，城郭如故人民非。", "年來世事轉頭改，不見華表丁令威。", "送君南浦祝此語，佇立江干背夕暉。"]'),
('8640f6a9-7cf6-4747-841b-982006c01455','回陸主簿賀生日詩','陽枋','宋','宋诗','song-poetry','','[]','南華眇彌誇靈椿，八千爲秋八千春。',304,'全唐诗/poet.song.197000.json','["南華眇彌誇靈椿，八千爲秋八千春。", "要是循名須責實，人生三萬六千日。", "世間修短皆自然，造化到底難爲言。", "一十二萬九千歲，更加五百乾之兌。", "安樂老仙窮象數，三哥笑言譏淺露。", "只如三百六十五，天運從來周一度。", "太羹玄酒常渾渾，何人於中羅八珍。", "八珍向裏有真味，未可以天而廢人。", "神數自一而至十，萬物生成由此出。", "坤兌無首乾無終，陰陽爲用常虛一。", "顔子聞一以知十，清明氣稟不苟畀。", "六德六行惟俱全，只向綱常窮所止。", "人能陋巷樂簞瓢，踐行即是奇男子。", "看盡古今爲聖賢，底事有經還有權。", "紛紜雜擾語不盡，匠斤扁斲惟心傳。", "道至無言而止矣，此外如何別有旨。", "萬靈昭灼會寸心，須使愛之若桐梓。", "朅來城市辭山林，蕭蕭兩鬢雪山侵。", "感甚秋高華晚節，搜枯聊作寒蛩吟。"]'),
('9f1ccfa3-225d-41ca-9f32-7a3162d62b85','壽鄧子西知縣','陽枋','宋','宋诗','song-poetry','','[]','猗猗竹繞鄧家灣，亭亭屋背摩圍山。',180,'全唐诗/poet.song.197000.json','["猗猗竹繞鄧家灣，亭亭屋背摩圍山。", "當軒水花日噴薄，覆戶雲葉時斕斑。", "中有高士金閨客，元從洞府生人間。", "捧觴天爵役人爵，戯彩前班羅後班。", "不妨花縣春風晚，且對萱堂白日閒。", "剩將千卷課兒習，博取一笑開慈顔。", "和氣向晚薄葱蒨，書聲半夜隨潺湲。", "只恐天上妬人暇，催公拔宅離塵寰。", "玉堂將母奉珍鼎，鏘聽羣仙鳴佩環。", "丹砂九轉戒獨善，刀圭分遣扶艱關。", "功成麟閣歸來早，筍輿隨步羞桃薦菊紉蘭蕳。"]'),
('9010c4b5-44ff-4709-ad2f-748b31ba69f6','用昌黎賦鳴雁韻勸蹇從叔出峽與乃兄相依','陽枋','宋','宋诗','song-poetry','','[]','楚天空闊雁南飛，整整秋來春又歸。',104,'全唐诗/poet.song.197000.json','["楚天空闊雁南飛，整整秋來春又歸。", "腸斷孤鴻鳴失依，重雲片影儔侶稀。", "野老吟情託興微，樊籠休羨稻粱肥。", "岷峨回首寸心違，華亭清唳昔人非。", "湖北湖南秋水多，洲渚星稀無網羅，平沙雪落聲相和。", "俛仰塵世應無他，君於此處意如何。"]');
